CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `ActualPaymentProcedure`( IN startDate DATE, IN endDate DATE ) BEGIN WITH LastCollection AS ( SELECT loanNo, MAX(collectedDate) AS lastCollectionDate FROM collection WHERE status IN ('Settlement', 'Closed', 'Part Payment') GROUP BY loanNo ), TotalCollected AS ( SELECT col.loanNo, SUM(col.collectedAmount) AS totalCollectedAmount FROM collection col JOIN LastCollection lc ON col.loanNo = lc.loanNo WHERE col.collectionStatus = 'Approved' AND col.collectedMode <> 'Waive Off' AND col.collectedDate <= lc.lastCollectionDate GROUP BY col.loanNo ), LatestStatus AS ( SELECT col.loanNo, col.status, ROW_NUMBER() OVER (PARTITION BY col.loanNo ORDER BY col.createdDate DESC) as rn FROM collection col WHERE col.status IN ('Closed', 'Settlement', 'Part Payment') ) SELECT l.loanNo AS 'Loan No', ld.customerID AS 'CustomerID', ld.leadID AS 'leadID', c.name AS 'Name', MAX(CASE WHEN cf.followType = 'Call' THEN cf.createdDate ELSE NULL END) AS 'Call Date', MAX(CASE WHEN cf.followType = 'Call' THEN cf.followType ELSE NULL END) AS 'Contact Type', MAX(cf.statusType) AS 'Status', MAX(CASE WHEN cf.statusType = 'PTP' THEN cf.statusTypeDate ELSE NULL END) AS 'PTP Date', MAX(cf.remark) AS 'Remark', l.disbursalAmount AS 'Loan Amount', a.tenure AS 'Tenure', a.roi AS 'ROI', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay Amount', a.repayDate AS 'Repay Date', COALESCE(tc.totalCollectedAmount, 0) AS 'Total Collected Amount', MAX(CASE WHEN ls.rn = 1 THEN ls.status ELSE NULL END) AS 'Collection Status', l.disbursalDate AS 'Date', MAX(addr.address) AS 'Address', MONTHNAME(l.disbursalDate) AS 'Disbursal Month', ld.fbLeads AS 'Loan Type', MAX(u.name) AS 'Credited By', lf.LoanFrequency AS 'Loan Frequency', c.employeeType AS 'Employee Type', MAX(cf.createdDate) AS 'Max Follow-up Date' FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN customer c ON ld.customerID = c.customerID LEFT JOIN collectionFollowup cf ON ld.leadID = cf.leadID LEFT JOIN collection col ON l.loanNo = col.loanNo LEFT JOIN address addr ON c.customerID = addr.customerID LEFT JOIN users u ON a.creditedby = u.userID JOIN ( SELECT customerID, COUNT(DISTINCT loanNo) AS LoanFrequency FROM loan WHERE status = 'Disbursed' GROUP BY customerID ) lf ON c.customerID = lf.customerID LEFT JOIN TotalCollected tc ON l.loanNo = tc.loanNo LEFT JOIN LatestStatus ls ON l.loanNo = ls.loanNo AND ls.rn = 1 WHERE a.repayDate BETWEEN startDate AND endDate AND l.status = 'Disbursed' AND col.status IN ('Closed', 'Settlement', 'Part Payment') GROUP BY l.loanNo, ld.customerID, ld.leadID, c.name, l.disbursalAmount, a.tenure, a.roi, a.repayDate, l.disbursalDate, ld.fbLeads, lf.LoanFrequency, c.employeeType, tc.totalCollectedAmount ORDER BY a.repayDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `agent_dsa_report`( IN report_type VARCHAR(20), IN utm_code VARCHAR(50), IN start_date DATE, IN end_date DATE, IN start_from INT, IN per_page_record INT, IN api_type VARCHAR(30), IN commission INT ) BEGIN
SET @old_sql_mode = @@sql_mode; SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', ''));
SET @filterquery = CONCAT('users.createdDate BETWEEN "', start_date, '" AND "', end_date, ' 23:59:59"');
IF report_type = 'total' AND api_type = 'api' THEN SET @sql = CONCAT( 'SELECT users.utmSource, COUNT(*) AS merchant_count, IFNULL(( SELECT 1 FROM leads WHERE leads.utmSource = users.utmSource AND leads.fbLeads <> ''Repeat Case'' AND leads.status IN (''Disbursed'', ''Settlement'', ''Closed'', ''Part Payment'', ''Blacklisted'') LIMIT 1 ), 0) AS payout, IFNULL(( SELECT 1 FROM leads WHERE leads.utmSource = users.utmSource AND leads.fbLeads <> ''Repeat Case'' AND leads.status IN (''Disbursed'', ''Settlement'', ''Closed'', ''Part Payment'', ''Blacklisted'') LIMIT 1 ) * 50, 0) AS total_payout, ', commission, ' AS total_paid FROM users WHERE ', @filterquery, ' AND users.referralCode = ''', utm_code, ''' GROUP BY users.utmSource' );
ELSEIF report_type = 'list' AND api_type = 'api' THEN SET @sql = CONCAT( 'SELECT u.id, u.name, users.email, users.mobile, users.createdDate AS created_date, users.status, IFNULL(( SELECT 1 FROM leads WHERE leads.utmSource = users.utmSource AND leads.fbLeads <> ''Repeat Case'' AND leads.status IN (''Disbursed'', ''Settlement'', ''Closed'', ''Part Payment'', ''Blacklisted'') LIMIT 1 ), 0) AS payout FROM users INNER JOIN dsa.users u ON u.internal_user_id = users.userID WHERE ', @filterquery, ' AND users.referralCode = ''', utm_code, ''' GROUP BY users.utmSource LIMIT ', start_from, ', ', per_page_record );
ELSE SET @sql = CONCAT( 'SELECT u.id, u.name, users.email, users.mobile, users.createdDate AS created_date, users.status, IFNULL(( SELECT 1 FROM leads WHERE leads.utmSource = users.utmSource AND leads.fbLeads <> ''Repeat Case'' AND leads.status IN (''Disbursed'', ''Settlement'', ''Closed'', ''Part Payment'', ''Blacklisted'') ), 0) AS payout FROM users INNER JOIN dsa.users u ON u.internal_user_id = users.userID WHERE ', @filterquery, ' AND users.referralCode = ''', utm_code, ''' GROUP BY users.utmSource LIMIT ', start_from, ', ', per_page_record ); END IF;
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
SET sql_mode = @old_sql_mode; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `All_leads`( IN start_date DATE, IN end_date DATE ) begin select DATE(leads.createdDate) as Date, customer.name as 'Name', customer.mobile as 'Mobile_Number', leads.status as 'Leads Status' from customer JOIN leads ON leads.customerID = customer.customerID WHERE DATE(leads.createdDate) BETWEEN start_date AND end_date GROUP BY leads.leadID ORDER BY leads.createdDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `api_log_data_with_error`( IN param1 VARCHAR(20), IN param2 VARCHAR(20) ) BEGIN DECLARE param3 VARCHAR(30) DEFAULT 0; SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', '')); SET param3 = CONCAT(param2,' 23:59:59'); select DATE(createdDate),SUM(CASE WHEN api_name = '/customers/customer-login-byMobile' AND status ='1' THEN 1 ELSE 0 END) AS OTP_Send_Success, SUM(CASE WHEN api_name = '/customers/customer-login-byMobile' AND status ='0' THEN 1 ELSE 0 END) AS OTP_Send_Fail, SUM(CASE WHEN api_name = '/customers/customer-login-byMobile' AND status ='0' and LEFT(message,12)='Your account' THEN 1 ELSE 0 END) AS Lock_Account, SUM(CASE WHEN api_name = '/customers/verify-otp' AND status ='0' and (LEFT(message,12)='OTP verifica' or LEFT(message,12)='Incorrect OT') THEN 1 ELSE 0 END) AS Incorrect_otp, SUM(CASE WHEN api_name = '/customers/verify-otp' AND status ='0' and LEFT(message,12)='OTP has expi' THEN 1 ELSE 0 END) AS OTP_expired, SUM(CASE WHEN api_name = '/customers/verify-otp' AND status ='0' and LEFT(message,12)='Unable to Lo' THEN 1 ELSE 0 END) AS PHP_token_not_coming, SUM(CASE WHEN api_name = '/customers/auto-login' AND status ='0' and LEFT(message,12)='Invalid toke' THEN 1 ELSE 0 END) AS Invalid_token, SUM(CASE WHEN api_name = '/customers/pan-auto-fetch' AND status ='1' THEN 1 ELSE 0 END) AS Pan_auto_fetch_Success, SUM(CASE WHEN api_name = '/customers/pan-auto-fetch' AND status ='0' THEN 1 ELSE 0 END) AS Pan_auto_fetch_fail, SUM(CASE WHEN api_name = '/customer_onboarding/pan-verification' AND status ='1' THEN 1 ELSE 0 END) AS Pan_fetch_Success, SUM(CASE WHEN api_name = '/customer_onboarding/pan-verification' AND status ='0' THEN 1 ELSE 0 END) AS Pan_fetch_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/pan-verification' AND status ='0' and LEFT(message,12)='This PAN is' THEN 1 ELSE 0 END) AS Pan_Already_linked, SUM(CASE WHEN api_name = '/customer_onboarding/pan-verification' AND status ='0' and LEFT(message,12)='Invalid PAN' THEN 1 ELSE 0 END) AS Invalid_pan, SUM(CASE WHEN api_name = '/customer_onboarding/pan-verification' AND status ='0' and LEFT(message,12)='You cannot a' THEN 1 ELSE 0 END) AS Pan_blacklist, SUM(CASE WHEN api_name = '/customer_onboarding/pan-confirmation' AND status ='1' THEN 1 ELSE 0 END) AS Pan_confirm_Success, SUM(CASE WHEN api_name = '/customer_onboarding/pan-confirmation' AND status ='0' THEN 1 ELSE 0 END) AS Pan_confirm_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/pan-confirmation' AND status ='0' and LEFT(message,12)='Eligibility' THEN 1 ELSE 0 END) AS Pan_Not_eligible, SUM(CASE WHEN api_name = '/customer_onboarding/pan-confirmation' AND status ='0' and LEFT(message,12)='An Issue occ' THEN 1 ELSE 0 END) AS Pan_save_error, SUM(CASE WHEN api_name = '/customer_onboarding/basic-details' AND status ='1' THEN 1 ELSE 0 END) AS Emp_detail_and_email_Success, SUM(CASE WHEN api_name = '/customer_onboarding/basic-details' AND status ='0' THEN 1 ELSE 0 END) AS Emp_detail_and_email_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/basic-details' AND status ='0' and LEFT(message,12)='This email a' THEN 1 ELSE 0 END) AS Email_already_exists, SUM(CASE WHEN api_name = '/customer_onboarding/basic-details' AND status ='0' and LEFT(message,12)='email must b' THEN 1 ELSE 0 END) AS Wrong_email_format, SUM(CASE WHEN api_name = '/customer_onboarding/basic-details' AND status ='0' and LEFT(message,12)='We are curre' THEN 1 ELSE 0 END) AS Bre_issue, SUM(CASE WHEN api_name = '/customer_onboarding/finbox-create-url' AND status ='1' THEN 1 ELSE 0 END) AS Finbox_create_Success, SUM(CASE WHEN api_name = '/customer_onboarding/finbox-create-url' AND status ='0' THEN 1 ELSE 0 END) AS Finbox_create_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/finbox-bank-connect' AND status ='1' THEN 1 ELSE 0 END) AS Finbox_connect_Success, SUM(CASE WHEN api_name = '/customer_onboarding/finbox-bank-connect' AND status ='0' THEN 1 ELSE 0 END) AS Finbox_connect_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/banking-surrogate' AND status ='1' THEN 1 ELSE 0 END) AS Banking_Surrogate_Success, SUM(CASE WHEN api_name = '/customer_onboarding/banking-surrogate' AND status ='0' THEN 1 ELSE 0 END) AS Banking_Surrogate_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/approval-view' AND status ='1' THEN 1 ELSE 0 END) AS Approval_view_Success, SUM(CASE WHEN api_name = '/customer_onboarding/approval-view' AND status ='0' THEN 1 ELSE 0 END) AS Approval_view_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/approval-view' AND status ='0' and LEFT(message,12)='productID is' THEN 1 ELSE 0 END) AS Approvel_view_error, SUM(CASE WHEN api_name = '/crm/paydayToEmiConversion' AND status ='1' THEN 1 ELSE 0 END) AS Payday_EMI_Success, SUM(CASE WHEN api_name = '/crm/paydayToEmiConversion' AND status ='0' THEN 1 ELSE 0 END) AS Payday_EMI_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/verify-email-otp' AND status ='1' THEN 1 ELSE 0 END) AS Email_verify_otp_Success, SUM(CASE WHEN api_name = '/customer_onboarding/verify-email-otp' AND status ='0' THEN 1 ELSE 0 END) AS Email_verify_otp_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/verify-email-otp' AND status ='0' and LEFT(message,12)='Wrong OTP, P' THEN 1 ELSE 0 END) AS Email_wrong_OTP, SUM(CASE WHEN api_name = '/customer-bank-account/bank-detail-on-ifsc' AND status ='1' THEN 1 ELSE 0 END) AS Get_IFSC_Success, SUM(CASE WHEN api_name = '/customer-bank-account/bank-detail-on-ifsc' AND status ='0' THEN 1 ELSE 0 END) AS Get_IFSC_Fail, SUM(CASE WHEN api_name = '/customers/customer-details' AND status ='1' THEN 1 ELSE 0 END) AS Fetch_Account_Details_Success, SUM(CASE WHEN api_name = '/customers/customer-details' AND status ='0' THEN 1 ELSE 0 END) AS Fetch_Account_Details_Fail, SUM(CASE WHEN api_name = '/customer-bank-account/bank-details' AND status ='1' THEN 1 ELSE 0 END) AS Save_bank_Success, SUM(CASE WHEN api_name = '/customer-bank-account/bank-details' AND status ='0' THEN 1 ELSE 0 END) AS Save_bank_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/penny-drop' AND status ='1' THEN 1 ELSE 0 END) AS Penny_drop_Success, SUM(CASE WHEN api_name = '/customer_onboarding/penny-drop' AND status ='0' THEN 1 ELSE 0 END) AS Penny_drop_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/penny-drop' AND status ='0' and LEFT(message,12)='Your name do' THEN 1 ELSE 0 END) AS Penny_name_mismatch, SUM(CASE WHEN api_name = '/customer-bank-account/closed' AND status ='1' THEN 1 ELSE 0 END) AS Bank_list_Success, SUM(CASE WHEN api_name = '/customer-bank-account/closed' AND status ='0' THEN 1 ELSE 0 END) AS Bank_list_Fail, SUM(CASE WHEN api_name = '/customer-bank-account/confirm' AND status ='1' THEN 1 ELSE 0 END) AS Confirm_bank_Success, SUM(CASE WHEN api_name = '/customer-bank-account/confirm' AND status ='0' THEN 1 ELSE 0 END) AS Confirm_bank_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-generate-otp' AND status ='1' THEN 1 ELSE 0 END) AS Aadhar_otp_Sucess, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-generate-otp' AND status ='0' THEN 1 ELSE 0 END) AS Aadhar_otp_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-verify-otp' AND status ='1' THEN 1 ELSE 0 END) AS Aadhar_verify_Success, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-verify-otp' AND status ='0' THEN 1 ELSE 0 END) AS Aadhar_verify_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-initiate-digilocker' AND status ='1' THEN 1 ELSE 0 END) AS Aadhar_digi_Success, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-initiate-digilocker' AND status ='0' THEN 1 ELSE 0 END) AS Aadhar_digi_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-verify-otp' AND status ='0' and LEFT(message,12)='Your Aadhar' THEN 1 ELSE 0 END) AS Aadhar_DOB_mismatch, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-generate-otp' AND status ='0' and LEFT(message,12)='Aadhaar Veri' THEN 1 ELSE 0 END) AS Aadhar_server_error, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-webhook-digilocker' AND status ='1' THEN 1 ELSE 0 END) AS Verify_digi_Success, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-webhook-digilocker' AND status ='0' THEN 1 ELSE 0 END) AS Verify_digi_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/aadhar-verification-webhook-digilocker' AND status ='0' and LEFT(message,12)='Your PAN is' THEN 1 ELSE 0 END) AS Pan_aadhar_link, SUM(CASE WHEN api_name = '/customer_onboarding/verify_selfie' AND status ='1' THEN 1 ELSE 0 END) AS Selfie_verify_Success, SUM(CASE WHEN api_name = '/customer_onboarding/verify_selfie' AND status ='0' THEN 1 ELSE 0 END) AS Selfie_verify_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/hyperverge-feature' AND status ='1' THEN 1 ELSE 0 END) AS Hyperverge_Success, SUM(CASE WHEN api_name = '/customer_onboarding/hyperverge-feature' AND status ='0' THEN 1 ELSE 0 END) AS Hyperverge_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/hyperverge/start-onboarding' AND status ='1' THEN 1 ELSE 0 END) AS Hyperverge_initiate_Success, SUM(CASE WHEN api_name = '/customer_onboarding/hyperverge/start-onboarding' AND status ='0' THEN 1 ELSE 0 END) AS Hyperverge_initiate_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/hyperverge/result' AND status ='1' THEN 1 ELSE 0 END) AS Hyperverge_status_Success, SUM(CASE WHEN api_name = '/customer_onboarding/hyperverge/result' AND status ='0' THEN 1 ELSE 0 END) AS Hyperverge_status_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/set-emandateV2' AND status ='1' THEN 1 ELSE 0 END) AS Initiate_emandate_Success, SUM(CASE WHEN api_name = '/customer_onboarding/set-emandateV2' AND status ='0' THEN 1 ELSE 0 END) AS Initiate_emandate_Fail, SUM(CASE WHEN api_name = '/customer_onboarding/kfs-payday' AND status ='1' THEN 1 ELSE 0 END) AS KFS_Success, SUM(CASE WHEN api_name = '/customer_onboarding/kfs-payday' AND status ='0' THEN 1 ELSE 0 END) AS KFS_Fail FROM journey_logs where createdDate BETWEEN param1 AND param3 GROUP BY DATE(createdDate) ORDER BY DATE(createdDate);
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `approved_process_transition`(from_date VARCHAR(20)) BEGIN SELECT DATE_FORMAT(ch1.createdDate, '%m') AS Month, DAY(ch1.createdDate) AS Date, l.fbLeads AS LeadsType, COUNT(DISTINCT CASE WHEN ch1.status = 'Approved Process' THEN ch1.leadID END) AS 'Approve Process Count', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) = 0 THEN 1 ELSE 0 END) AS 'T', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) = 1 THEN 1 ELSE 0 END) AS 'T+1', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) BETWEEN 2 AND 7 THEN 1 ELSE 0 END) AS '02-07 Days', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) BETWEEN 8 AND 15 THEN 1 ELSE 0 END) AS '08-15 Days', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) BETWEEN 16 AND 30 THEN 1 ELSE 0 END) AS '16-30 Days', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) BETWEEN 31 AND 60 THEN 1 ELSE 0 END) AS '30-60 Days', SUM(CASE WHEN DATEDIFF(ch2.createdDate, ch1.createdDate) > 60 THEN 1 ELSE 0 END) AS '60+ Days' FROM callhistoryLogs ch1 LEFT JOIN callhistoryLogs ch2 ON ch1.leadID = ch2.leadID AND ch2.status = 'Approved' AND ch1.createdDate <= ch2.createdDate JOIN leads l ON ch1.leadID = l.leadID WHERE ch1.status = 'Approved Process' AND ch1.createdDate >= from_date GROUP BY DATE_FORMAT(ch1.createdDate, '%m'), DAY(ch1.createdDate), l.fbLeads ORDER BY DATE_FORMAT(ch1.createdDate, '%m'), DAY(ch1.createdDate), l.fbLeads; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `cibil_data_dump`( IN start_date DATE, IN end_date DATE) BEGIN WITH DueAmounts AS ( SELECT l.leadID, le.productID, l.disbursalAmount, l.loanNo, (SELECT c.status FROM collection c WHERE c.loanNo = l.loanNo and c.collectedDate<end_date And collectionStatus='Approved' ORDER BY c.collectionID DESC LIMIT 1 ) AS leadStatus, ROUND( CASE WHEN le.productID = 1 THEN ( SELECT SUM(CASE WHEN emi.status = 'due' AND emi.dueDate < end_date THEN emi.principal WHEN emi.status = 'part-payment' THEN emi.amountRemains ELSE 0 END) FROM equated_monthly_installments emi LEFT JOIN credits cr ON emi.leadID = cr.leadID WHERE emi.leadID = l.leadID) WHEN le.productID = 2 THEN ( ROUND( ROUND( l.disbursalAmount + ( l.disbursalAmount * a.roi / 100 * a.tenure ) ) + ( l.disbursalAmount * 1.25 / 100 * DATEDIFF(end_date, a.repayDate) ) - IFNULL(SUM(co.collectedAmount), 0) ) ) ELSE NULL END,2) currentAmount, ROUND( CASE WHEN le.productID = 1 THEN ( SELECT SUM( ROUND( CASE WHEN emi.status = 'due' AND emi.dueDate < end_date THEN emi.principal + emi.interest + (emi.principal * (((cr.roi / 12) / 100) + 0.1) * DATEDIFF(end_date, emi.dueDate) + 590) WHEN emi.status = 'part-payment' AND emi.actualPaymentDate > emi.dueDate THEN emi.principal + emi.interest + emi.panelty + emi.amountRemains * (((cr.roi / 12) / 100) + 0.1) * DATEDIFF(CURRENT_DATE, emi.actualPaymentDate) + 590 - emi.amountPayable WHEN emi.status = 'part-payment' AND emi.actualPaymentDate < emi.dueDate AND emi.dueDate < end_date THEN emi.principal + emi.interest + emi.amountRemains * (((cr.roi / 12) / 100) + 0.1) * DATEDIFF(end_date, emi.dueDate) + 590 - emi.amountPayable ELSE emi.amountPayable END, 2 ) ) FROM equated_monthly_installments emi LEFT JOIN credits cr ON emi.leadID = cr.leadID WHERE emi.leadID = l.leadID ) WHEN le.productID = 2 THEN ( ROUND( ROUND( l.disbursalAmount + ( l.disbursalAmount * a.roi / 100 * a.tenure ) ) + ( l.disbursalAmount * 1.25 / 100 * DATEDIFF(end_date, a.repayDate) ) - IFNULL(SUM(co.collectedAmount), 0) ) ) ELSE NULL END ) AS DueAmount,
ROUND( ( CASE WHEN SUM(co.collectedAmount) > 0 THEN ( (SELECT (IFNULL(total_interest, 0) + IFNULL(penality_charge, 0)) FROM collection WHERE leadID = l.leadID and collectedDate<end_date ORDER BY collectionID DESC LIMIT 1 ) + MIN(co.principal_amount) + ( MIN(co.principal_amount) * ((a.roi + 0.1) / 100) * DATEDIFF( '2024-12-31', MAX(co.collectedDate) ) ) ) ELSE ( l.disbursalAmount + ( l.disbursalAmount * a.roi / 100 * a.tenure ) + 590 + ( l.disbursalAmount * (a.roi + 0.1) / 100 * DATEDIFF(end_date, a.repayDate) ) ) END ) ) AS IPCDueAmount, ROUND(l.disbursalAmount - ifnull(SUM(co.collected_principal),0)) AS IPCCurrentAmount, DATEDIFF(NOW(), a.repayDate) AS CurrentTenure FROM leads le join loan l on le.leadID=l.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN ( SELECT * FROM collection WHERE collectionStatus = 'Approved' AND collectedDate < end_date ) AS co ON l.leadID = co.leadID WHERE l.disbursalDate < end_date GROUP BY l.leadID )
SELECT c.name AS 'Consumer Name', c.dob AS 'Date of Birth', CASE WHEN c.gender = 'Male' THEN 2 WHEN c.gender = 'Female' THEN 1 END AS Gender, c.pancard AS 'Income Tax ID Number', c.mobile AS 'Telephone No.Mobile', c.email AS 'Email ID 1', l.loanNo AS 'Curr/New Account No', l.disbursalDate AS 'Date Opened/Disbursed', l.disbursalAmount AS 'High Credit/Sanctioned Amt', ROUND( l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * DATEDIFF(a.repayDate, l.disbursalDate)) , 2) AS repayAmount, a.repayDate AS 'Repay Date', MAX(col.collectedDate) AS 'Last Collected Date',
CASE WHEN DA.leadStatus = 'Settlement' THEN COALESCE( CASE WHEN le.productID = 1 THEN (
SELECT SUM(emi.paymentReceived) FROM equated_monthly_installments emi WHERE emi.leadID = le.leadID AND emi.is_deleted = 1 AND emi.status = 'paid' ) WHEN le.productID = 2 THEN (
SUM( CASE WHEN col.collectedMode NOT IN ('DISCOUNT', 'Waive Off') THEN col.collectedAmount ELSE 0 END ) ) ELSE 0 END, 0) ELSE NULL END AS 'Settlement Amount',
CASE WHEN lal.api_type = 'aadhaar-v2-submit-otp' THEN CONCAT( JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.loc')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.vtc')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.subdist')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.street')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.house')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.landmark')) ) WHEN lal.api_type = 'digilocker_eaadhaar' THEN CONCAT( JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.house')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.landmark')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.district')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.vtc')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.subDistrict')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.locality')) ) WHEN lal.api_type = 'ckyc_download' THEN CONCAT( JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.ckyc_download_data.personal_identifiable_data.personal_details.perm_line1')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.ckyc_download_data.personal_identifiable_data.personal_details.perm_line2')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.ckyc_download_data.personal_identifiable_data.personal_details.perm_line3')), ', ', JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.ckyc_download_data.personal_identifiable_data.personal_details.perm_dist')) ) ELSE NULL END AS Address, CASE WHEN lal.api_type = 'aadhaar-v2-submit-otp' THEN JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.zip')) WHEN lal.api_type = 'digilocker_eaadhaar' THEN JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.pincode')) WHEN lal.api_type = 'ckyc_download' THEN JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.ckyc_download_data.personal_identifiable_data.personal_details.perm_pin')) ELSE NULL END AS Pincode, CASE WHEN lal.api_type = 'aadhaar-v2-submit-otp' THEN JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.address.state')) WHEN lal.api_type = 'digilocker_eaadhaar' THEN JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.proofOfAddress.state')) WHEN lal.api_type = 'ckyc_download' THEN CONCAT( JSON_UNQUOTE(JSON_EXTRACT(lal.api_response, '$.data.ckyc_download_data.personal_identifiable_data.personal_details.perm_state')),'' ) ELSE NULL END AS State, COALESCE( DA.leadStatus, 'Disbursed' ) AS 'Current Status', CASE WHEN COALESCE(DA.leadStatus, 'Disbursed') = 'Part Payment' OR COALESCE(DA.leadStatus, 'Disbursed') = 'Disbursed' THEN CASE WHEN a.repayDate >= end_date THEN NULL ELSE DATEDIFF(end_date, a.repayDate) END ELSE NULL END AS DPD, (CASE WHEN COALESCE(DA.leadStatus, 'Disbursed') IN ('Closed', 'Settlement') THEN 0 ELSE (CASE WHEN (le.ipc = 1 and le.productID=2) THEN DA.IPCDueAmount ELSE DA.DueAmount END) END) AS DueAmount, (CASE WHEN COALESCE(DA.leadStatus, 'Disbursed') IN ('Closed', 'Settlement') THEN 0 ELSE (CASE WHEN (le.ipc = 1 and le.productID=2) THEN DA.IPCCurrentAmount ELSE DA.currentAmount END) END) AS CurrentDueAmount, CASE WHEN DA.leadStatus = 'Settlement' THEN CASE WHEN le.productID = 1 THEN ( SELECT SUM( emi.amountRemains + emi.amountRemainsInterest + emi.amountRemainsPenalty + emi.amountRemainsBrokenPeriodIntrest ) FROM equated_monthly_installments emi WHERE emi.leadID = le.leadID AND emi.is_deleted = 1 AND emi.status = 'paid' ) WHEN le.productID = 2 THEN ROUND( (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * DATEDIFF(a.repayDate, l.disbursalDate)) + (l.disbursalAmount * (CASE WHEN le.ipc=1 THEN (a.roi+0.1) ELSE 1.25 END) / 100 * DATEDIFF(MAX(col.collectedDate), a.repayDate))) - (SELECT SUM(cole.collectedAmount) FROM collection cole WHERE cole.leadID = le.leadID AND cole.collectedMode NOT IN ('Waive Off', 'DISCOUNT') AND cole.collectionStatus='Approved' ), 2) ELSE NULL END ELSE NULL END AS 'Total Write Off',
CASE WHEN DA.leadStatus = 'Settlement' THEN CASE WHEN le.productID = 1 THEN ABS( l.disbursalAmount - ( SELECT SUM(emi.paymentReceived) FROM equated_monthly_installments emi WHERE emi.leadID = le.leadID AND emi.is_deleted = 1 AND emi.status = 'paid' ) ) WHEN le.productID = 2 THEN GREATEST(( l.disbursalAmount - ( SELECT SUM(cole.collectedAmount) FROM collection cole WHERE cole.leadID = le.leadID AND cole.collectedMode NOT IN ('Waive Off', 'DISCOUNT') AND cole.collectionStatus='Approved' ) ), 0) ELSE NULL END ELSE NULL END AS 'Principal Write Off' FROM customer c JOIN leads le ON le.customerID = c.customerID JOIN loan l ON le.leadID = l.leadID LEFT JOIN (select * from collection where collectedDate>= start_date and collectedDate< end_date and collectionStatus='Approved') col ON l.leadID = col.leadID LEFT JOIN leads_api_log lal ON c.mobile = lal.mobile_no AND JSON_VALID(lal.api_response) = 1 AND lal.status = 1 AND ( lal.api_type = 'aadhaar-v2-submit-otp' OR lal.api_type = 'digilocker_eaadhaar' OR lal.api_type = 'ckyc_download' ) JOIN approval a ON l.leadID = a.leadID LEFT JOIN DueAmounts DA ON DA.loanNo = l.loanNo WHERE l.disbursalDate < end_date and (le.status ='Part Payment' or le.status='Disbursed' or exists(select 1 from collection where (status='Closed' or status='Settlement') and collectedDate>= start_date and leadID=le.leadID)) AND l.status = 'Disbursed' GROUP BY l.loanNo;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `ClosedAccountsProcedure`( IN startDate DATE, IN endDate DATE ) BEGIN WITH LastCollection AS ( SELECT loanNo, MAX(collectedDate) AS lastCollectionDate FROM collection WHERE status IN ('Settlement', 'Closed') GROUP BY loanNo ), TotalCollected AS ( SELECT col.loanNo, SUM(col.collectedAmount) AS totalCollectedAmount FROM collection col JOIN LastCollection lc ON col.loanNo = lc.loanNo WHERE col.collectionStatus = 'Approved' AND col.collectedMode <> 'Waive Off' AND col.collectedDate <= lc.lastCollectionDate GROUP BY col.loanNo ) SELECT l.loanNo AS 'Loan No', ld.customerID AS 'CustomerID', ld.leadID AS 'leadID', c.name AS 'Name', MAX(CASE WHEN cf.followType = 'Call' THEN cf.createdDate ELSE NULL END) AS 'Call Date', MAX(CASE WHEN cf.followType = 'Call' THEN cf.followType ELSE NULL END) AS 'Contact Type', MAX(cf.statusType) AS 'Status', MAX(CASE WHEN cf.statusType = 'PTP' THEN cf.statusTypeDate ELSE NULL END) AS 'PTP Date', MAX(cf.remark) AS 'Remark', l.disbursalAmount AS 'Loan Amount', a.tenure AS 'Tenure', a.roi AS 'ROI', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay Amount', a.repayDate AS 'Repay Date', COALESCE(tc.totalCollectedAmount, 0) AS 'Total Collected Amount', MAX(col.status) AS 'Collection Status', l.disbursalDate AS 'Date', MAX(addr.address) AS 'Address', MONTHNAME(l.disbursalDate) AS 'Disbursal Month', ld.fbLeads AS 'Loan Type', MAX(u.name) AS 'Credited By', lf.LoanFrequency AS 'Loan Frequency', c.employeeType AS 'Employee Type', MAX(cf.createdDate) AS 'Max Follow-up Date' FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN customer c ON ld.customerID = c.customerID LEFT JOIN collectionFollowup cf ON ld.leadID = cf.leadID LEFT JOIN collection col ON l.loanNo = col.loanNo LEFT JOIN address addr ON c.customerID = addr.customerID LEFT JOIN users u ON a.creditedby = u.userID JOIN ( SELECT customerID, COUNT(DISTINCT loanNo) AS LoanFrequency FROM loan WHERE status = 'Disbursed' GROUP BY customerID ) lf ON c.customerID = lf.customerID LEFT JOIN TotalCollected tc ON l.loanNo = tc.loanNo WHERE a.repayDate BETWEEN startDate AND endDate AND l.status = 'Disbursed' AND col.status IN ('Closed', 'Settlement') GROUP BY l.loanNo, ld.customerID, ld.leadID, c.name, l.disbursalAmount, a.tenure, a.roi, a.repayDate, l.disbursalDate, ld.fbLeads, lf.LoanFrequency, c.employeeType, tc.totalCollectedAmount ORDER BY a.repayDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `collection_emi_data`(IN startDate DATE, IN endDate DATE) BEGIN DECLARE start_datetime DATETIME; DECLARE end_datetime DATETIME;
SET start_datetime = CONCAT(startDate, ' 00:00:00'); SET end_datetime = CONCAT(endDate, ' 23:59:59');
SET SESSION sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
SELECT t.loanNo as 'Loan No.', t.leadID as 'Lead ID', COALESCE(l.bankBranch, '') as 'Branch', COALESCE(c.name, '') as 'Name', COALESCE(l.disbursalAmount, '') as 'Loan Amount', COALESCE(l.disbursalDate, '') as 'Disbursed Date', COALESCE(ewp.dueDate, '') as 'Repay Date', CASE WHEN cr.tenure IS NOT NULL THEN CONCAT(cr.tenure, ' Month') ELSE '' END as 'Loan Tenure', COALESCE(a.roi, '') as 'ROI',
CASE WHEN ROW_NUMBER() OVER (PARTITION BY COALESCE(t.referenceNo, CONCAT('txn_', t.id)) ORDER BY t.id) = 1 THEN t.amount ELSE 0 END as 'Collected Amount', (COALESCE(et.interest, 0) + COALESCE(et.principal, 0) + COALESCE(et.penalty, 0) + COALESCE(et.dpd_amount, 0)) as 'Adjusted Amount', COALESCE(et.principal, 0) as 'Principal', COALESCE(et.interest, 0) as 'Interest Amount', (COALESCE(et.penalty, 0) + COALESCE(et.dpd_amount, 0)) as 'Default Interest', COALESCE(ewp.waive_off_amount, 0) as 'Waive Off', ewp.emi_position as 'EMI month', et.emi_status as 'EMI Status',
CASE WHEN t.mode IS NOT NULL AND t.mode != '' AND LOWER(t.mode) != 'upi' THEN t.mode ELSE t.gateway END as 'Collected Mode', DATE(COALESCE(t.transactionDate, t.createdAt)) as 'Collected Date', COALESCE(t.referenceNo, '') as 'Reference No.', COALESCE(op.razorpayPaymentId, '') as 'Pay ID', COALESCE(t.waiver, 0) as 'Discount Amount', COALESCE(ld.monthlyIncome, 0) as 'Monthly Income', CASE WHEN t.status = 1 THEN 'Captured' WHEN t.status = 3 THEN 'Approved' ELSE '' END as 'Status', COALESCE(t.remarks, '') as 'Remark', COALESCE(ld.fbLeads, '') as 'Lead Type', COALESCE(t.updatedAt, '') as 'Approval Date' FROM transactions t INNER JOIN emi_transactions et ON t.id = et.transaction_id INNER JOIN ( SELECT emiID, leadID, waive_off_amount, dueDate, ROW_NUMBER() OVER (PARTITION BY leadID ORDER BY emiID) as emi_position FROM equated_monthly_installments WHERE is_deleted = 0 ) ewp ON ewp.emiID = et.emi_id LEFT JOIN ( SELECT razorpayOrderId, razorpayPaymentId, method FROM onlinepayment WHERE razorpayOrderId IS NOT NULL GROUP BY razorpayOrderId ) op ON op.razorpayOrderId = t.orderId LEFT JOIN customer c ON c.customerID = t.customerID LEFT JOIN approval a ON a.customerID = t.customerID AND a.leadID = t.leadID LEFT JOIN loan l ON l.customerID = t.customerID AND l.leadID = t.leadID LEFT JOIN credits cr ON cr.customerID = t.customerID AND cr.leadID = t.leadID LEFT JOIN leads ld ON ld.customerID = t.customerID AND ld.leadID = t.leadID WHERE t.status IN (1, 3) AND t.emiID = 0 AND ( (t.transactionDate IS NOT NULL AND t.transactionDate BETWEEN start_datetime AND end_datetime) OR (t.transactionDate IS NULL AND t.createdAt BETWEEN start_datetime AND end_datetime) ) ORDER BY t.createdAt DESC;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `collection_summary`( IN start_date DATE, IN end_date DATE ) BEGIN DECLARE total_cases INT DEFAULT 0; DECLARE total_loan_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_repay_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_collection_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_percentage DECIMAL(10,2) DEFAULT 0;
DECLARE ami DECIMAL(15,2) DEFAULT 0; DECLARE tac DECIMAL(15,2) DEFAULT 0; DECLARE ct INT DEFAULT 0; DECLARE pr DECIMAL(15,2) DEFAULT 0; DECLARE tpo DECIMAL(10,2) DEFAULT 0;
IF start_date = CURDATE() AND end_date = CURDATE() THEN
select * from temp_report_results;
ELSE
SELECT COUNT(LL.leadID), SUM(LL.disbursalAmount) INTO total_cases, total_loan_amount FROM approval A INNER JOIN leads le ON le.leadID = A.leadID INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND le.productID = 2;
SELECT SUM(LL.disbursalAmount + (A.tenure * ROUND((LL.disbursalAmount * (A.roi / 100)), 2))), COUNT(*) INTO ami, ct FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND L.productID = 2;
SELECT SUM(IFNULL(collection_sum.total_collected, 0)) INTO tac FROM approval A INNER JOIN leads le ON le.leadID = A.leadID INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as total_collected FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) collection_sum ON LL.leadID = collection_sum.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND L.productID = 2;
SET pr = ami - total_loan_amount; SET tpo = CASE WHEN total_loan_amount != 0 THEN ROUND((pr * 100) / total_loan_amount, 2) ELSE 0 END; SET total_percentage = 100 + tpo;
SELECT 1 as row_order, 'Total Loan Repayment Amount' as type_name, total_cases as no_of_cases_1, ROUND(total_loan_amount) as loan_amount, '100%' as loan_percentage, ct as no_of_cases_2, ROUND(ami) as repay_date_amount, ROUND(tac) as collection_amount, CONCAT(total_percentage, '%') as collection_percentage
UNION ALL
SELECT 2, 'Part Payment Accounts', pp_basic.cases, ROUND(pp_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((pp_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), pp_collection.repay_cases, ROUND(pp_repay.repay_amount), ROUND(pp_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((pp_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM ( SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Part Payment' AND LL.status = 'Disbursed' AND L.productID = 2 ) pp_basic CROSS JOIN ( SELECT COUNT(DISTINCT pp_leads.leadID) as repay_cases, SUM(IFNULL(pp_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Part Payment' AND LL.productID = 2 ) pp_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' AND status = 'Part Payment' GROUP BY leadID ) pp_coll ON pp_leads.leadID = pp_coll.leadID ) pp_collection CROSS JOIN ( SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Part Payment' AND L.productID = 2 ) pp_repay
UNION ALL
SELECT 3, 'Settled Accounts', st_basic.cases, ROUND(st_basic.loan_amount), CONCAT( CASE WHEN st_basic.loan_amount != 0 THEN ROUND((st_basic.loan_amount * 100) / st_basic.loan_amount, 2) ELSE 0 END, '%' ), st_collection.repay_cases, ROUND(st_repay.repay_amount), ROUND(st_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((st_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM ( SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Settlement' AND LL.status = 'Disbursed' AND L.productID = 2 ) st_basic CROSS JOIN ( SELECT COUNT(DISTINCT st_leads.leadID) as repay_cases, SUM(IFNULL(st_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Settlement' AND LL.productID = 2 ) st_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) st_coll ON st_leads.leadID = st_coll.leadID ) st_collection CROSS JOIN ( SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Settlement' AND L.productID = 2 ) st_repay
UNION ALL
SELECT 4, 'Close Accounts', cl_basic.cases, ROUND(cl_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((cl_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), cl_collection.repay_cases, ROUND(cl_repay.repay_amount), ROUND(cl_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((cl_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM ( SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Closed' AND LL.status = 'Disbursed' AND L.productID = 2 ) cl_basic CROSS JOIN ( SELECT COUNT(DISTINCT cl_leads.leadID) as repay_cases, SUM(IFNULL(cl_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID INNER JOIN loan L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Closed' AND L.status = 'Disbursed' AND LL.productID = 2 ) cl_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) cl_coll ON cl_leads.leadID = cl_coll.leadID ) cl_collection CROSS JOIN ( SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Closed' AND LL.status = 'Disbursed' AND L.productID = 2 ) cl_repay
UNION ALL
SELECT 5, 'Actual Payment Received', ap_basic.cases, ROUND(ap_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((ap_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), ap_collection.repay_cases, ROUND(ap_repay.repay_amount), ROUND(ap_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((ap_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM ( SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_basic CROSS JOIN ( SELECT COUNT(DISTINCT ap_leads.leadID) as repay_cases, SUM(IFNULL(ap_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID INNER JOIN loan L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (LL.status = 'Closed' OR LL.status = 'Settlement' OR LL.status = 'Part Payment') AND L.status = 'Disbursed' AND LL.productID = 2 ) ap_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) ap_coll ON ap_leads.leadID = ap_coll.leadID ) ap_collection CROSS JOIN ( SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_repay
UNION ALL
SELECT 6, 'Pending Amount', (total_cases - ap_summary.ap_cases), ROUND(total_loan_amount - ap_summary.ap_loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND(((total_loan_amount - ap_summary.ap_loan_amount) * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), (0 - ap_summary.ap_repay_cases), ROUND(pd_repay.repay_amount), ROUND(ami - ap_summary.ap_collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND(((ami - ap_summary.ap_collection_amount) * 100) / ami, 2) ELSE 0 END, '%' ) FROM ( SELECT COUNT(LL.leadID) as ap_cases, SUM(LL.disbursalAmount) as ap_loan_amount, SUM(IFNULL(ap_coll.collection_amount, 0)) as ap_collection_amount, COUNT(DISTINCT ap_coll.leadID) as ap_repay_cases FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) ap_coll ON LL.leadID = ap_coll.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_summary CROSS JOIN ( SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Disbursed' AND LL.status = 'Disbursed' AND L.productID = 2 ) pd_repay
ORDER BY row_order;
END IF;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `collection_summary_aa`( IN start_date DATE, IN end_date DATE ) BEGIN DECLARE total_cases INT DEFAULT 0; DECLARE total_loan_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_repay_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_collection_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_percentage DECIMAL(10,2) DEFAULT 0;
DECLARE ami DECIMAL(15,2) DEFAULT 0; DECLARE tac DECIMAL(15,2) DEFAULT 0; DECLARE ct INT DEFAULT 0; DECLARE pr DECIMAL(15,2) DEFAULT 0; DECLARE tpo DECIMAL(10,2) DEFAULT 0;
IF start_date = CURDATE() AND end_date = CURDATE() THEN select * from temp_report_results1; ELSE
CREATE TEMPORARY TABLE temp_report_results_new ( row_order INT, type_name VARCHAR(255), no_of_cases_1 INT, loan_amount DECIMAL(15,2), loan_percentage VARCHAR(20), no_of_cases_2 INT, repay_date_amount DECIMAL(15,2), collection_amount DECIMAL(15,2), collection_percentage VARCHAR(20) );
SELECT COUNT(LL.leadID), SUM(LL.disbursalAmount) INTO total_cases, total_loan_amount FROM approval A INNER JOIN leads le ON le.leadID = A.leadID INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND le.productID = 2;
SELECT SUM(LL.disbursalAmount + (A.tenure * ROUND((LL.disbursalAmount * (A.roi / 100)), 2))), COUNT(*) INTO ami, ct FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND L.productID = 2;
SELECT SUM(IFNULL(collection_sum.total_collected, 0)) INTO tac FROM approval A INNER JOIN leads le ON le.leadID = A.leadID INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as total_collected FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) collection_sum ON LL.leadID = collection_sum.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND L.productID = 2;
SET pr = ami - total_loan_amount; SET tpo = CASE WHEN total_loan_amount != 0 THEN ROUND((pr * 100) / total_loan_amount, 2) ELSE 0 END; SET total_percentage = 100 + tpo;
INSERT INTO temp_report_results_new VALUES ( 1, 'Total Loan Repayment Amount', total_cases, ROUND(total_loan_amount), '100%', ct, ROUND(ami), ROUND(tac), CONCAT(total_percentage, '%') );
INSERT INTO temp_report_results_new SELECT 2, 'Part Payment Accounts', pp_basic.cases, ROUND(pp_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((pp_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), pp_collection.repay_cases, ROUND(pp_repay.repay_amount), ROUND(pp_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((pp_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Part Payment' AND LL.status = 'Disbursed' AND L.productID = 2 ) pp_basic CROSS JOIN (
SELECT COUNT(DISTINCT pp_leads.leadID) as repay_cases, SUM(IFNULL(pp_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Part Payment' AND LL.productID = 2 ) pp_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' AND status = 'Part Payment' GROUP BY leadID ) pp_coll ON pp_leads.leadID = pp_coll.leadID ) pp_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Part Payment' AND L.productID = 2 ) pp_repay;
INSERT INTO temp_report_results_new SELECT 3, 'Settled Accounts', st_basic.cases, ROUND(st_basic.loan_amount), CONCAT( CASE WHEN st_basic.loan_amount != 0 THEN ROUND((st_basic.loan_amount * 100) / st_basic.loan_amount, 2) ELSE 0 END, '%' ), st_collection.repay_cases, ROUND(st_repay.repay_amount), ROUND(st_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((st_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Settlement' AND LL.status = 'Disbursed' AND L.productID = 2 ) st_basic CROSS JOIN (
SELECT COUNT(DISTINCT st_leads.leadID) as repay_cases, SUM(IFNULL(st_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Settlement' AND LL.productID = 2 ) st_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) st_coll ON st_leads.leadID = st_coll.leadID ) st_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Settlement' AND L.productID = 2 ) st_repay;
INSERT INTO temp_report_results_new SELECT 4, 'Close Accounts', cl_basic.cases, ROUND(cl_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((cl_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), cl_collection.repay_cases, ROUND(cl_repay.repay_amount), ROUND(cl_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((cl_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Closed' AND LL.status = 'Disbursed' AND L.productID = 2 ) cl_basic CROSS JOIN (
SELECT COUNT(DISTINCT cl_leads.leadID) as repay_cases, SUM(IFNULL(cl_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID INNER JOIN loan L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Closed' AND L.status = 'Disbursed' AND LL.productID = 2 ) cl_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) cl_coll ON cl_leads.leadID = cl_coll.leadID ) cl_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Closed' AND LL.status = 'Disbursed' AND L.productID = 2 ) cl_repay;
INSERT INTO temp_report_results_new SELECT 5, 'Actual Payment Received', ap_basic.cases, ROUND(ap_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((ap_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), ap_collection.repay_cases, ROUND(ap_repay.repay_amount), ROUND(ap_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((ap_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_basic CROSS JOIN (
SELECT COUNT(DISTINCT ap_leads.leadID) as repay_cases, SUM(IFNULL(ap_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID INNER JOIN loan L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (LL.status = 'Closed' OR LL.status = 'Settlement' OR LL.status = 'Part Payment') AND L.status = 'Disbursed' AND LL.productID = 2 ) ap_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) ap_coll ON ap_leads.leadID = ap_coll.leadID ) ap_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_repay;
SET @ap_cases = (SELECT no_of_cases_1 FROM temp_report_results WHERE row_order = 5); SET @ap_loan_amount = (SELECT loan_amount FROM temp_report_results WHERE row_order = 5); SET @ap_collection_amount = (SELECT collection_amount FROM temp_report_results WHERE row_order = 5); SET @ap_repay_cases = (SELECT no_of_cases_2 FROM temp_report_results WHERE row_order = 5);
INSERT INTO temp_report_results_new SELECT 6, 'Pending Amount', (total_cases - @ap_cases), ROUND(total_loan_amount - @ap_loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND(((total_loan_amount - @ap_loan_amount) * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), (0 - @ap_repay_cases), ROUND(pd_repay.repay_amount), ROUND(ami - @ap_collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND(((ami - @ap_collection_amount) * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Disbursed' AND LL.status = 'Disbursed' AND L.productID = 2 ) pd_repay;
SELECT type_name as 'Type', no_of_cases_1 as 'Loan Cases', loan_amount as 'Loan Amount', loan_percentage as 'Loan Percentage', no_of_cases_2 as 'Repay Cases', repay_date_amount as 'Repay Date Amount', collection_amount as 'Collection Amount', collection_percentage as 'Collection Percentage' FROM temp_report_results ORDER BY row_order; IF start_date = CURDATE() AND end_date = CURDATE() THEN DROP TABLE temp_report_results1; CREATE TABLE temp_report_results1 select * from temp_report_results_new; END IF; DROP TEMPORARY TABLE temp_report_results_new; END IF;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `collection_summary_dd`(IN startDate DATE, IN endDate DATE) begin with TotalLoanRepaymentAmount as ( select SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) as `Total Loan Amount` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID WHERE l.status = 'Disbursed' and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate ),
TotalLoanRepayment as ( SELECT 'Total Loan Repayment Amount' as Type, COUNT(DISTINCT ld.leadID) as `Total No of Cases`, SUM(l.disbursalAmount) as `Loan Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) as `Total Repayment Amount`, SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) AS `Total Collected Amount`, ROUND(( SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) )/SUM(l.disbursalAmount), 2) AS `Percentage`, ROUND((SUM(l.disbursalAmount) / (SELECT `Total Loan Amount` FROM TotalLoanRepaymentAmount)) * 100, 2) AS `Loan Amount Percentage` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN ( SELECT loanNo, collectionStatus, collectedMode, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo ) c ON l.loanNo = c.loanNo WHERE l.status = 'Disbursed' and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate ),
PartPaymentAccounts as ( select 'Part Payment Accounts' as Type, COUNT(DISTINCT ld.leadID) as `Total No of Cases`, SUM(l.disbursalAmount) as `Loan Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) as `Total Repayment Amount`, SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) AS `Total Collected Amount`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) ) * 100, 2) AS `Percentage`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / (SELECT `Total Loan Amount` FROM TotalLoanRepaymentAmount)) * 100, 2) AS `Loan Amount Percentage` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN ( SELECT loanNo, collectionStatus, collectedMode, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo ) c ON l.loanNo = c.loanNo WHERE ld.status = 'Part Payment' and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate ),
SettledAccounts as ( select 'Settled Accounts' as Type, COUNT(DISTINCT ld.leadID) as `Total No of Cases`, SUM(l.disbursalAmount) as `Loan Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) AS `Total Repayment Amount`, SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) AS `Total Collected Amount`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) ) * 100, 2) AS `Percentage`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / (SELECT `Total Loan Amount` FROM TotalLoanRepaymentAmount)) * 100, 2) AS `Loan Amount Percentage` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN ( SELECT loanNo, collectionStatus, collectedMode, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo ) c ON l.loanNo = c.loanNo WHERE ld.status = 'Settlement' and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate ),
ClosedAccounts as ( select 'Close Accounts' as Type, COUNT(DISTINCT ld.leadID) as `Total No of Cases`, SUM(l.disbursalAmount) as `Loan Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) as `Total Repayment Amount`, SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) AS `Total Collected Amount`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) ) * 100, 2) AS `Percentage`, ROUND((SUM(ifnull(c.collectedAmount,0)) / (SELECT `Total Loan Amount` FROM TotalLoanRepaymentAmount)) * 100, 2) AS `Loan Amount Percentage` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN ( SELECT loanNo, collectionStatus, collectedMode, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo ) c ON l.loanNo = c.loanNo WHERE ld.status = 'Closed' and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate ),
ActualPaymentReceived as ( select 'Actual Payment Received' as Type, COUNT(DISTINCT ld.leadID) as `Total No of Cases`, SUM(l.disbursalAmount) as `Loan Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) as `Total Repayment Amount`, SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) AS `Total Collected Amount`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) ) * 100, 2) AS `Percentage`, ROUND((SUM(CASE WHEN c.collectionStatus = 'Approved' AND c.collectedMode NOT IN ('Waive Off', 'DISCOUNT') THEN c.collectedAmount ELSE 0 END) / (SELECT `Total Loan Amount` FROM TotalLoanRepaymentAmount)) * 100, 2) AS `Loan Amount Percentage` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN ( SELECT loanNo, collectionStatus, collectedMode, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo ) c ON l.loanNo = c.loanNo WHERE ld.status IN ('Closed', 'Part Payment', 'Settlement') and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate ), PendingAmount as ( select 'Pending Amount' as `Type`, COUNT(DISTINCT ld.leadID) as `Total No of Cases`, SUM(l.disbursalAmount) as `Loan Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) as `Total Repayment Amount`, SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * DATEDIFF(CURDATE(), l.disbursalDate)), 2)) AS `Total Collected Amount`, ROUND( ( SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * DATEDIFF(CURDATE(), l.disbursalDate)), 2)) / SUM(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) ) * 100, 2 ) as `Percentage`, ROUND((SUM(l.disbursalAmount) / (SELECT `Total Loan Amount` FROM TotalLoanRepaymentAmount)) * 100, 2) AS `Loan Amount Percentage` FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN ( SELECT loanNo, collectionStatus, collectedMode, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo ) c ON l.loanNo = c.loanNo WHERE ld.status = 'Disbursed' and ld.productID=2 AND a.repayDate BETWEEN startDate AND endDate )
select * from TotalLoanRepayment union all select * from PartPaymentAccounts union all select * from SettledAccounts union all select * from ClosedAccounts union all select * from ActualPaymentReceived union all select `Type`,`Total No of Cases`,`Loan Amount`,`Total Repayment Amount`,((select `Total Repayment Amount` from TotalLoanRepayment)-(select `Total Collected Amount` from ActualPaymentReceived)) AS `Total Collected Amount`, `Percentage`, `Loan Amount Percentage` from PendingAmount;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `collection_summary_nnew`(IN startDate DATE, IN endDate DATE) BEGIN WITH tmp_collection AS ( SELECT loanNo, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedMode NOT IN ('Waive Off', 'DISCOUNT') GROUP BY loanNo), tmp_loan AS ( SELECT ld.leadID, l.loanNo, l.disbursalAmount, a.roi, a.tenure, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure), 2) AS total_repayment, ld.status AS lead_status, l.status AS loan_status, ld.productID, a.repayDate, l.disbursalDate FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID WHERE ld.productID = 2 AND a.repayDate BETWEEN startDate AND endDate), temp_loan1 as (Select sum(total_repayment) aa from tmp_loan)
SELECT 'Total Loan Repayment Amount' AS `Type`, COUNT(DISTINCT t.leadID) AS `Total No of Cases`, IFNULL(SUM(t.disbursalAmount), 0) AS `Loan Amount`, IFNULL(SUM(t.total_repayment), 0) AS `Total Repayment Amount`, IFNULL(SUM(IFNULL(c.collectedAmount, 0)), 0) AS `Total Collected Amount`, CASE WHEN SUM(t.disbursalAmount) = 0 THEN 0 ELSE ROUND(SUM(t.total_repayment) / SUM(t.disbursalAmount), 2) END AS `Percentage`, CASE WHEN (Select aa from temp_loan1) = 0 THEN 0 ELSE ROUND((SUM(t.disbursalAmount) / (Select aa from temp_loan1)) * 100, 2) END AS `Loan Amount Percentage` FROM tmp_loan t LEFT JOIN tmp_collection c ON t.loanNo = c.loanNo WHERE t.loan_status = 'Disbursed' UNION ALL
SELECT 'Part Payment Accounts' AS `Type`, COUNT(DISTINCT t.leadID) AS `Total No of Cases`, IFNULL(SUM(t.disbursalAmount), 0) AS `Loan Amount`, IFNULL(SUM(t.total_repayment), 0) AS `Total Repayment Amount`, IFNULL(SUM(IFNULL(c.collectedAmount, 0)), 0) AS `Total Collected Amount`, CASE WHEN SUM(t.total_repayment) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / SUM(t.total_repayment)) * 100, 2) END AS `Percentage`, CASE WHEN (Select aa from temp_loan1) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / (Select aa from temp_loan1) ) * 100, 2) END AS `Loan Amount Percentage` FROM tmp_loan t JOIN tmp_collection c ON t.loanNo = c.loanNo WHERE t.lead_status = 'Part Payment' UNION ALL
SELECT 'Settled Accounts' AS `Type`, COUNT(DISTINCT t.leadID) AS `Total No of Cases`, IFNULL(SUM(t.disbursalAmount), 0) AS `Loan Amount`, IFNULL(SUM(t.total_repayment), 0) AS `Total Repayment Amount`, IFNULL(SUM(IFNULL(c.collectedAmount, 0)), 0) AS `Total Collected Amount`, CASE WHEN SUM(t.total_repayment) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / SUM(t.total_repayment)) * 100, 2) END AS `Percentage`, CASE WHEN (Select aa from temp_loan1) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / (Select aa from temp_loan1)) * 100, 2) END AS `Loan Amount Percentage` FROM tmp_loan t LEFT JOIN tmp_collection c ON t.loanNo = c.loanNo WHERE t.lead_status = 'Settlement' UNION ALL
SELECT 'Close Accounts' AS `Type`, COUNT(DISTINCT t.leadID) AS `Total No of Cases`, IFNULL(SUM(t.disbursalAmount), 0) AS `Loan Amount`, IFNULL(SUM(t.total_repayment), 0) AS `Total Repayment Amount`, IFNULL(SUM(IFNULL(c.collectedAmount, 0)), 0) AS `Total Collected Amount`, CASE WHEN SUM(t.total_repayment) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / SUM(t.total_repayment)) * 100, 2) END AS `Percentage`, CASE WHEN (Select aa from temp_loan1) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / (Select aa from temp_loan1)) * 100, 2) END AS `Loan Amount Percentage` FROM tmp_loan t JOIN tmp_collection c ON t.loanNo = c.loanNo WHERE t.lead_status = 'Closed' UNION ALL
SELECT 'Actual Payment Received' AS `Type`, COUNT(DISTINCT t.leadID) AS `Total No of Cases`, IFNULL(SUM(t.disbursalAmount), 0) AS `Loan Amount`, IFNULL(SUM(t.total_repayment), 0) AS `Total Repayment Amount`, IFNULL(SUM(IFNULL(c.collectedAmount, 0)), 0) AS `Total Collected Amount`, CASE WHEN SUM(t.total_repayment) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / SUM(t.total_repayment)) * 100, 2) END AS `Percentage`, CASE WHEN (Select aa from temp_loan1) = 0 THEN 0 ELSE ROUND((SUM(IFNULL(c.collectedAmount,0)) / (Select aa from temp_loan1)) * 100, 2) END AS `Loan Amount Percentage` FROM tmp_loan t LEFT JOIN tmp_collection c ON t.loanNo = c.loanNo WHERE t.lead_status IN ('Closed', 'Part Payment', 'Settlement') UNION ALL
SELECT 'Pending Amount' AS `Type`, COUNT(DISTINCT t.leadID) AS `Total No of Cases`, IFNULL(SUM(t.disbursalAmount), 0) AS `Loan Amount`, IFNULL(SUM(t.total_repayment), 0) AS `Total Repayment Amount`, SUM(ROUND(t.disbursalAmount + (t.disbursalAmount * t.roi / 100 * DATEDIFF(CURDATE(), t.disbursalDate)), 2)) AS `Total Collected Amount`, CASE WHEN SUM(t.total_repayment) = 0 THEN 0 ELSE ROUND((IFNULL(SUM(ROUND(t.disbursalAmount + (t.disbursalAmount * t.roi / 100 * DATEDIFF(CURDATE(), (SELECT MIN(l3.disbursalDate) FROM loan l3 WHERE l3.loanNo = t.loanNo LIMIT 1))),2)),0) / SUM(t.total_repayment)) * 100, 2) END AS `Percentage`, CASE WHEN (Select aa from temp_loan1) = 0 THEN 0 ELSE ROUND((SUM(t.disbursalAmount) / (Select aa from temp_loan1)) * 100, 2) END AS `Loan Amount Percentage` FROM tmp_loan t LEFT JOIN tmp_collection c ON t.loanNo = c.loanNo WHERE t.lead_status = 'Disbursed';
END
CREATE DEFINER=`admin`@`%` PROCEDURE `collection_summarya`( IN start_date DATE, IN end_date DATE ) BEGIN DECLARE total_cases INT DEFAULT 0; DECLARE total_loan_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_repay_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_collection_amount DECIMAL(15,2) DEFAULT 0; DECLARE total_percentage DECIMAL(10,2) DEFAULT 0;
DECLARE ami DECIMAL(15,2) DEFAULT 0; DECLARE tac DECIMAL(15,2) DEFAULT 0; DECLARE ct INT DEFAULT 0; DECLARE pr DECIMAL(15,2) DEFAULT 0; DECLARE tpo DECIMAL(10,2) DEFAULT 0;
DROP TABLE IF EXISTS temp_report_results_new1;
CREATE TABLE temp_report_results_new1 ( row_order INT, type_name VARCHAR(255), no_of_cases_1 INT, loan_amount DECIMAL(15,2), loan_percentage VARCHAR(20), no_of_cases_2 INT, repay_date_amount DECIMAL(15,2), collection_amount DECIMAL(15,2), collection_percentage VARCHAR(20) );
SELECT COUNT(LL.leadID), SUM(LL.disbursalAmount) INTO total_cases, total_loan_amount FROM approval A INNER JOIN leads le ON le.leadID = A.leadID INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND le.productID = 2;
SELECT SUM(LL.disbursalAmount + (A.tenure * ROUND((LL.disbursalAmount * (A.roi / 100)), 2))), COUNT(*) INTO ami, ct FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND L.productID = 2;
SELECT SUM(IFNULL(collection_sum.total_collected, 0)) INTO tac FROM approval A INNER JOIN leads le ON le.leadID = A.leadID INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as total_collected FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) collection_sum ON LL.leadID = collection_sum.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (A.status = 'Approved' OR A.status = 'Approved Process') AND LL.status = 'Disbursed' AND L.productID = 2;
SET pr = ami - total_loan_amount; SET tpo = CASE WHEN total_loan_amount != 0 THEN ROUND((pr * 100) / total_loan_amount, 2) ELSE 0 END; SET total_percentage = 100 + tpo;
INSERT INTO temp_report_results_new1 VALUES ( 1, 'Total Loan Repayment Amount', total_cases, ROUND(total_loan_amount), '100%', ct, ROUND(ami), ROUND(tac), CONCAT(total_percentage, '%') );
INSERT INTO temp_report_results_new1 SELECT 2, 'Part Payment Accounts', pp_basic.cases, ROUND(pp_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((pp_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), pp_collection.repay_cases, ROUND(pp_repay.repay_amount), ROUND(pp_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((pp_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Part Payment' AND LL.status = 'Disbursed' AND L.productID = 2 ) pp_basic CROSS JOIN (
SELECT COUNT(DISTINCT pp_leads.leadID) as repay_cases, SUM(IFNULL(pp_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Part Payment' AND LL.productID = 2 ) pp_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' AND status = 'Part Payment' GROUP BY leadID ) pp_coll ON pp_leads.leadID = pp_coll.leadID ) pp_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Part Payment' AND L.productID = 2 ) pp_repay;
INSERT INTO temp_report_results_new1 SELECT 3, 'Settled Accounts', st_basic.cases, ROUND(st_basic.loan_amount), CONCAT( CASE WHEN st_basic.loan_amount != 0 THEN ROUND((st_basic.loan_amount * 100) / st_basic.loan_amount, 2) ELSE 0 END, '%' ), st_collection.repay_cases, ROUND(st_repay.repay_amount), ROUND(st_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((st_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Settlement' AND LL.status = 'Disbursed' AND L.productID = 2 ) st_basic CROSS JOIN (
SELECT COUNT(DISTINCT st_leads.leadID) as repay_cases, SUM(IFNULL(st_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Settlement' AND LL.productID = 2 ) st_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) st_coll ON st_leads.leadID = st_coll.leadID ) st_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Settlement' AND L.productID = 2 ) st_repay;
INSERT INTO temp_report_results_new1 SELECT 4, 'Close Accounts', cl_basic.cases, ROUND(cl_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((cl_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), cl_collection.repay_cases, ROUND(cl_repay.repay_amount), ROUND(cl_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((cl_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Closed' AND LL.status = 'Disbursed' AND L.productID = 2 ) cl_basic CROSS JOIN (
SELECT COUNT(DISTINCT cl_leads.leadID) as repay_cases, SUM(IFNULL(cl_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID INNER JOIN loan L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND LL.status = 'Closed' AND L.status = 'Disbursed' AND LL.productID = 2 ) cl_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) cl_coll ON cl_leads.leadID = cl_coll.leadID ) cl_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Closed' AND LL.status = 'Disbursed' AND L.productID = 2 ) cl_repay;
INSERT INTO temp_report_results_new1 SELECT 5, 'Actual Payment Received', ap_basic.cases, ROUND(ap_basic.loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND((ap_basic.loan_amount * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), ap_collection.repay_cases, ROUND(ap_repay.repay_amount), ROUND(ap_collection.collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND((ap_collection.collection_amount * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT COUNT(LL.leadID) as cases, SUM(LL.disbursalAmount) as loan_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_basic CROSS JOIN (
SELECT COUNT(DISTINCT ap_leads.leadID) as repay_cases, SUM(IFNULL(ap_coll.collection_amount, 0)) as collection_amount FROM ( SELECT LL.leadID FROM approval A INNER JOIN leads LL ON A.leadID = LL.leadID INNER JOIN loan L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (LL.status = 'Closed' OR LL.status = 'Settlement' OR LL.status = 'Part Payment') AND L.status = 'Disbursed' AND LL.productID = 2 ) ap_leads LEFT JOIN ( SELECT leadID, SUM(collectedAmount) as collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) ap_coll ON ap_leads.leadID = ap_coll.leadID ) ap_collection CROSS JOIN (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND (L.status = 'Closed' OR L.status = 'Settlement' OR L.status = 'Part Payment') AND LL.status = 'Disbursed' AND L.productID = 2 ) ap_repay;
SET @ap_cases = (SELECT no_of_cases_1 FROM temp_report_results_new1 WHERE row_order = 5); SET @ap_loan_amount = (SELECT loan_amount FROM temp_report_results_new1 WHERE row_order = 5); SET @ap_collection_amount = (SELECT collection_amount FROM temp_report_results_new1 WHERE row_order = 5); SET @ap_repay_cases = (SELECT no_of_cases_2 FROM temp_report_results_new1 WHERE row_order = 5);
INSERT INTO temp_report_results_new1 SELECT 6, 'Pending Amount', (total_cases - @ap_cases), ROUND(total_loan_amount - @ap_loan_amount), CONCAT( CASE WHEN total_loan_amount != 0 THEN ROUND(((total_loan_amount - @ap_loan_amount) * 100) / total_loan_amount, 2) ELSE 0 END, '%' ), (0 - @ap_repay_cases), ROUND(pd_repay.repay_amount), ROUND(ami - @ap_collection_amount), CONCAT( CASE WHEN ami != 0 THEN ROUND(((ami - @ap_collection_amount) * 100) / ami, 2) ELSE 0 END, '%' ) FROM (
SELECT SUM( LL.disbursalAmount + ( (DATEDIFF(A.repayDate, LL.disbursalDate)) * ROUND((LL.disbursalAmount * (A.roi / 100)), 2) ) ) as repay_amount FROM approval A INNER JOIN loan LL ON A.leadID = LL.leadID INNER JOIN leads L ON A.leadID = L.leadID AND LL.leadID = L.leadID WHERE (A.repayDate BETWEEN start_date AND end_date) AND L.status = 'Disbursed' AND LL.status = 'Disbursed' AND L.productID = 2 ) pd_repay;
DROP TABLE IF EXISTS temp_report_results; ALTER TABLE temp_report_results_new1 RENAME TO temp_report_results;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `CollectionCityWiseProcedure`(IN start_date Date, IN end_date Date) BEGIN
SELECT COALESCE(ld.city, 'Total') AS 'City', ROUND(SUM(l.disbursalAmount)) AS 'Loan Amount', ROUND(SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) AS 'Repayment Amount', COUNT(*) AS 'Total No of Cases', ROUND(SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END)) AS 'Part Payment Rs.', ROUND(SUM(CASE WHEN c.status = 'Settlement' THEN c.collectedAmount ELSE 0 END)) AS 'Settlement Rs.', ROUND(SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END)) AS 'Closed Rs.', ROUND(SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END)) AS 'Actual Rec', ROUND(SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - (SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END))) AS 'Pending', ROUND((SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Closed%', ROUND((SUM(CASE WHEN c.status IN ('Part Payment', 'Closed') THEN c.collectedAmount ELSE 0 END) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Actual Rec%', ROUND(((SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - (SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END))) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Pending%' FROM loan l JOIN leads ld ON l.leadID = ld.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN collection c ON l.leadID = c.leadID WHERE a.repayDate BETWEEN start_date AND end_date AND ld.city IN ('Bangalore', 'Hyderabad', 'Mumbai', 'New Delhi', 'Chennai', 'Pune', 'Kolkata', 'Delhi', 'Ahmedabad', 'Ghaziabad', 'Gurugram', 'Bengaluru', 'Noida', 'Faridabad', 'Coimbatore', 'Jaipur', 'Lucknow', 'Greater Noida', 'Aurangabad', 'Surat') AND l.status = 'Disbursed' GROUP BY ld.city WITH ROLLUP; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `CollectionCreditmanagerWiseProcedure`( IN start_date DATE, IN end_date DATE ) BEGIN SELECT COALESCE(u.name, 'Total') AS 'Name', SUM(l.disbursalAmount) AS 'Loan Amount', ROUND(SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)), 2) AS 'Repayment Amount', COUNT(*) AS 'Total No of Cases', ROUND(SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END)) AS 'Part Payment Rs.', ROUND(SUM(CASE WHEN c.status = 'Settlement' THEN c.collectedAmount ELSE 0 END)) AS 'Settlement Rs.', ROUND(SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END)) AS 'Closed Rs.', ROUND(SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END)) AS 'Actual Rec', ROUND(SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - (SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END))) AS 'Pending', ROUND((SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Closed%', ROUND((SUM(CASE WHEN c.status IN ('Part Payment', 'Closed') THEN c.collectedAmount ELSE 0 END) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Actual Rec%', ROUND(((SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - (SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END))) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Pending%' FROM loan l JOIN leads ld ON l.leadID = ld.leadID JOIN approval a ON l.leadID = a.leadID JOIN users u ON a.creditedby = u.userID LEFT JOIN collection c ON l.leadID = c.leadID WHERE a.repayDate BETWEEN start_date AND end_date AND l.status = 'Disbursed' GROUP BY u.name WITH ROLLUP; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `CollectionSanctionalmanagerWiseProcedure`( IN start_date DATE, IN end_date DATE ) BEGIN SELECT COALESCE(u.name, 'Total') AS 'Name', ROUND(SUM(l.disbursalAmount)) AS 'Loan Amount', ROUND(SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) AS 'Repayment Amount', COUNT(*) AS 'Total No of Cases', ROUND(SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END)) AS 'Part Payment Rs.', ROUND(SUM(CASE WHEN c.status = 'Settlement' THEN c.collectedAmount ELSE 0 END)) AS 'Settlement Rs.', ROUND(SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END)) AS 'Closed Rs.', ROUND(SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END)) AS 'Actual Rec', ROUND(SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - (SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END))) AS 'Pending', ROUND((SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Closed%', ROUND((SUM(CASE WHEN c.status IN ('Part Payment', 'Closed') THEN c.collectedAmount ELSE 0 END) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Actual Rec%', ROUND(((SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - (SUM(CASE WHEN c.status = 'Part Payment' THEN c.collectedAmount ELSE 0 END) + SUM(CASE WHEN c.status = 'Closed' THEN c.collectedAmount ELSE 0 END))) / SUM(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) * 100, 2) AS 'Pending%' FROM loan l JOIN leads ld ON l.leadID = ld.leadID JOIN approval a ON l.leadID = a.leadID JOIN users u ON u.userID = a.sanctionalloUID LEFT JOIN collection c ON l.leadID = c.leadID WHERE a.repayDate BETWEEN start_date AND end_date AND l.status = 'Disbursed' GROUP BY u.name WITH ROLLUP; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `CreditReportNewCasesProcedure`( IN start_date DATE, IN end_date DATE ) BEGIN SELECT u.Name, SUM(CASE WHEN a.status = 'Approved Process' THEN 1 ELSE 0 END) AS `Approved process`, SUM(CASE WHEN a.status = 'Approved' THEN 1 ELSE 0 END) AS `Approved`, SUM(CASE WHEN a.status = 'Rejected Process' THEN 1 ELSE 0 END) AS `Rejected process`, SUM(CASE WHEN a.status = 'Rejected' THEN 1 ELSE 0 END) AS `Rejected`, SUM(CASE WHEN a.status = 'Not Required' THEN 1 ELSE 0 END) AS `Not Required`, SUM(CASE WHEN a.status = 'Not Required Process' THEN 1 ELSE 0 END) AS `Not Required Process`, SUM(CASE WHEN l.status = 'Disbursal Sheet Send' THEN 1 ELSE 0 END) AS `Bank update`, SUM(CASE WHEN l.status = 'Disbursed' THEN 1 ELSE 0 END) AS `Disbursed`, COUNT(DISTINCT a.leadID) AS `Total Cases` FROM approval a JOIN leads ld ON a.leadID = ld.leadID LEFT JOIN loan l ON a.leadID = l.leadID JOIN users u ON a.creditedby = u.userID WHERE (ld.fbleads = 'New Case' OR ld.fbleads = 'Existing Case') AND a.repayDate BETWEEN start_date AND end_date GROUP BY u.Name; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `CreditReportRepeatCasesProcedure`( IN start_date DATE, IN end_date DATE ) BEGIN SELECT u.Name, SUM(CASE WHEN a.status = 'Approved Process' THEN 1 ELSE 0 END) AS `Approved process`, SUM(CASE WHEN a.status = 'Approved' THEN 1 ELSE 0 END) AS `Approved`, SUM(CASE WHEN a.status = 'Rejected Process' THEN 1 ELSE 0 END) AS `Rejected process`, SUM(CASE WHEN a.status = 'Rejected' THEN 1 ELSE 0 END) AS `Rejected`, SUM(CASE WHEN a.status = 'Not Required' THEN 1 ELSE 0 END) AS `Not Required`, SUM(CASE WHEN a.status = 'Not Required Process' THEN 1 ELSE 0 END) AS `Not Required Process`, SUM(CASE WHEN l.status = 'Disbursal Sheet Send' THEN 1 ELSE 0 END) AS `Bank update`, SUM(CASE WHEN l.status = 'Disbursed' THEN 1 ELSE 0 END) AS `Disbursed`, COUNT(DISTINCT a.leadID) AS `Total Cases` FROM approval a JOIN leads ld ON a.leadID = ld.leadID LEFT JOIN loan l ON a.leadID = l.leadID JOIN users u ON a.creditedby = u.userID WHERE ld.fbleads = 'Repeat Case' AND a.repayDate BETWEEN start_date AND end_date GROUP BY u.Name; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `datewise_payday_pending`(IN date_param DATE) BEGIN SELECT c.Name AS `Name`, ROUND(a.loanAmtApproved, 2) AS `Loan Amount`, ROUND(l.disbursalAmount - (0.10 * l.disbursalAmount + 0.18 * (0.10 * l.disbursalAmount)), 0) AS `Disbursed Amount`, COALESCE(SUM(CASE WHEN col.status = 'Part Payment' AND col.collectionstatus = 'Approved' AND col.collectedmode != 'Waive off' THEN col.collectedamount ELSE 0 END), 0) AS `Part Payment Amount` FROM customer c JOIN approval a ON c.customerID = a.customerID JOIN loan l ON a.leadID = l.leadID LEFT JOIN collection col ON l.leadID = col.leadID AND col.status = 'Part Payment' AND col.collectionstatus = 'Approved' AND col.collectedmode != 'Waive off' WHERE DATE(a.repaydate) = date_param GROUP BY c.Name, ROUND(a.loanAmtApproved, 2), ROUND(l.disbursalAmount - (0.10 * l.disbursalAmount + 0.18 * (0.10 * l.disbursalAmount)), 0);
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `DateWiseEMI`( IN start_date DATE, IN end_date DATE ) begin select DATE(dueDate) as `Due Date`, COUNT(DISTINCT leadID) as `Total Leads`, COUNT(DISTINCT CASE WHEN status = 'paid' THEN leadID END) as `Paid`, COUNT(DISTINCT CASE WHEN status = 'due' THEN leadID END) as `Due`, COUNT(DISTINCT CASE WHEN status = 'partially-paid' THEN leadID END) as `Part Payment` from equated_monthly_installments WHERE dueDate BETWEEN start_date AND end_date GROUP BY DATE(dueDate); END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `disbursalAmount_asondate`(IN startDate DATE) BEGIN select max(disbursalDate), sum(ifnull(l.disbursalAmount,0)) DisbursedAmount, sum(CASE WHEN payout_status=2 THEN ifnull(l.disbursalAmount,0) END) UpdateUTRDisbursedAmount from loan l inner join leads le on l.leadID=le.leadID where l.status='Disbursed' and l.disbursalDate<=startDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_partner_data_as_disbursal`( IN start_date DATE, IN end_date DATE, IN name VARCHAR(255)) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); Select '' referrer, utmSource, dsa_name, count(*) 'Lead Count', count( CASE when fresh_status = 'Fresh Lead' then 1 end ) 'Fresh Lead', count( CASE when approved_status = 'Approved' then 1 end ) 'Approved', count( CASE when disbursalAmount > 0 then 1 end ) 'Disbursed', sum(disbursalAmount) 'Disbursed Amount' from (select leads.leadID, leads.utmSource, u.name as dsa_name, customer.mobile, leads.createdDate AS leads_date, leads.customerID, leads.loanRequeried as 'Loan required', leads.state, leads.status AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, ifnull(loan.disbursalAmount,0) disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate, ifnull( ( select status from callhistoryLogs where status = 'Approved' and leadID = leads.leadID limit 1 ), '' ) approved_status, ifnull( ( select status from callhistoryLogs where status = 'Fresh Lead' and leadID = leads.leadID limit 1 ), '' ) fresh_status, (CASE WHEN expiryDate is null THEN (CASE WHEN ifnull(loan.disbursalDate,0)>0 THEN DATEDIFF(loan.disbursalDate,DATE_FORMAT(leads.createdDate,'%Y-%m-%d')) ELSE 1 END) ELSE (CASE WHEN loan.disbursalDate <= DATE_FORMAT(expiryDate,'%Y-%m-%d') THEN 1 ELSE 0 END) END ) as attr_status
