CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_partner_data_as_disbursal_billing`( IN start_date DATE, IN end_date DATE ) BEGIN
SET sql_mode = (SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
SELECT * FROM ( SELECT leads.leadID, leads.utmSource AS leads_utmSource, leads.utm_assigned_date, leads.createdDate AS leads_date, leads.customerID, leads.loanRequeried AS 'Loan required', leads.state, leads.status AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, IFNULL(loan.disbursalAmount, 0) AS disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate, ua_last.source AS utmSource, ua_last.expiryDate,
CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN loan.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status
FROM leads
JOIN customer ON leads.customerID = customer.customerID
/* ✅ Faster latest attribution using MAX(id) */ LEFT JOIN ( SELECT ua.* FROM user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = leads.customerID
LEFT JOIN approval ON leads.leadID = approval.leadID
LEFT JOIN loan ON leads.leadID = loan.leadID
/* ✅ Index-friendly date filter */ WHERE loan.disbursalDate >= start_date AND loan.disbursalDate <= end_date AND loan.payout_status = 2 AND loan.status = 'Disbursed' AND leads.fbLeads <> 'Repeat Case'
) t WHERE attr_status = 1;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_partner_data_as_leads`( IN start_date DATE, IN end_date DATE) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); Select '' referrer, source, count(*) 'Lead Count', count( CASE when approved_status = 'Approved' then 1 end ) 'Approved', count( CASE when disbursalAmount > 0 then 1 end ) 'Disbursed', sum(disbursalAmount) 'Disbursed Amount' from (select leads.leadID, ua.source, customer.mobile, ua.createdDate AS leads_date, leads.customerID, leads.loanRequeried as 'Loan required', leads.state, leads.status AS lead_current_status, ifnull(loan.disbursalAmount,0) disbursalAmount, loan.disbursalDate, ifnull( ( select status from callhistoryLogs where status = 'Approved' and leadID = leads.leadID limit 1 ), '' ) approved_status from
customer join user_attributions ua on ua.customerID=customer.customerID left join leads on leads.customerID=customer.customerID left join loan ON leads.leadID = loan.leadID where ua.expiryDate<=now() and DATE_FORMAT(leads.createdDate, '%Y-%m-%d')>= start_date and DATE_FORMAT(leads.createdDate, '%Y-%m-%d')<=end_date group by customer.customerID) ta group by source;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_partner_data_as_leads_new`( IN start_date DATE, IN end_date DATE) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); Select '' referrer, source, count(*) 'Lead Count', count( CASE when approved_status = 'Approved' then 1 end ) 'Approved', count( CASE when disbursalAmount > 0 then 1 end ) 'Disbursed', sum(disbursalAmount) 'Disbursed Amount' from (select leads.leadID, ua.source, customer.mobile, ua.createdDate AS leads_date, leads.customerID, leads.loanRequeried as 'Loan required', leads.state, leads.status AS lead_current_status, ifnull(loan.disbursalAmount,0) disbursalAmount, loan.disbursalDate, ifnull( ( select status from callhistoryLogs where status = 'Approved' and leadID = leads.leadID limit 1 ), '' ) approved_status from
customer join user_attributions ua on ua.customerID=customer.customerID left join leads on leads.customerID=customer.customerID left join loan ON leads.leadID = loan.leadID where ua.expiryDate<=now() and DATE_FORMAT(leads.createdDate, '%Y-%m-%d')>= start_date and DATE_FORMAT(leads.createdDate, '%Y-%m-%d')<=end_date group by customer.customerID) ta group by source;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_partner_data_list`( IN start_date DATE, IN end_date DATE) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); select customer.customerID, leads.leadID, customer.name, (CASE WHEN productID=1 THEN 'EMI Loan' ELSE 'Payday' END) LoanType, '' as referrer, ifnull(leads.utmSource,ua.source) source, leads.createdDate AS leads_date, ifnull(max(expiryDate),DATE_ADD(leads.createdDate, INTERVAL 30 DAY)) as expiryDate, leads.loanRequeried as 'Loan required', leads.state, (CASE WHEN leads.status= 'Disbursed' and ifnull(loan.payout_status,0)=2 THEN 'Disbursed' else leads.status end) AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, ifnull(loan.disbursalAmount,0) disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate, max(ua.createdDate) attr_date, ifnull(ua.medium,'') attr_medium, (CASE WHEN ifnull(loan.disbursalDate,0)>0 THEN DATEDIFF(loan.disbursalDate,DATE_FORMAT(ifnull(max(ua.createdDate),leads.createdDate),'%Y-%m-%d')) ELSE 1 END) as diffdate from customer join leads on leads.customerID=customer.customerID Left join user_attributions ua on ua.customerID=customer.customerID left join approval ON leads.leadID = approval.leadID left join loan ON leads.leadID = loan.leadID where DATE_FORMAT(leads.createdDate, '%Y-%m-%d') between start_date and end_date group by leads.leadID having diffdate<=30 UNION ALL select customer.customerID, leads.leadID, customer.name, (CASE WHEN productID=1 THEN 'EMI Loan' ELSE 'Payday' END) LoanType, '' as referrer, leads.utmSource source, leads.createdDate AS leads_date, DATE_ADD(leads.createdDate, INTERVAL 30 DAY) as expiryDate, leads.loanRequeried as 'Loan required', leads.state, (CASE WHEN leads.status= 'Disbursed' and ifnull(loan.payout_status,0)=2 THEN 'Disbursed' else leads.status end) AS lead_current_status, 'Approved' AS approval_status, loan.disbursalAmount as loanAmtApproved, ifnull(loan.disbursalAmount,0) disbursalAmount, leads.createdDate AS approval_decision_date, loan.disbursalDate, leads.createdDate as attr_date, '' As attr_medium, '30' as diffdate from customer join leads on leads.customerID=customer.customerID join loan ON leads.leadID = loan.leadID where loan.disbursalDate between start_date and end_date and leads.fbLeads='Repeat Case' and leads.utmSource in ('arthashree','Loanzy'); END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_userwise_report`( IN report_type VARCHAR(20), IN utm_codes VARCHAR(50), IN start_date DATE, IN end_date DATE, IN start_from INT, IN per_page_record INT, IN api_type VARCHAR(30), IN in_lead_status VARCHAR(50), IN last_commission_date DATE, IN total_commission_amount INT, IN commission_type VARCHAR(20), IN commission_value INT, IN filter_type VARCHAR(30) ) BEGIN DECLARE utmCode varchar(500000); DECLARE mobile_hash int; SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', '')); SET SESSION group_concat_max_len = 10000000; SET @mobile_hash = IF(utm_codes = 'Performance_Max_Custom_Audience_old', 1, 0);
IF filter_type = 'disbursal' THEN SET @filterqery = CONCAT(' loan.disbursalDate BETWEEN "', start_date, '" AND "', end_date, ' 23:59:59" '); ELSE SET @filterqery = CONCAT(' leads.createdDate BETWEEN "', start_date, '" AND "', end_date, ' 23:59:59" '); END IF;
SET utmCode = IFNULL((select group_concat(utm_source SEPARATOR "','") from user_utm_link where user_id=(select internal_user_id from dsa.users where utm_code=utm_codes limit 1)), utm_codes);
IF report_type = 'total' AND api_type = 'api' THEN SET @sql = CONCAT( 'SELECT COUNT(DISTINCT leadID) AS lead_count, COUNT(CASE WHEN status IN (\'Disbursed\', \'Settlement\', \'Closed\', \'Part Payment\', \'Blacklisted\') THEN leadID END) AS disbursed_leads, COUNT(CASE WHEN status = \'Part Payment\' THEN leadID END) AS part_payment_leads, COUNT(CASE WHEN status IN (\'Closed\', \'Settlement\', \'Blacklisted\') THEN leadID END) AS closed_leads, COUNT(CASE WHEN status IN (\'Rejected\', \'Rejected Process\', \'Not Eligible\') THEN leadID END) AS rejected_leads, COUNT(CASE WHEN status IN (\'Not Interested\', \'Not Required\', \'Not Required Process\') THEN leadID END) AS not_interested_leads, COUNT(CASE WHEN status IN (\'Disbursed\', \'Part Payment\') AND repayDate < DATE_FORMAT(NOW(), \'%Y-%m-%d\') THEN leadID END) AS overdue_leads, SUM(CASE WHEN loan_status = \'Disbursed\' THEN disbursalAmount END) AS disbursal_amount, (CASE WHEN \'', commission_type, '\' = \'disbursal\' THEN (SUM(CASE WHEN loan_status = \'Disbursed\' AND payout_status = 2 THEN disbursalAmount END) * 3 / 100) ELSE COUNT(DISTINCT leadID) * ', commission_value, ' END) AS commission_amount FROM ( SELECT leads.leadID, leads.status, approval.repayDate, loan.disbursalAmount, loan.status AS loan_status, loan.payout_status, ua_last.Source AS utmSource, CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN loan.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status FROM leads JOIN customer ON leads.customerID = customer.customerID LEFT JOIN ( SELECT ua.* FROM user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = leads.customerID LEFT JOIN approval ON leads.leadID = approval.leadID LEFT JOIN loan ON leads.leadID = loan.leadID WHERE (ua_last.Source IN ( \'', utmCode, '\' ) AND leads.fbLeads <> \'Repeat Case\') AND loan.payout_status = 2 AND loan.status = \'Disbursed\' AND ', @filterqery, ' ) t WHERE attr_status = 1' );
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
ELSEIF report_type = 'list' AND api_type = 'api' AND in_lead_status = 'ALL' THEN SET @sql = CONCAT( 'SELECT leadID, name, pancard, mobile, leads_date, customerID, `Loan required`, state, lead_current_status, approval_status, loanAmtApproved, disbursalAmount, approval_decision_date, disbursalDate, utmSource FROM ( SELECT leads.leadID, customer.name, (CASE WHEN @mobile_hash=1 THEN 0 ELSE customer.pancard END) AS pancard, (CASE WHEN @mobile_hash=1 THEN 0 ELSE customer.mobile END) AS mobile, leads.createdDate AS leads_date, leads.customerID, leads.loanRequeried AS `Loan required`, leads.state, leads.status AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, loan.disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate, ua_last.Source AS utmSource, CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN loan.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status FROM leads JOIN customer ON leads.customerID = customer.customerID LEFT JOIN ( SELECT ua.* FROM user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = leads.customerID LEFT JOIN approval ON leads.leadID = approval.leadID LEFT JOIN loan ON leads.leadID = loan.leadID WHERE (ua_last.Source IN ( \'', utmCode, '\' ) AND leads.fbLeads <> \'Repeat Case\') AND loan.payout_status = 2 AND loan.status = \'Disbursed\' AND ', @filterqery, ' GROUP BY leads.leadID ) t WHERE attr_status = 1 LIMIT ', start_from, ', ', per_page_record );
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
ELSE SET @sql = CONCAT( 'SELECT leadID, name, pancard, mobile, leads_date, customerID, `Loan required`, state, lead_current_status, approval_status, loanAmtApproved, disbursalAmount, approval_decision_date, disbursalDate, utmSource FROM ( SELECT leads.leadID, customer.name, (CASE WHEN @mobile_hash=1 THEN 0 ELSE customer.pancard END) AS pancard, (CASE WHEN @mobile_hash=1 THEN 0 ELSE customer.mobile END) AS mobile, leads.createdDate AS leads_date, leads.customerID, leads.loanRequeried AS `Loan required`, leads.state, leads.status AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, loan.disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate, ua_last.Source AS utmSource, CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN loan.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status FROM leads JOIN customer ON leads.customerID = customer.customerID LEFT JOIN ( SELECT ua.* FROM user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = leads.customerID LEFT JOIN approval ON leads.leadID = approval.leadID LEFT JOIN loan ON leads.leadID = loan.leadID WHERE (ua_last.Source IN ( \'', utmCode, '\' ) AND leads.fbLeads <> \'Repeat Case\') AND loan.payout_status = 2 AND loan.status = \'Disbursed\' AND ', @filterqery, ' AND leads.status = \'', in_lead_status, '\' GROUP BY leads.leadID ) t WHERE attr_status = 1 LIMIT ', start_from, ', ', per_page_record );
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt; END IF;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_userwise_report_new`( IN report_type VARCHAR(20), IN utm_codes VARCHAR(50), IN start_date DATE, IN end_date DATE, IN start_from INT, IN per_page_record INT, IN api_type VARCHAR(30), IN in_lead_status VARCHAR(50), IN last_commission_date DATE, IN total_commission_amount INT, IN commission_type VARCHAR(20), IN commission_value INT, IN filter_type VARCHAR(30) ) BEGIN DECLARE utmCode varchar(1024); SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', ''));
IF filter_type = 'disbursal' THEN SET @filterqery = CONCAT(' loan.disbursalDate BETWEEN "', start_date, '" AND "', end_date, ' 23:59:59" '); ELSE SET @filterqery = CONCAT(' leads.createdDate BETWEEN "', start_date, '" AND "', end_date, ' 23:59:59" '); END IF; SET utmCode = IFNULL((select group_concat(utm_source SEPARATOR "','") from user_utm_link where user_id=(select internal_user_id from dsa.users where utm_code=utm_codes)), utm_codes); IF report_type = 'total' AND api_type = 'api' THEN
SET @sql = CONCAT( 'SELECT COUNT(DISTINCT leads.leadID) AS lead_count, COUNT(CASE WHEN leads.status IN (\'Disbursed\', \'Settlement\', \'Closed\', \'Part Payment\', \'Blacklisted\') THEN leads.leadID END) AS disbursed_leads, COUNT(CASE WHEN leads.status = \'Part Payment\' THEN leads.leadID END) AS part_payment_leads, COUNT(CASE WHEN leads.status IN (\'Closed\', \'Settlement\', \'Blacklisted\') THEN leads.leadID END) AS closed_leads, COUNT(CASE WHEN leads.status IN (\'Rejected\', \'Rejected Process\', \'Not Eligible\') THEN leads.leadID END) AS rejected_leads, COUNT(CASE WHEN leads.status IN (\'Not Interested\', \'Not Required\', \'Not Required Process\') THEN leads.leadID END) AS not_interested_leads, COUNT(CASE WHEN leads.status IN (\'Disbursed\', \'Part Payment\') AND approval.repayDate < DATE_FORMAT(NOW(), \'%Y-%m-%d\') THEN leads.leadID END) AS overdue_leads, SUM(CASE WHEN loan.status = \'Disbursed\' THEN loan.disbursalAmount END) AS disbursal_amount, (CASE WHEN \'', commission_type, '\' = \'disbursal\' THEN (SUM(CASE WHEN loan.status = \'Disbursed\' and loan.payout_status=2 THEN loan.disbursalAmount END) * (select ifnull(value,3) from dsa.commission_slab where SUM(CASE WHEN loan.status = \'Disbursed\' and loan.payout_status=2 THEN loan.disbursalAmount END) between start and end and profile_id=(select profile.id from dsa.profile join dsa.users on profile.user_id=users.id where utm_code in ( \'', utmCode, '\' )))/ 100) ELSE COUNT(DISTINCT leads.leadID) * ', commission_value, ' END) AS commission_amount FROM leads JOIN customer ON leads.customerID = customer.customerID LEFT JOIN approval ON leads.leadID = approval.leadID LEFT JOIN loan ON leads.leadID = loan.leadID WHERE (leads.utmSource in ( \'', utmCode, '\' ) AND leads.fbLeads <> \'Repeat Case\') AND ifnull(DATEDIFF(loan.disbursalDate,DATE_FORMAT(leads.createdDate, \'%Y-%m-%d \')),0)<=30 AND ', @filterqery );
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
ELSEIF report_type = 'list' AND api_type = 'api' AND in_lead_status = 'ALL' THEN SET @sql = CONCAT( 'SELECT leads.leadID, customer.name, customer.pancard, customer.mobile, leads.createdDate AS leads_date, leads.customerID, leads.loanRequeried AS "Loan required", leads.state, leads.status AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, loan.disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate FROM leads JOIN customer ON leads.customerID = customer.customerID LEFT JOIN approval ON leads.leadID = approval.leadID LEFT JOIN loan ON leads.leadID = loan.leadID WHERE (leads.utmSource in ( \'', utmCode, '\' ) AND leads.fbLeads <> \'Repeat Case\') AND ifnull(DATEDIFF(loan.disbursalDate,DATE_FORMAT(leads.createdDate, \'%Y-%m-%d \')),0)<=30 AND ', @filterqery, ' GROUP BY leads.leadID LIMIT ', start_from, ', ', per_page_record );
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
ELSE
SET @sql = CONCAT( 'SELECT leads.leadID, customer.name, customer.pancard, customer.mobile, leads.createdDate AS leads_date, leads.customerID, leads.loanRequeried AS "Loan required", leads.state, leads.status AS lead_current_status, approval.status AS approval_status, approval.loanAmtApproved, loan.disbursalAmount, approval.createdDate AS approval_decision_date, loan.disbursalDate FROM leads JOIN customer ON leads.customerID = customer.customerID LEFT JOIN approval ON leads.leadID = approval.leadID LEFT JOIN loan ON leads.leadID = loan.leadID WHERE (leads.utmSource in ( \'', utmCode, '\' ) AND leads.fbLeads <> \'Repeat Case\') AND ifnull(DATEDIFF(loan.disbursalDate,DATE_FORMAT(leads.createdDate, \'%Y-%m-%d \')),0)<=30 AND ', @filterqery, ' AND leads.status = \'', in_lead_status, '\' GROUP BY leads.leadID LIMIT ', start_from, ', ', per_page_record );
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt; END IF;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `dsa_userwise_report_opt`( IN report_type VARCHAR(20), IN utm_codes VARCHAR(50), IN start_date DATE, IN end_date DATE, IN start_from INT, IN per_page_record INT, IN api_type VARCHAR(30), IN in_lead_status VARCHAR(50), IN commission_type VARCHAR(20), IN commission_value INT, IN filter_type VARCHAR(30) ) BEGIN
DECLARE utmCode TEXT;
SET SESSION group_concat_max_len = 1000000;
IF filter_type = 'disbursal' THEN SET @date_filter = CONCAT( 'loan.disbursalDate BETWEEN ''', start_date, ''' AND ''', end_date, ' 23:59:59''' ); ELSE SET @date_filter = CONCAT( 'l.createdDate BETWEEN ''', start_date, ''' AND ''', end_date, ' 23:59:59''' ); END IF;
SELECT IFNULL( GROUP_CONCAT(utm_source SEPARATOR "','"), utm_codes ) INTO utmCode FROM user_utm_link WHERE user_id = ( SELECT internal_user_id FROM dsa.users WHERE utm_code = utm_codes LIMIT 1 );
IF report_type='total' AND api_type='api' THEN
SET @sql = CONCAT(
'SELECT
COUNT(DISTINCT l.leadID) AS lead_count,
SUM(l.status IN (''Disbursed'',''Settlement'',''Closed'',''Part Payment'',''Blacklisted'')) AS disbursed_leads,
SUM(l.status=''Part Payment'') AS part_payment_leads,
SUM(l.status IN (''Closed'',''Settlement'',''Blacklisted'')) AS closed_leads,
SUM(l.status IN (''Rejected'',''Rejected Process'',''Not Eligible'')) AS rejected_leads,
SUM(l.status IN (''Not Interested'',''Not Required'',''Not Required Process'')) AS not_interested_leads,
SUM( l.status IN (''Disbursed'',''Part Payment'') AND approval.repayDate < CURDATE() ) AS overdue_leads,
SUM( CASE WHEN loan.status=''Disbursed'' THEN loan.disbursalAmount ELSE 0 END ) AS disbursal_amount,
CASE
WHEN ''', commission_type, ''' = ''disbursal''
THEN SUM( CASE WHEN loan.payout_status=2 THEN loan.disbursalAmount ELSE 0 END ) * ', commission_value, ' / 100
ELSE COUNT(DISTINCT l.leadID) * ', commission_value, '
END AS commission_amount
FROM leads l
JOIN customer c ON c.customerID = l.customerID
LEFT JOIN user_attributions ua ON ua.id = ( SELECT MAX(id) FROM user_attributions WHERE customerID = l.customerID )
LEFT JOIN approval ON approval.leadID = l.leadID
LEFT JOIN loan ON loan.leadID = l.leadID
WHERE ua.Source IN (''', utmCode, ''')
AND l.fbLeads <> ''Repeat Case''
AND ', @date_filter
);
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
ELSE
SET @sql = CONCAT(
'SELECT
l.leadID, c.name, c.pancard, c.mobile, l.createdDate AS lead_date, l.loanRequeried, l.state, l.status AS lead_status, approval.loanAmtApproved, loan.disbursalAmount, loan.disbursalDate, ua.Source AS utmSource
FROM leads l
JOIN customer c ON c.customerID = l.customerID
LEFT JOIN user_attributions ua ON ua.id = ( SELECT MAX(id) FROM user_attributions WHERE customerID = l.customerID )
LEFT JOIN approval ON approval.leadID = l.leadID
LEFT JOIN loan ON loan.leadID = l.leadID
WHERE ua.Source IN (''', utmCode, ''')
AND l.fbLeads <> ''Repeat Case''
AND ', @date_filter,
IF( in_lead_status <> 'ALL', CONCAT(' AND l.status = ''', in_lead_status, ''''), '' ),
' ORDER BY l.leadID DESC
LIMIT ', start_from, ',', per_page_record
);
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
END IF;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `emi_collection_summary`( IN start_date DATE, IN end_date DATE ) BEGIN
DECLARE total_emi_cases INT; SELECT COUNT(*) INTO total_emi_cases FROM equated_monthly_installments WHERE is_deleted = 0 AND duedate BETWEEN start_date AND end_date;
SELECT 'Total EMI' AS `type`, FORMAT(COUNT(*), 0, 'en_IN') AS `total no OF cases`, FORMAT(SUM(principal), 2, 'en_IN') AS `due principal`, FORMAT(SUM(amountpayable), 2, 'en_IN') AS `total repayment amount`, FORMAT(SUM(paymentreceived), 2, 'en_IN') AS `total collected amount`, FORMAT(SUM( CASE WHEN status = 'due' THEN amountpayable WHEN status = 'partially-paid' THEN (amountpayable - paymentreceived) ELSE 0 END), 2, 'en_IN') AS `total pending amount`, FORMAT(SUM(waive_off_amount), 2, 'en_IN') AS `waive OFF amount`, CONCAT(ROUND((SUM(paymentreceived) / SUM(amountpayable)) * 100, 2), '%') AS `percentage` FROM equated_monthly_installments WHERE is_deleted = 0 AND duedate BETWEEN start_date AND end_date UNION ALL SELECT 'Total Paid' AS `type`, FORMAT(COUNT(*), 0, 'en_IN') AS `total no OF cases`, FORMAT(SUM(principal), 2, 'en_IN') AS `due principal`, FORMAT(SUM(amountpayable), 2, 'en_IN') AS `total repayment amount`, FORMAT(SUM(paymentreceived), 2, 'en_IN') AS `total collected amount`, FORMAT(SUM( CASE WHEN status = 'due' THEN amountpayable WHEN status = 'partially-paid' THEN (amountpayable - paymentreceived) ELSE 0 END), 2, 'en_IN') AS `total pending amount`, FORMAT(SUM(waive_off_amount), 2, 'en_IN') AS `waive OFF amount`, CONCAT(ROUND((COUNT(*) / total_emi_cases) * 100, 2), '%') AS `percentage` FROM equated_monthly_installments WHERE status = 'Paid' AND is_deleted = 0 AND duedate BETWEEN start_date AND end_date UNION ALL SELECT 'Partial Paid' AS `type`, FORMAT(COUNT(*), 0, 'en_IN') AS `total no OF cases`, FORMAT(SUM(principal), 2, 'en_IN') AS `due principal`, FORMAT(SUM(amountpayable), 2, 'en_IN') AS `total repayment amount`, FORMAT(SUM(paymentreceived), 2, 'en_IN') AS `total collected amount`, FORMAT(SUM( CASE WHEN status = 'due' THEN amountpayable WHEN status = 'partially-paid' THEN (amountpayable - paymentreceived) ELSE 0 END), 2, 'en_IN') AS `total pending amount`, FORMAT(SUM(waive_off_amount), 2, 'en_IN') AS `waive OFF amount`, CONCAT(ROUND((COUNT(*) / total_emi_cases) * 100, 2), '%') AS `percentage` FROM equated_monthly_installments WHERE status = 'partially-paid' AND is_deleted = 0 AND duedate BETWEEN start_date AND end_date UNION ALL SELECT 'Not Paid' AS `type`, FORMAT(COUNT(*), 0, 'en_IN') AS `total no OF cases`, FORMAT(SUM(principal), 2, 'en_IN') AS `due principal`, FORMAT(SUM(amountpayable), 2, 'en_IN') AS `total repayment amount`, FORMAT(SUM(paymentreceived), 2, 'en_IN') AS `total collected amount`, FORMAT(SUM( CASE WHEN status = 'due' THEN amountpayable WHEN status = 'partially-paid' THEN (amountpayable - paymentreceived) ELSE 0 END), 2, 'en_IN') AS `total pending amount`, FORMAT(SUM(waive_off_amount), 2, 'en_IN') AS `waive OFF amount`, CONCAT(ROUND((COUNT(*) / total_emi_cases) * 100, 2), '%') AS `percentage` FROM equated_monthly_installments WHERE status = 'due' AND is_deleted = 0 AND duedate BETWEEN start_date AND end_date UNION ALL SELECT 'Principal Paid' AS `type`, FORMAT(COUNT(*), 0, 'en_IN') AS `total no OF cases`, FORMAT(SUM(principal), 2, 'en_IN') AS `due principal`, FORMAT(SUM(principal), 2, 'en_IN') AS `total repayment amount`, FORMAT(SUM(principal - amountremains), 2, 'en_IN') AS `total collected amount`, FORMAT(SUM(amountremains), 2, 'en_IN') AS `total pending amount`, '0' AS `waive OFF amount`, CONCAT(ROUND((COUNT(*) / total_emi_cases) * 100, 2), '%') AS `percentage` FROM equated_monthly_installments WHERE (status = 'Paid' OR status = 'partially-paid') AND principal <> amountremains AND is_deleted = 0 AND duedate BETWEEN start_date AND end_date; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `emi_loan_collection_detail`(IN start_date DATE, IN end_date DATE) BEGIN
SELECT ln.loanNo AS Loan_No, a.branch AS Branch, c.name AS Name, c.mobile AS Mobile, cf.followType AS Contact_Type, cf.StatusType AS `Status`, cf.statusTypeDate AS PTP_Date, cf.remark AS Remark, a.loanAmtApproved AS Loan_Amount, cr.tenure AS Tenure, ROUND(cr.roi / 12, 2) AS ROI, ROUND( CASE WHEN emi.status = 'due' AND emi.dueDate < CURRENT_DATE THEN emi.principal + emi.interest + emi.principal * (((cr.roi / 12) / 100) + 0.1) * DATEDIFF(CURRENT_DATE, emi.dueDate) + 590 WHEN emi.status = 'part-payment' AND emi.actualPaymentDate > emi.dueDate THEN emi.principal + emi.interest + emi.panelty + emi.amountRemains * (((cr.roi / 12) / 100) + 0.1) * DATEDIFF(CURRENT_DATE, emi.actualPaymentDate) + 590 - emi.amountPayable WHEN emi.status = 'part-payment' AND emi.actualPaymentDate < emi.dueDate AND emi.dueDate < CURRENT_DATE THEN emi.principal + emi.interest + emi.amountRemains * (((cr.roi / 12) / 100) + 0.1) * DATEDIFF(CURRENT_DATE, emi.dueDate) + 590 - emi.amountPayable ELSE emi.amountPayable END, 2 ) AS Repay_Amount, emi.dueDate AS Repay_Date,
(SELECT SUM(ei.paymentReceived) FROM equated_monthly_installments AS ei WHERE ei.leadID = emi.leadID AND ei.is_deleted = 0 ) AS Total_Collection,
CASE WHEN emi.status = 'due' AND emi.dueDate < CURRENT_DATE THEN 'Over due' WHEN emi.status = 'part-payment' AND emi.actualPaymentDate > emi.dueDate THEN 'Over due' WHEN emi.status = 'part-payment' AND emi.actualPaymentDate < emi.dueDate AND emi.dueDate < CURRENT_DATE THEN 'Over due' ELSE emi.status END AS `Status`,
(SELECT uu.name FROM callhistoryLogs ca INNER JOIN users uu ON ca.calledBy = uu.userID WHERE ca.customerID = c.customerID AND ca.leadID = l.leadID AND ca.callType = "IVR" AND ca.status = "Approved Process" ORDER BY ca.callHistoryID ASC LIMIT 1 ) AS Credit_By, emi.actualPaymentDate AS Close_Date, emi.createdAt AS `Date`, c.pancard AS PAN_NO, addr.address AS Address, l.fbLeads AS Loan_type,
(SELECT COUNT(*) FROM leads WHERE customerID = c.customerID AND status IN ('Closed', 'Settlement', 'Part Payment', 'Disbursed') ) AS Loan_freq, c.employeeType AS Employee_type, l.monthlyIncome AS Monthly_Income, DATE_FORMAT(l.createdDate, '%Y-%m') AS Dis_Month FROM equated_monthly_installments AS emi LEFT JOIN leads l ON l.leadID = emi.leadID LEFT JOIN loan ln ON ln.leadID = l.leadID LEFT JOIN approval a ON a.leadID = l.leadID LEFT JOIN credits cr ON cr.leadID = l.leadID LEFT JOIN customer c ON c.customerID = l.customerID LEFT JOIN address addr ON addr.customerID = l.customerID
LEFT JOIN ( SELECT customerID, leadID, followType, StatusType, statusTypeDate, remark FROM collectionFollowup WHERE reviewID IN ( SELECT MAX(reviewID) FROM collectionFollowup GROUP BY customerID, leadID ) ) AS cf ON cf.customerID = l.customerID AND cf.leadID = l.leadID WHERE emi.is_deleted = 0 AND emi.dueDate BETWEEN start_date AND end_date group by l.leadID; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `event_data`( IN start_date DATE, IN end_date DATE) BEGIN Select * from user_flow_data where event_date between start_date and DATE_FORMAT(end_date,'%Y-%m-%d 23:59:59'); END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `event_funnel_report`( IN start_date DATE, IN end_date DATE, IN inputUtmSource VARCHAR(100), IN inputplatformVersion VARCHAR(10)) BEGIN WITH pan_users AS ( SELECT e.customerId, DATE(dddd) AS funnel_date FROM eventLogs e Join (SELECT customerId, MIN(id) AS first_id, MIN(eventDate) dddd FROM eventLogs WHERE eventName = 'OTP_Verified' AND userType = 'New Case' GROUP BY customerId ) f on e.id = f.first_id WHERE dddd between start_date and concat(end_date,' 23:59:59') and ( inputUtmSource = '' OR inputUtmSource IS NULL OR utmSource= inputUtmSource OR utmSource in ( select utm_source from user_utm_link where user_id = (select u.userID from users u where u.utmSource= inputUtmSource)) ) AND ( inputplatformVersion = '' OR inputplatformVersion IS NULL OR platformVersion = inputplatformVersion ) ) SELECT p.funnel_date AS funnel_date, 'Matured' AS type, COUNT(DISTINCT p.customerId) AS otp_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified' THEN u.customerId END) AS otp_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified_Repeat' THEN u.customerId END) AS otp_verified_repeat_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Pan_Verification_Succesful' THEN u.customerId END) AS pan_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' THEN u.customerId END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' and l.productID=1 THEN u.customerId END) AS emi_emandate_count, COUNT(DISTINCT CASE WHEN (u.eventName = 'BRE_Run_Initiated' or u.eventName= 'PTB_BRE_Run_Initiated') THEN u.customerId END) AS bre_run_initiated_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Approved' THEN u.customerId END) AS approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Approved' THEN u.customerId END) AS ptb_approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Rejected' THEN u.customerId END) AS ptb_rejected_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Selfie_Verified' THEN u.customerId END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KYC_Success' THEN u.customerId END) AS kyc_completed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' THEN u.customerId END) AS kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' and l.productID=1 THEN u.customerId END) AS emi_kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' THEN u.customerId END) AS disbursed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' and l.productID=1 THEN u.customerId END) AS emi_disbursed_count, COUNT(DISTINCT CASE WHEN l.fbLeads = 'Existing Case' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS existing_count FROM pan_users p LEFT JOIN eventLogs u ON u.customerId = p.customerId LEFT JOIN leads l ON l.leadID = u.leadId Where userType='New Case'
GROUP BY p.funnel_date UNION ALL SELECT p.funnel_date AS funnel_date, 'Sameday' AS type, COUNT(DISTINCT p.customerId) AS otp_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS otp_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified_Repeat' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS otp_verified_repeat_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Pan_Verification_Succesful' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS pan_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' AND DATE(u.eventDate) = p.funnel_date AND l.productID=1 THEN u.customerId END) AS emi_emandate_count, COUNT(DISTINCT CASE WHEN (u.eventName = 'BRE_Run_Initiated' or u.eventName= 'PTB_BRE_Run_Initiated') AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS bre_run_initiated_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Approved' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Approved' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS ptb_approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Rejected' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS ptb_rejected_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Selfie_Verified' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KYC_Success' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS kyc_completed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' AND DATE(u.eventDate) = p.funnel_date AND l.productID=1 THEN u.customerId END) AS emi_kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS disbursed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' AND DATE(u.eventDate) = p.funnel_date AND l.productID=1 THEN u.customerId END) AS emi_disbursed_count, COUNT(DISTINCT CASE WHEN l.fbLeads = 'Existing Case' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS existing_count FROM pan_users p LEFT JOIN eventLogs u ON u.customerId = p.customerId LEFT JOIN leads l ON l.leadID = u.leadId Where userType='New Case' GROUP BY p.funnel_date ORDER BY funnel_date, type DESC;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `event_funnel_report_generate`( IN start_date DATE, IN end_date DATE) BEGIN Select * from ( WITH pan_users AS ( SELECT customerId, DATE(MIN(eventDate)) AS funnel_date FROM eventLogs WHERE eventName = 'OTP_Verified' AND userType='New Case' AND eventDate between start_date and concat(end_date,' 23:59:59') group by customerId ) SELECT p.funnel_date AS funnel_date, 'V0' AS type, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified' THEN u.customerId END) AS otp_verified, COUNT(DISTINCT CASE WHEN u.eventName = 'Enter_Pan' THEN u.customerId END) AS pan_enter, COUNT(DISTINCT CASE WHEN u.eventName = 'Pan_Verification_Succesful' THEN u.customerId END) AS pan_verified, COUNT(DISTINCT CASE WHEN (u.eventName = 'BRE_Run_Initiated' or u.eventName = 'PTB_BRE_Run_Initiated' ) THEN u.customerId END) AS bre_run, COUNT(DISTINCT CASE WHEN u.eventName = 'Approved' THEN u.customerId END) AS approved, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' THEN u.customerId END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' and l.productID=1 THEN u.customerId END) AS emi_emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Selfie_Verified' THEN u.customerId END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KYC_Success' THEN u.customerId END) AS kyc_completed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' THEN u.customerId END) AS kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' and l.productID=1 THEN u.customerId END) AS emi_kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' THEN u.customerId END) AS disbursed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' and l.productID=1 THEN u.customerId END) AS emi_disbursed_count FROM pan_users p LEFT JOIN eventLogs u ON u.customerId = p.customerId LEFT JOIN leads l ON l.leadID = u.leadId Where userType='New Case' AND u.platformVersion = 'V0' GROUP BY p.funnel_date UNION ALL SELECT p.funnel_date AS funnel_date, 'V1' AS type, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified' THEN u.customerId END) AS otp_verified, COUNT(DISTINCT CASE WHEN u.eventName = 'pan_details_fetched_from_surepass' THEN u.customerId END) AS pan_enter, COUNT(DISTINCT CASE WHEN u.eventName = 'Pan_Verification_Succesful' THEN u.customerId END) AS pan_verified, COUNT(DISTINCT CASE WHEN (u.eventName = 'BRE_Run_Initiated' or u.eventName = 'PTB_BRE_Run_Initiated' ) THEN u.customerId END) AS bre_run, COUNT(DISTINCT CASE WHEN u.eventName = 'Approved' THEN u.customerId END) AS approved, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' THEN u.customerId END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' and l.productID=1 THEN u.customerId END) AS emi_emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Selfie_Verified' THEN u.customerId END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KYC_Success' THEN u.customerId END) AS kyc_completed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' THEN u.customerId END) AS kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' and l.productID=1 THEN u.customerId END) AS emi_kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' THEN u.customerId END) AS disbursed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' and l.productID=1 THEN u.customerId END) AS emi_disbursed_count FROM pan_users p LEFT JOIN eventLogs u ON u.customerId = p.customerId LEFT JOIN leads l ON l.leadID = u.leadId Where u.platformVersion = 'V1' GROUP BY p.funnel_date ) t order by funnel_date asc;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `event_funnel_reports`( IN start_date DATE, IN end_date DATE, IN inputUtmSource VARCHAR(100), IN inputplatformVersion VARCHAR(10)) BEGIN WITH pan_users AS ( SELECT e.customerId, DATE(dddd) AS funnel_date FROM eventLogs e Join (SELECT customerId, MIN(id) AS first_id, MIN(eventDate) dddd FROM eventLogs WHERE eventName = 'OTP_Verified' AND userType = 'New Case' GROUP BY customerId ) f on e.id = f.first_id WHERE dddd between start_date and concat(end_date,' 23:59:59') AND inputUtmSource != 'iota' AND inputUtmSource != 'iota?utm_source=iota' and ( inputUtmSource = '' OR inputUtmSource IS NULL OR utmSource= inputUtmSource OR utmSource in ( select utm_source from user_utm_link where user_id = (select u.userID from users u where u.utmSource= inputUtmSource)) ) AND ( inputplatformVersion = '' OR inputplatformVersion IS NULL OR platformVersion = inputplatformVersion ) ) SELECT p.funnel_date AS funnel_date, 'Matured' AS type, COUNT(DISTINCT p.customerId) AS otp_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified' THEN u.customerId END) AS otp_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified_Repeat' THEN u.customerId END) AS otp_verified_repeat_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Pan_Verification_Succesful' THEN u.customerId END) AS pan_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' THEN u.customerId END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' and l.productID=1 THEN u.customerId END) AS emi_emandate_count, COUNT(DISTINCT CASE WHEN (u.eventName = 'BRE_Run_Initiated' or u.eventName= 'PTB_BRE_Run_Initiated') THEN u.customerId END) AS bre_run_initiated_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Approved' THEN u.customerId END) AS approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Approved' THEN u.customerId END) AS ptb_approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Rejected' THEN u.customerId END) AS ptb_rejected_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Selfie_Verified' THEN u.customerId END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KYC_Success' THEN u.customerId END) AS kyc_completed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' THEN u.customerId END) AS kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' and l.productID=1 THEN u.customerId END) AS emi_kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' THEN u.customerId END) AS disbursed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' and l.productID=1 THEN u.customerId END) AS emi_disbursed_count, COUNT(DISTINCT CASE WHEN l.fbLeads = 'Existing Case' THEN u.customerId END) AS existing_count FROM pan_users p LEFT JOIN eventLogs u ON u.customerId = p.customerId LEFT JOIN leads l ON l.leadID = u.leadId Where userType='New Case' and l.fbLeads = 'New Case' AND ( inputUtmSource = '' OR inputUtmSource IS NULL OR u.utmSource= inputUtmSource OR u.utmSource in ( select utm_source from user_utm_link where user_id = (select a.userID from users a where a.utmSource= inputUtmSource)) )
GROUP BY p.funnel_date UNION ALL SELECT p.funnel_date AS funnel_date, 'Sameday' AS type, COUNT(DISTINCT p.customerId) AS otp_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS otp_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'OTP_Verified_Repeat' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS otp_verified_repeat_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Pan_Verification_Succesful' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS pan_verified_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Emandate_Success' AND DATE(u.eventDate) = p.funnel_date AND l.productID=1 THEN u.customerId END) AS emi_emandate_count, COUNT(DISTINCT CASE WHEN (u.eventName = 'BRE_Run_Initiated' or u.eventName= 'PTB_BRE_Run_Initiated') AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS bre_run_initiated_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Approved' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Approved' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS ptb_approved_count, COUNT(DISTINCT CASE WHEN u.eventName = 'PTB_Rejected' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS ptb_rejected_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Selfie_Verified' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KYC_Success' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS kyc_completed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'KFS_Done' AND DATE(u.eventDate) = p.funnel_date AND l.productID=1 THEN u.customerId END) AS emi_kfsdone_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS disbursed_count, COUNT(DISTINCT CASE WHEN u.eventName = 'Disbursed' AND DATE(u.eventDate) = p.funnel_date AND l.productID=1 THEN u.customerId END) AS emi_disbursed_count, COUNT(DISTINCT CASE WHEN l.fbLeads = 'Existing Case' AND DATE(u.eventDate) = p.funnel_date THEN u.customerId END) AS existing_count FROM pan_users p LEFT JOIN eventLogs u ON u.customerId = p.customerId LEFT JOIN leads l ON l.leadID = u.leadId Where userType='New Case' and l.fbLeads = 'New Case' AND ( inputUtmSource = '' OR inputUtmSource IS NULL OR u.utmSource= inputUtmSource OR u.utmSource in ( select utm_source from user_utm_link where user_id = (select a.userID from users a where a.utmSource= inputUtmSource)) ) GROUP BY p.funnel_date ORDER BY funnel_date, type DESC;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `fy_monthly_summary`(IN from_date DATE, IN to_date DATE) BEGIN -- Unused Parameters: from_date and to_date are declared but not used in the logic (as requested) -- in quick report these are manadary DECLARE start_date DATE; DECLARE end_date DATE; DECLARE cur_date DATE; DECLARE prev_date DATE; DECLARE tbl_name VARCHAR(64); DECLARE prev_tbl_name VARCHAR(64); DECLARE sql_text LONGTEXT;
IF MONTH(CURDATE()) >= 4 THEN SET start_date = MAKEDATE(YEAR(CURDATE()), 91); ELSE SET start_date = MAKEDATE(YEAR(CURDATE()) - 1, 91); END IF;
SET end_date = LAST_DAY(DATE_SUB(CURDATE(), INTERVAL 1 MONTH));
SET cur_date = start_date; SET sql_text = '';
WHILE cur_date <= end_date DO SET prev_date = DATE_SUB(cur_date, INTERVAL 1 MONTH); SET tbl_name = CONCAT('loanbook', DATE_FORMAT(LAST_DAY(cur_date), '%Y%m%d')); SET prev_tbl_name = CONCAT('loanbook', DATE_FORMAT(LAST_DAY(prev_date), '%Y%m%d'));
SET sql_text = CONCAT( sql_text, 'SELECT "', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" AS MonthYear, ', 'LAST_DAY("', cur_date, '") AS MonthEndDate, ',
'SUM(CASE WHEN `Disbursal Month Year`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Disbursal Amount` ELSE 0 END) AS DisbursalAmount, ',
'SUM(CASE WHEN `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Collected Amount` ELSE 0 END) AS CollectedAmount, ',
'SUM(CASE WHEN (WriteOffFlag="No" OR WriteOffDate="', DATE_FORMAT(LAST_DAY(cur_date), '%M-%Y'), '") AND `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Principal Collected_ipc` ELSE 0 END) AS CollectedPrincipalAmount, ',
'SUM(CASE WHEN WriteOffFlag="YES" AND WriteOffDate<>"March-2024" AND `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Principal Collected_ipc` ELSE 0 END) AS CollectedPrincipal_writeoff, ',
'SUM(CASE WHEN `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Interest Collected_ipc` ELSE 0 END) AS InterestIncome, ',
'SUM(CASE WHEN `Disbursal Month Year`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN PF ELSE 0 END) AS PFINCOME, ',
'SUM(CASE WHEN `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Late Fee Collected_ipc` ELSE 0 END) AS LateFee, ',
'SUM(CASE WHEN WriteOffFlag="YES" AND WriteOffDate="', DATE_FORMAT(LAST_DAY(cur_date), '%M-%Y'), '" THEN Loan_POS ELSE 0 END) AS WriteOffAmount, ',
'SUM(CASE WHEN WriteOffPaymentFlag="YES" AND `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Principal Collected_ipc` ELSE 0 END) AS WriteoffPrincipalCollection, ',
'SUM(CASE WHEN WriteOffPaymentFlag="YES" AND `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN `Collected Amount` ELSE 0 END) AS WriteoffTotalCollection, ',
'SUM(CASE WHEN `Collected Month`="', DATE_FORMAT(LAST_DAY(cur_date), '%M %Y'), '" THEN principal_waive_off ELSE 0 END) AS Waiver, ',
'SUM(principal_waive_off) AS com_Waiver, ',
'(SELECT SUM(principal_waive_off) FROM ', tbl_name, ' WHERE (WriteOffFlag="No" OR WriteOffDate="', DATE_FORMAT(LAST_DAY(cur_date), '%M-%Y'), '") AND loanId NOT IN (SELECT loanId FROM ', prev_tbl_name, ' WHERE principal_waive_off>0)) AS WriteoffWaiver, ',
'SUM(CASE WHEN WriteOffDate="" THEN Loan_POS ELSE 0 END) AS AUM ',
'FROM ', tbl_name, ' ',
'UNION ALL ' );
SET cur_date = DATE_ADD(cur_date, INTERVAL 1 MONTH); END WHILE;
SET sql_text = LEFT(sql_text, LENGTH(sql_text) - 10);
SET @final_query = sql_text; PREPARE stmt FROM @final_query; EXECUTE stmt; DEALLOCATE PREPARE stmt; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_approval_process_counts_data`( IN startDate DATE, IN endDate DATE ) BEGIN WITH LatestApprovedProcess AS ( SELECT DISTINCT(chl.leadID), DATE(chl.callbackTime) as processDate, MAX(chl.callbackTime) as latestTime FROM ramfin.callhistoryLogs as chl JOIN leads as l ON l.leadID = chl.leadID WHERE chl.status = 'Approved Process' AND l.fbLeads = 'New Case' GROUP BY chl.leadID, DATE(chl.callbackTime) ), DailyApprovedProcessCount AS ( SELECT lap.processDate, COUNT(*) as approvedProcessCount FROM LatestApprovedProcess lap GROUP BY lap.processDate ), ApprovalCounts AS ( SELECT lap.processDate, DATEDIFF(DATE(cl.disbursalDate), lap.processDate) as daysAfterProcess, COUNT(DISTINCT cl.leadID) as approvedCount FROM LatestApprovedProcess lap JOIN ramfin.loan cl ON lap.leadID = cl.leadID AND cl.status = 'Disbursed' AND DATE(cl.disbursalDate) >= lap.processDate GROUP BY lap.processDate, DATEDIFF(DATE(cl.disbursalDate), lap.processDate) ) SELECT d.processDate as Day, d.approvedProcessCount as ApprovedProcess, COALESCE(ac0.approvedCount, 0) as Day_0, COALESCE(ac1.approvedCount, 0) as Day_1, COALESCE(ac2.approvedCount, 0) as Day_2, COALESCE(ac3.approvedCount, 0) as Day_3, COALESCE(ac4.approvedCount, 0) as Day_4, COALESCE(ac5.approvedCount, 0) as Day_5, COALESCE(ac6.approvedCount, 0) as Day_6, COALESCE(ac7.approvedCount, 0) as Day_7, COALESCE(ac8.approvedCount, 0) as Day_8, COALESCE(ac9.approvedCount, 0) as Day_9, COALESCE(ac10.approvedCount, 0) as Day_10, COALESCE(ac11.approvedCount, 0) as Day_11, COALESCE(ac12.approvedCount, 0) as Day_12, COALESCE(ac13.approvedCount, 0) as Day_13, COALESCE(ac14.approvedCount, 0) as Day_14, COALESCE(ac15.approvedCount, 0) as Day_15, COALESCE(ac16.approvedCount, 0) as Day_16, COALESCE(ac17.approvedCount, 0) as Day_17, COALESCE(ac18.approvedCount, 0) as Day_18, COALESCE(ac19.approvedCount, 0) as Day_19, COALESCE(ac20.approvedCount, 0) as Day_20, COALESCE(ac21.approvedCount, 0) as Day_21, COALESCE(ac22.approvedCount, 0) as Day_22, COALESCE(ac23.approvedCount, 0) as Day_23, COALESCE(ac24.approvedCount, 0) as Day_24, COALESCE(ac25.approvedCount, 0) as Day_25, COALESCE(ac26.approvedCount, 0) as Day_26, COALESCE(ac27.approvedCount, 0) as Day_27, COALESCE(ac28.approvedCount, 0) as Day_28, COALESCE(ac29.approvedCount, 0) as Day_29, COALESCE(ac30.approvedCount, 0) as Day_30 FROM DailyApprovedProcessCount d LEFT JOIN ApprovalCounts ac0 ON d.processDate = ac0.processDate AND ac0.daysAfterProcess = 0 LEFT JOIN ApprovalCounts ac1 ON d.processDate = ac1.processDate AND ac1.daysAfterProcess = 1 LEFT JOIN ApprovalCounts ac2 ON d.processDate = ac2.processDate AND ac2.daysAfterProcess = 2 LEFT JOIN ApprovalCounts ac3 ON d.processDate = ac3.processDate AND ac3.daysAfterProcess = 3 LEFT JOIN ApprovalCounts ac4 ON d.processDate = ac4.processDate AND ac4.daysAfterProcess = 4 LEFT JOIN ApprovalCounts ac5 ON d.processDate = ac5.processDate AND ac5.daysAfterProcess = 5 LEFT JOIN ApprovalCounts ac6 ON d.processDate = ac6.processDate AND ac6.daysAfterProcess = 6 LEFT JOIN ApprovalCounts ac7 ON d.processDate = ac7.processDate AND ac7.daysAfterProcess = 7 LEFT JOIN ApprovalCounts ac8 ON d.processDate = ac8.processDate AND ac8.daysAfterProcess = 8 LEFT JOIN ApprovalCounts ac9 ON d.processDate = ac9.processDate AND ac9.daysAfterProcess = 9 LEFT JOIN ApprovalCounts ac10 ON d.processDate = ac10.processDate AND ac10.daysAfterProcess = 10 LEFT JOIN ApprovalCounts ac11 ON d.processDate = ac11.processDate AND ac11.daysAfterProcess = 11 LEFT JOIN ApprovalCounts ac12 ON d.processDate = ac12.processDate AND ac12.daysAfterProcess = 12 LEFT JOIN ApprovalCounts ac13 ON d.processDate = ac13.processDate AND ac13.daysAfterProcess = 13 LEFT JOIN ApprovalCounts ac14 ON d.processDate = ac14.processDate AND ac14.daysAfterProcess = 14 LEFT JOIN ApprovalCounts ac15 ON d.processDate = ac15.processDate AND ac15.daysAfterProcess = 15 LEFT JOIN ApprovalCounts ac16 ON d.processDate = ac16.processDate AND ac16.daysAfterProcess = 16 LEFT JOIN ApprovalCounts ac17 ON d.processDate = ac17.processDate AND ac17.daysAfterProcess = 17 LEFT JOIN ApprovalCounts ac18 ON d.processDate = ac18.processDate AND ac18.daysAfterProcess = 18 LEFT JOIN ApprovalCounts ac19 ON d.processDate = ac19.processDate AND ac19.daysAfterProcess = 19 LEFT JOIN ApprovalCounts ac20 ON d.processDate = ac20.processDate AND ac20.daysAfterProcess = 20 LEFT JOIN ApprovalCounts ac21 ON d.processDate = ac21.processDate AND ac21.daysAfterProcess = 21 LEFT JOIN ApprovalCounts ac22 ON d.processDate = ac22.processDate AND ac22.daysAfterProcess = 22 LEFT JOIN ApprovalCounts ac23 ON d.processDate = ac23.processDate AND ac23.daysAfterProcess = 23 LEFT JOIN ApprovalCounts ac24 ON d.processDate = ac24.processDate AND ac24.daysAfterProcess = 24 LEFT JOIN ApprovalCounts ac25 ON d.processDate = ac25.processDate AND ac25.daysAfterProcess = 25 LEFT JOIN ApprovalCounts ac26 ON d.processDate = ac26.processDate AND ac26.daysAfterProcess = 26 LEFT JOIN ApprovalCounts ac27 ON d.processDate = ac27.processDate AND ac27.daysAfterProcess = 27 LEFT JOIN ApprovalCounts ac28 ON d.processDate = ac28.processDate AND ac28.daysAfterProcess = 28 LEFT JOIN ApprovalCounts ac29 ON d.processDate = ac29.processDate AND ac29.daysAfterProcess = 29 LEFT JOIN ApprovalCounts ac30 ON d.processDate = ac30.processDate AND ac30.daysAfterProcess = 30 WHERE d.processDate BETWEEN startDate AND endDate ORDER BY d.processDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_collection_data`( IN param1 varchar(20), IN param2 varchar(20), IN param3 varchar(20), IN param4 varchar(20), IN param5 varchar(20), IN param6 varchar(20) ) BEGIN
SET sql_mode = (SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
SELECT l.*, (SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate ) AS totalCollectedAmount, coll.settlemenAmount, coll.discountAmount, (CASE WHEN ll.ipc=1 then (ifnull(collected_interest,0)+ifnull(collected_penality,0)) ELSE (CASE WHEN l.disbursalAmount>(SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate) THEN 0 ELSE ((SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate) - l.disbursalAmount) END) END) as monthlyIncome, ll.fbLeads, c.name, c.aadharNo, c.pancard, c.dob, a.adminFee, a.roi, a.branch, a.loanAmtApproved, a.tenure, a.repayDate, coll.collectedAmount, coll.collectedDate, coll.referenceNo, coll.collectedMode, coll.status, coll.remark, (SELECT uu.name FROM callhistoryLogs ca INNER JOIN users uu ON ca.calledBy=uu.userID WHERE ca.customerID=c.customerID AND ca.leadID=l.leadID AND ca.callType='IVR' AND ca.status='Approved Process' ORDER BY ca.callHistoryID DESC LIMIT 1 ) AS calledby FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID INNER JOIN collection coll ON coll.loanNo = l.loanNo WHERE (coll.collectionStatus = 'Approved' OR coll.collectionStatus = 'Approved-refunded') AND (param1 IS NULL AND param2 IS NULL OR coll.collectedDate BETWEEN param1 AND param2) AND (param3 IS NULL OR coll.loanNo = param3) AND (param4 IS NULL OR l.leadID = param4) AND (param5 IS NULL OR c.customerID = param5) AND (param6 IS NULL OR c.mobile = param6) ORDER BY coll.collectedDate DESC; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_collection_data_report_dashboard`( IN startDate varchar(20), IN endDate varchar(20) ) BEGIN SET sql_mode = (SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
SELECT l.leadID, l.loanNo, (SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate ) AS totalCollectedAmount, coll.settlemenAmount, coll.discountAmount, (CASE WHEN ll.ipc=1 THEN (IFNULL(collected_interest,0)+IFNULL(collected_penality,0)) ELSE (CASE WHEN l.disbursalAmount > (SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved'
AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate) THEN 0 ELSE ((SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved'
AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate) - l.disbursalAmount) END) END) as monthlyIncome, ll.fbLeads, a.roi, a.loanAmtApproved, a.tenure, a.repayDate, coll.collectedAmount, coll.collectedDate, coll.referenceNo, coll.collected_interest, coll.collected_principal, coll.collected_penality,
CASE WHEN op.method = 'emandate' THEN 'Yes' ELSE 'No' END AS emandate,
coll.collectedMode, coll.status, coll.remark, coll.refund_utr_no, coll.excess_amount, ln.name AS lender_name, (SELECT uu.name FROM callhistoryLogs ca INNER JOIN users uu ON ca.calledBy=uu.userID WHERE ca.customerID=c.customerID AND ca.leadID=l.leadID AND ca.callType='IVR' AND ca.status='Approved Process' ORDER BY ca.callHistoryID DESC LIMIT 1 ) AS calledby FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID INNER JOIN collection coll ON coll.loanNo = l.loanNo LEFT JOIN lender ln ON ll.lenderID = ln.lenderID
LEFT JOIN onlinepayment op ON op.pID = ( SELECT MAX(pID) FROM onlinepayment WHERE razorpayOrderId = coll.referenceNo ) AND op.razorpayOrderId = coll.referenceNo
WHERE (coll.collectionStatus = 'Approved' OR coll.collectionStatus = 'Approved-refunded') AND (coll.collectedDate BETWEEN startDate AND endDate) ORDER BY coll.collectedDate DESC; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_collection_data_report_dashboard_created_at`( IN startDate varchar(20), IN endDate varchar(20) ) BEGIN
SET sql_mode = (SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
SELECT l.leadID,l.loanNo, (SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate ) AS totalCollectedAmount, coll.settlemenAmount, coll.discountAmount, (CASE WHEN ll.ipc=1 then (ifnull(collected_interest,0)+ifnull(collected_penality,0)) ELSE (CASE WHEN l.disbursalAmount>(SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate) THEN 0 ELSE ((SELECT SUM(collectedAmount) FROM collection WHERE collectionStatus='Approved' AND IFNULL(collectedMode,'') <> 'Waive Off' AND loanNo = l.loanNo AND collectedDate <= coll.collectedDate) - l.disbursalAmount) END) END) as monthlyIncome, ll.fbLeads, a.roi, a.loanAmtApproved, a.tenure, a.repayDate, coll.collectedAmount, coll.collectedDate, coll.referenceNo, coll.collectedMode, coll.status, ln.name AS lender_name, coll.remark, coll.refund_utr_no, coll.excess_amount, (SELECT uu.name FROM callhistoryLogs ca INNER JOIN users uu ON ca.calledBy=uu.userID WHERE ca.customerID=c.customerID AND ca.leadID=l.leadID AND ca.callType='IVR' AND ca.status='Approved Process' ORDER BY ca.callHistoryID DESC LIMIT 1 ) AS calledby FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID INNER JOIN collection coll ON coll.loanNo = l.loanNo LEFT JOIN lender ln ON ll.lenderID = ln.lenderID WHERE (coll.collectionStatus = 'Approved' OR coll.collectionStatus = 'Approved-refunded') AND (coll.createdDate BETWEEN startDate AND concat(endDate,' 23:59:59') ) ORDER BY coll.createdDate DESC; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_collection_data_report_dashboard_optimized`( IN startDate VARCHAR(20), IN endDate VARCHAR(20) ) BEGIN
SET SESSION sql_mode = REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','');
WITH
base_collection AS ( SELECT * FROM collection WHERE collectionStatus IN ('Approved','Approved-refunded') AND collectedDate BETWEEN startDate AND endDate ),
collection_daily AS ( SELECT loanNo, collectedDate, SUM(collectedAmount) AS dailyAmount FROM collection WHERE collectionStatus = 'Approved' AND (collectedMode IS NULL OR collectedMode <> 'Waive Off') AND collectedDate <= endDate GROUP BY loanNo, collectedDate ),
collection_running AS ( SELECT loanNo, collectedDate, SUM(dailyAmount) OVER ( PARTITION BY loanNo ORDER BY collectedDate ) AS totalCollectedAmount FROM collection_daily ),
collection_daily_all AS ( SELECT loanNo, collectedDate, SUM(collectedAmount) AS dailyAmount FROM collection WHERE collectionStatus = 'Approved' AND collectedDate <= endDate GROUP BY loanNo, collectedDate ),
collection_running_all AS ( SELECT loanNo, collectedDate, SUM(dailyAmount) OVER ( PARTITION BY loanNo ORDER BY collectedDate ) AS totalCollectedAmountAll FROM collection_daily_all ),
latest_payment AS ( SELECT * FROM ( SELECT op.*, ROW_NUMBER() OVER ( PARTITION BY op.razorpayOrderId ORDER BY op.pID DESC ) rn FROM onlinepayment op ) t WHERE rn = 1 ),
latest_call AS ( SELECT * FROM ( SELECT ca.customerID, ca.leadID, uu.name, ROW_NUMBER() OVER ( PARTITION BY ca.customerID, ca.leadID ORDER BY ca.callHistoryID DESC ) rn FROM callhistoryLogs ca JOIN users uu ON ca.calledBy = uu.userID WHERE ca.callType = 'IVR' AND ca.status = 'Approved Process' ) t WHERE rn = 1 )
SELECT l.leadID, l.loanNo,
cr.totalCollectedAmount,
coll.settlemenAmount, coll.discountAmount,
CASE WHEN ll.ipc = 1 THEN IFNULL(coll.collected_interest,0) + IFNULL(coll.collected_penality,0) ELSE CASE WHEN l.disbursalAmount > IFNULL(cra.totalCollectedAmountAll,0) THEN 0 ELSE IFNULL(cra.totalCollectedAmountAll,0) - l.disbursalAmount END END AS monthlyIncome,
ll.fbLeads, a.roi, a.loanAmtApproved, a.tenure, a.repayDate,
coll.collectedAmount, coll.collectedDate, coll.referenceNo,
coll.collected_interest, coll.collected_principal, coll.collected_penality,
CASE WHEN lp.method = 'emandate' THEN 'Yes' ELSE 'No' END AS emandate,
coll.collectedMode, coll.status, coll.remark, coll.refund_utr_no, coll.excess_amount,
ln.name AS lender_name, lc.name AS calledby
FROM base_collection coll
JOIN loan l ON coll.loanNo = l.loanNo JOIN customer c ON l.customerID = c.customerID JOIN approval a ON l.leadID = a.leadID JOIN leads ll ON ll.leadID = a.leadID
LEFT JOIN lender ln ON ll.lenderID = ln.lenderID
LEFT JOIN collection_running cr ON cr.loanNo = coll.loanNo AND cr.collectedDate = coll.collectedDate
LEFT JOIN collection_running_all cra ON cra.loanNo = coll.loanNo AND cra.collectedDate = coll.collectedDate
LEFT JOIN latest_payment lp ON lp.razorpayOrderId = coll.referenceNo
LEFT JOIN latest_call lc ON lc.customerID = c.customerID AND lc.leadID = l.leadID
ORDER BY coll.collectedDate DESC;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_disbursal_data`( IN param1 VARCHAR(20), IN param2 VARCHAR(20), IN param3 VARCHAR(20), IN param4 VARCHAR(20), IN param5 VARCHAR(20), IN param6 VARCHAR(20) ) BEGIN SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', ''));
SELECT l.*, c.gender, c.email, c.mobile, (CASE WHEN ll.productID=1 THEN 'EMI' ELSE 'PAYDAY' END) AS loan_type, l.disbursalDate, (SELECT COUNT(*) FROM leads WHERE customerID = l.customerID AND (status = 'Closed' OR status = 'Settlement' OR status = 'Disbursed')) AS frequency, l.utr, ll.monthlyIncome, ll.fbleads, c.name, c.aadharNo, c.pancard, c.dob, c.employeeType, a.adminFee, a.GstOfAdminFee, a.roi, a.branch, a.loanAmtApproved, a.tenure, a.repayDate, SUM(collectedAmount) AS total_amount, MAX(collectedDate) AS collectedDate, coll.status AS collectedStatus, (SELECT uu.name FROM callhistoryLogs ca INNER JOIN users uu ON ca.calledBy = uu.userID WHERE ca.customerID = c.customerID AND ca.leadID = l.leadID AND ca.callType = 'IVR' AND ca.status = 'Approved Process' ORDER BY ca.callHistoryID DESC LIMIT 1) AS credit_name FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID LEFT JOIN collection coll ON coll.loanNo = l.loanNo WHERE l.status = 'Disbursed' and l.payout_status=2 AND (param1 IS NULL OR param2 IS NULL OR l.disbursalDate BETWEEN param1 AND param2) AND (param3 IS NULL OR coll.loanNo = param3) AND (param4 IS NULL OR l.leadID = param4) AND (param5 IS NULL OR c.customerID = param5) AND (param6 IS NULL OR c.mobile = param6) GROUP BY l.leadID ORDER BY l.disbursalDate DESC;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_disbursal_data_account`( IN param1 VARCHAR(20), IN param2 VARCHAR(20) ) BEGIN SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', '')); SELECT l.leadID, l.loanNo, c.name, l.disbursalDate, l.disbursalAmount, l.disbursalRefrenceNo, l.disbursalTime, l.createdDate AS initiated_date, l.utr, l.deduction, a.adminFee, a.GstOfAdminFee, ( SELECT COUNT(*) FROM leads WHERE customerID = l.customerID AND (status = 'Closed' OR status = 'Settlement' OR status = 'Disbursed') ) AS frequency, ll.monthlyIncome, ll.fbleads, a.repayDate, CASE WHEN ll.productID = 1 THEN 'EMI' ELSE 'payday' END AS loan_type FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID WHERE l.status = 'Disbursed' AND l.payout_status = 2 AND l.disbursalDate BETWEEN param1 AND param2 GROUP BY l.leadID ORDER BY l.disbursalDate DESC;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_disbursal_data_account_ava`( IN param1 VARCHAR(20), IN param2 VARCHAR(20) ) BEGIN
SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', ''));
SELECT l.leadID, l.loanNo, c.name, l.disbursalDate, l.disbursalAmount, l.disbursalRefrenceNo, l.disbursalTime, l.createdDate AS initiated_date, l.utr, l.deduction, a.adminFee, a.GstOfAdminFee, ( SELECT COUNT(*) FROM leads WHERE customerID = l.customerID AND (status = 'Closed' OR status = 'Settlement' OR status = 'Disbursed') ) AS frequency, ll.monthlyIncome, ll.fbleads, a.repayDate, CASE WHEN ll.productID = 1 THEN 'EMI' ELSE 'payday' END AS loan_type FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID WHERE l.status = 'Disbursed' AND l.payout_status = 2 AND l.disbursalDate BETWEEN param1 AND param2 AND ll.lenderID = 2 GROUP BY l.leadID ORDER BY l.disbursalDate DESC; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_disbursal_data_quick_report`( IN param1 VARCHAR(20), IN param2 VARCHAR(20) ) BEGIN SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', ''));
SELECT l.*, c.gender, c.email, c.mobile, l.disbursalDate, (SELECT COUNT(*) FROM leads WHERE customerID = l.customerID AND (status = 'Closed' OR status = 'Settlement' OR status = 'Disbursed')) AS frequency, l.utr, ll.monthlyIncome, ll.fbleads, c.name, c.aadharNo, c.pancard, c.dob, c.employeeType, a.adminFee, a.roi, a.branch, l.disbursalAmount, (l.disbursalAmount-l.deduction) netDisbursalAmount, a.tenure, a.repayDate, SUM(collectedAmount) AS total_amount, MAX(collectedDate) AS collectedDate, coll.status AS collectedStatus
FROM loan AS l INNER JOIN customer c ON l.customerID = c.customerID INNER JOIN approval a ON l.leadID = a.leadID INNER JOIN leads ll ON ll.leadID = a.leadID LEFT JOIN collection coll ON coll.loanNo = l.loanNo WHERE l.status = 'Disbursed' and l.payout_status=2 and l.disbursalDate BETWEEN param1 AND param2 GROUP BY l.leadID ORDER BY l.disbursalDate DESC; END
CREATE DEFINER=`ramfincorp_user`@`%` PROCEDURE `get_journey_logs`( IN p_start_date DATETIME, IN p_end_date DATETIME ) BEGIN SELECT api_name, TIMESTAMP(DATE(createdDate), MAKETIME(HOUR(createdDate),0,0)) AS log_datetime, COUNT(*) AS total_logs, SUM(status='1') AS success_count, SUM(status='0') AS failure_count FROM journey_logs WHERE createdDate BETWEEN p_start_date AND p_end_date GROUP BY api_name, TIMESTAMP(DATE(createdDate), MAKETIME(HOUR(createdDate),0,0)) ORDER BY log_datetime DESC, api_name;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_lead_data`(IN from_date DATE, IN to_date DATE) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
SELECT l.leadID, l.customerID, l.fbLeads, DATE_FORMAT(l.createdDate, '%Y-%m-%d') AS leads_createdDate, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Fresh Lead' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Fresh_Lead_Date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Approved' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Approved_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Approved Process' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Approved_Process_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Document Received' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Document_Received_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Disbursed' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Disbursed_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Rejected' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Rejected_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Rejected Process' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Rejected_Process_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Not Required' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Not_Required_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN ch.status = 'Not Required Process' THEN ch.createdDate END), '%Y-%m-%d'), '') AS Not_Required_Process_date, IFNULL(DATE_FORMAT(MAX(CASE WHEN (ch.status = 'Hold' or ch.status='Hold Process') THEN ch.createdDate END), '%Y-%m-%d'), '') AS Not_Required_Process_date,
IFNULL((CASE WHEN loan.status = 'Disbursed' THEN loan.status END), '') AS loan_status, IFNULL((CASE WHEN loan.status = 'Disbursed' THEN loan.disbursalAmount END), '') AS disbursalAmount, IFNULL((CASE WHEN loan.status = 'Disbursed' THEN loan.disbursalDate END), '') AS disbursalDate, pd.credated_date panny_drop_date, (case when em.status<>'paid' then '' else em.credated_date end) emandate_date, MAX(reff.createdDate) reference_date, (CASE WHEN ch.status = 'Approved Process' THEN (select name from users where userID=ch.calledBy) else '' END) AS credit_manage
FROM leads l JOIN callhistoryLogs ch ON l.leadID = ch.leadID LEFT JOIN `reference` reff on reff.customerID=l.customerID LEFT JOIN `razorpay_mandate` em on em.id=l.em_id LEFT JOIN `penny_drop` pd on pd.customerID=l.customerID LEFT JOIN loan ON l.leadID = loan.leadID WHERE l.createdDate BETWEEN from_date AND to_date GROUP BY l.leadID;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_loan_book_data`(IN AS_ON_DATE DATE) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); WITH CollectionDetails AS ( SELECT col.collectionID, col.leadID, col.loanNo, col.status, col.excess_amount, col.principal_amount AS principal_amount, col.collected_principal AS collected_principal, col.collected_interest AS collected_interest, col.collected_penality AS collected_penality, col.collectedDate AS collectedDate, col.referenceNo AS referenceNo, CONCAT(MONTHNAME(col.collectedDate), ' ', YEAR(col.collectedDate)) AS CollectedMonth, col.collectedAmount AS CollectedAmount, DATEDIFF(col.collectedDate, a.repayDate) AS PaymentDPDs, col.orderID AS OrderIDs, col.collectedMode, (CASE WHEN collectedMode='Waive Off' or collectedMode='DISCOUNT' THEN collectedAmount else 0 end) Waive_off_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN discount_waiver_amount ELSE 0 END) AS discount_waiver_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN collectedDate ELSE NULL END) AS WaiverDate, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' and collectedMode NOT IN ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) AS actual_collected_amount, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalCollectedAmount, (SELECT SUM(collected_principal) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalPrincipalAmount, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE ) AS MaxCollectedDate, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE AND (status='closed' OR status='Settlement')) AS MaxClosedOrSettlementDate, (SELECT status FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE order by collectionID desc limit 1) AS lead_status, collected_penality AS penalCharges FROM collection col JOIN approval a ON col.leadID = a.leadID WHERE col.collectionStatus = 'Approved' and col.collectedDate<= AS_ON_DATE and collectedMode NOT IN ('Waive Off','DISCOUNT') order by collectionID asc ), RefundDetails AS ( SELECT leadID, loanNo, collectedAmount AS `Refunded Amount`, collectedDate AS `Refund Date` FROM collection WHERE collectionStatus = 'Approved-refunded' and collectedMode NOT IN ('Waive Off','DISCOUNT') and collectedDate <= AS_ON_DATE ), CalculatedAmounts AS ( SELECT l.leadID, l.loanNo, l.disbursalAmount, col.collectionID, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS RepayAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount AS InterestAmount, COALESCE(col.TotalCollectedAmount, 0) AS TotalCollectedAmount, (CASE WHEN LEAST(l.disbursalAmount, COALESCE(col.TotalCollectedAmount, 0))=col.TotalCollectedAmount THEN col.collectedAmount ELSE (CASE WHEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount))>0 THEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount)) else 0 END) END) AS PrincipalCollected, (CASE WHEN LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount - COALESCE(col.collectedAmount,0), 0))=(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) Then 0 ELSE LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount, 0)) END) AS InterestCollected, (CASE WHEN GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - COALESCE(col.collectedAmount,0), 0)>0 THEN col.collectedAmount ELSE GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)),0) END) AS PenalInterest, GREATEST(l.disbursalAmount - COALESCE(col.TotalCollectedAmount, 0), 0) AS POS, IFNULL((SELECT principal_amount FROM collection WHERE col.leadID=leadID AND collectionStatus='Approved' AND collectedDate <=AS_ON_DATE ORDER BY collectionID DESC LIMIT 1), l.disbursalAmount) AS POSIPC,
CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE DATEDIFF(NOW(), l.disbursalDate) END AS ActualTenureDays, CASE WHEN (l.disbursalAmount > (col.actual_collected_amount)) and (col.status='Closed' or col.status='Settlement') THEN (l.disbursalAmount - (col.actual_collected_amount)) ELSE 0 END AS `principal_waive_off` FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE ), OverdueAmounts AS ( SELECT l.leadID, l.loanNo, l.disbursalAmount AS OverduePrincipal, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount AS OverdueInterest FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN leads le ON l.leadID = le.leadID WHERE le.status = 'part payment' ), DueAmounts AS ( SELECT l.leadID, l.disbursalAmount, l.loanNo, ROUND( ROUND( l.disbursalAmount + ( l.disbursalAmount * a.roi / 100 * a.tenure ) ) + ( l.disbursalAmount * 1.25 / 100 * DATEDIFF(AS_ON_DATE, a.repayDate) ) - ifnull(SUM(co.collectedAmount),0) ) AS DueAmount, ROUND( ( CASE WHEN SUM(co.collectedAmount)> 0 THEN ((select (ifnull(total_interest,0)+ifnull(penality_charge,0)) from collection where leadID=l.leadID order by collectionID desc limit 1) + min(co.principal_amount) + ( min(co.principal_amount) * ((a.roi+0.1) / 100) * DATEDIFF( AS_ON_DATE, max(co.collectedDate) ) ))ELSE ( l.disbursalAmount + ( l.disbursalAmount * a.roi / 100 * a.tenure )+590+( l.disbursalAmount * (a.roi + 0.1) / 100 * DATEDIFF(AS_ON_DATE, a.repayDate) ) ) END )) AS IPCDueAmount, DATEDIFF(NOW(), a.repayDate) AS CurrentTenure FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN ( Select * from collection where collectionStatus = 'Approved' and collectedDate <= AS_ON_DATE ) as co ON l.leadID = co.leadID LEFT JOIN leads le ON l.leadID = le.leadID WHERE a.repayDate <= AS_ON_DATE
GROUP BY l.leadID ), AgeCategorized AS ( SELECT c.customerID, TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) AS age, CASE WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 20 AND 29 THEN '20-29' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 30 AND 39 THEN '30-39' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 40 AND 49 THEN '40-49' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 50 AND 59 THEN '50-59' ELSE '60+' END AS AgeBracket FROM customer c ), TenureCategorized AS ( SELECT a.leadID, a.tenure, CASE WHEN a.tenure BETWEEN 1 AND 15 THEN '1-15 days' WHEN a.tenure BETWEEN 16 AND 30 THEN '16-30 days' ELSE '30+ days' END AS TenureBin FROM approval a ), CIBILScore AS ( select * from (Select customerID, score from cibil_score union all select customerID,score from credit_reports where score is not null) t group by t.customerID ), DisbursalAmountCategorized AS ( SELECT l.loanID, l.disbursalAmount, CASE WHEN l.disbursalAmount < 5000 THEN '<5000' WHEN l.disbursalAmount BETWEEN 5000 AND 9999 THEN '5000-10000' WHEN l.disbursalAmount BETWEEN 10000 AND 19999 THEN '10000-20000' WHEN l.disbursalAmount BETWEEN 20000 AND 29999 THEN '20000-30000' WHEN l.disbursalAmount BETWEEN 30000 AND 39999 THEN '30000-40000' WHEN l.disbursalAmount BETWEEN 40000 AND 49999 THEN '40000-80000' WHEN l.disbursalAmount BETWEEN 50000 AND 59999 THEN '50000-60000' WHEN l.disbursalAmount BETWEEN 60000 AND 69999 THEN '60000-70000' WHEN l.disbursalAmount BETWEEN 70000 AND 79999 THEN '70000-80000' WHEN l.disbursalAmount BETWEEN 80000 AND 89999 THEN '80000-90000' WHEN l.disbursalAmount BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN l.disbursalAmount BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '>150000' END AS DisbursalBracket FROM loan l ), IncomeRanking AS ( SELECT le.leadID, le.monthlyIncome, CASE WHEN le.monthlyIncome < 25000 THEN '<25000' WHEN le.monthlyIncome BETWEEN 25000 AND 29999 THEN '25000-30000' WHEN le.monthlyIncome BETWEEN 30000 AND 60000 THEN '30000-60000' WHEN le.monthlyIncome BETWEEN 60000 AND 89999 THEN '60000-90000' WHEN le.monthlyIncome BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN le.monthlyIncome BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '180000+' END AS IncomeBracket FROM leads le WHERE le.monthlyIncome IS NOT NULL ), ROICategorized AS ( SELECT a.leadID, a.roi, CASE WHEN a.roi < 0.8 THEN '<0.8' WHEN a.roi BETWEEN 0.8 AND 0.89 THEN '0.8-0.9' WHEN a.roi BETWEEN 0.9 AND 0.99 THEN '0.9-1' WHEN a.roi = 1.00 THEN '1' ELSE '>1' END AS ROIBracket FROM approval a ), Loan_POS_CTE AS ( SELECT l.loanNo, COALESCE( (SELECT (CASE WHEN le.ipc=1 then POSIPC ELSE POS END) FROM CalculatedAmounts ca WHERE ca.loanNo = l.loanNo ORDER BY ca.collectionID DESC LIMIT 1), 0) AS LastPOS FROM loan l inner join leads le on l.leadID=le.leadID WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE )
SELECT c.customerID AS UserID, l.loanNo AS LoanID, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE l.disbursalAmount END) AS 'Disbursal Amount', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE a.adminFee END) AS 'PF', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE a.GstOfAdminFee END) AS `GST amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (l.disbursalAmount - a.adminFee - a.GstOfAdminFee) END) AS `Net Disbursal Amount`, l.disbursalDate AS `Disbursal Date`, CONCAT(MONTHNAME(l.disbursalDate), ' ', YEAR(l.disbursalDate)) AS `Disbursal Month Year`, a.repayDate AS `Due Date`, CONCAT(MONTHNAME(a.repayDate), ' ', YEAR(a.repayDate)) AS `Due Date Month Year`, IFNULL(col.status,'Disbursed') AS paymentStatus, col.collectedMode AS Modeofpayment, (CASE when le.productID=1 THEN 'EMI' ELSE 'Payday' END) AS `ProductID or Name`, cs.score AS `CIBIL Score`, a.roi AS Interest_Rate, a.tenure AS Tenure, DATEDIFF(a.repayDate, l.disbursalDate) AS DISB_TENURE, CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE NULL END AS ACTUAL_TENURE, col.MaxCollectedDate AS `Date of Collection (Most Recent)`, col.CollectedDate AS `Collected Date`, col.CollectedMonth AS `Collected Month`, col.CollectedAmount AS `Collected Amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE COALESCE(ca.RepayAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) END) AS 'DD Repay Amount', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE COALESCE(ca.InterestAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) END) AS 'DD Interest Amount', COALESCE(col.TotalCollectedAmount, 0) AS `Total Collected Amount`, (CASE WHEN (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END)>l.disbursalAmount THEN l.disbursalAmount ELSE (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END) END ) AS 'Principal Collected_ipc', (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE (CASE WHEN ca.InterestCollected=0 Then 0 else ca.InterestCollected- ifnull((select InterestCollected from CalculatedAmounts cc where ca.leadID = cc.leadID AND cc.loanNo = ca.loanNo AND cc.collectionID < ca.collectionID order by cc.collectionID desc limit 1),0) END) END) AS 'Interest Collected_ipc', (CASE WHEN le.ipc=1 THEN col.collected_penality ELSE ca.PenalInterest END) AS 'Late Fee Collected_ipc', IFNULL(col.PaymentDPDs,0) AS `Payment DPDs`, CASE WHEN IFNULL(col.PaymentDPDs,0) <= 0 THEN '(<=0)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 1 AND 30 THEN '(1-30)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 31 AND 60 THEN '(31-60)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 61 AND 90 THEN '(61-90)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 91 AND 180 THEN '(91-180)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 181 AND 365 THEN '(181-365)' ELSE '(>365)' END AS `Payment DPD bins`, CASE WHEN DATEDIFF(AS_ON_DATE,a.repayDate) <= 0 THEN 'Standard Assets' WHEN IFNULL(MaxClosedOrSettlementDate,0)>0 THEN 'Closed Assets' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) <= 0 THEN '(<=0)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 1 AND 30 THEN '(1-30)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 31 AND 60 THEN '(31-60)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 61 AND 90 THEN '(61-90)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 91 AND 180 THEN '(91-180)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 181 AND 365 THEN '(181-365)' ELSE '(>365)' END AS `Loan DPD bins`, (CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END) AS `Overdue Principal`, COALESCE((ca.InterestAmount - (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE ca.InterestCollected END)), 0) AS `Overdue Interest`, (CASE WHEN col.lead_status in ('Settlement','Closed') THEN 0 ELSE COALESCE((CASE WHEN le.ipc=1 THEN da.IPCDueAmount ELSE da.DueAmount END), 0) END) AS `Overdue Amount`, IFNULL(col.lead_status,'Disbursed') AS `Lead Status`, le.createdDate AS `Status Date`, le.ipc AS `IPC FLAG`, le.fbLeads AS `Customer type`, ifnull((CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END),l.disbursalAmount) AS `Principal Outstanding (POS)`, da.DueAmount AS `Due Amount on Current Date`, da.CurrentTenure AS `Current Tenure`, le.pincode AS `Pincode`,
(CASE WHEN col.TotalCollectedAmount<>col.collectedAmount or IFNULL(MaxClosedOrSettlementDate,0)<>0 THEN '-' ELSE lc.LastPOS END) AS `Loan_POS`, col.Waive_off_amount, c.employeeType AS `Employment Type`, c.designation AS `Designation`, age.AgeBracket AS `Age Bracket`, tenure.TenureBin AS `Tenure Bracket`, disbursal.DisbursalBracket AS `Disbursal Amount Bracket`, income.IncomeBracket AS `Income Bracket`, roi.ROIBracket AS `ROI Bracket`, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays)) AS `Actual Repay Amount`, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays)) - l.disbursalAmount AS `Actual Interest Amount`, (CASE WHEN le.ipc = 1 THEN col.excess_amount ELSE CASE WHEN (col.actual_collected_amount - (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays))) < 0 THEN 0 ELSE (col.actual_collected_amount - (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays))) END END) AS 'Excess Amount', CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) >90 THEN 'Yes' ELSE 'No' END AS WriteOffFlag, CASE WHEN le.ipc = 1 THEN col.penalCharges ELSE 0 END AS `Penal Charges`, CASE WHEN le.ipc = 0 THEN ca.PenalInterest ELSE 0 END AS `Penal Interest`, col.discount_waiver_amount AS `Discount Waiver Amount`, col.WaiverDate AS `Waiver Date`,
(CASE WHEN col.TotalCollectedAmount<>col.collectedAmount or IFNULL(MaxClosedOrSettlementDate,0)<>0 THEN '-' ELSE (CASE WHEN le.ipc=1 THEN (select sum(collected_principal) from collection where leadID=l.leadID and collectionStatus='Approved' and collectedMode IN ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) else ca.principal_waive_off end) end) AS principal_waive_off, (CASE WHEN ca.principal_waive_off=0 THEN col.discount_waiver_amount ELSE (col.discount_waiver_amount-ca.principal_waive_off) END) AS `interest_waive_off`, l.utr AS utr,CONCAT('"',col.OrderIDs,'"') AS `Collection Order IDs`,CONCAT('"',col.referenceNo,'"') AS razorpayOrderId
FROM loan l JOIN leads le ON l.leadID = le.leadID JOIN customer c ON l.customerID = c.customerID LEFT JOIN CIBILScore cs on cs.customerID=c.customerID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CalculatedAmounts ca ON l.leadID = ca.leadID AND l.loanNo = ca.loanNo AND col.collectionID = ca.collectionID LEFT JOIN OverdueAmounts oa ON l.leadID = oa.leadID AND l.loanNo = oa.loanNo
LEFT JOIN razorpay_payout_disbured_amount rpda ON l.leadID = rpda.leadID AND rpda.status = 'processed' LEFT JOIN DueAmounts da ON l.leadID = da.leadID AND l.loanNo = da.loanNo LEFT JOIN AgeCategorized age ON c.customerID = age.customerID LEFT JOIN TenureCategorized tenure ON a.leadID = tenure.leadID LEFT JOIN DisbursalAmountCategorized disbursal ON l.loanID = disbursal.loanID LEFT JOIN IncomeRanking income ON le.leadID = income.leadID LEFT JOIN ROICategorized roi ON a.leadID = roi.leadID LEFT JOIN Loan_POS_CTE lc ON l.loanNo = lc.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_loan_book_data_aum`(IN AS_ON_DATE DATE) BEGIN SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY',''));
WITH CollectionDetails AS ( SELECT col.collectionID, col.leadID, col.loanNo, col.status, col.excess_amount, col.principal_amount AS principal_amount, col.collected_principal AS collected_principal, col.collected_interest AS collected_interest, col.collected_penality AS collected_penality, col.collectedDate AS collectedDate, col.referenceNo AS referenceNo, CONCAT(MONTHNAME(col.collectedDate), ' ', YEAR(col.collectedDate)) AS CollectedMonth, col.collectedAmount AS CollectedAmount, DATEDIFF(col.collectedDate, a.repayDate) AS PaymentDPDs, col.orderID AS OrderIDs, col.collectedMode, (CASE WHEN collectedMode='Waive Off' or collectedMode='DISCOUNT' THEN collectedAmount else 0 end) Waive_off_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN discount_waiver_amount ELSE 0 END) AS discount_waiver_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN collectedDate ELSE NULL END) AS WaiverDate, (SELECT SUM(CASE WHEN collectedMode NOT IN ('Waive Off','DISCOUNT') THEN collectedAmount ELSE 0 END) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' and collectedDate<= AS_ON_DATE) AS actual_collected_amount, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalCollectedAmount, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE ) AS MaxCollectedDate, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE AND (status='closed' OR status='Settlement')) AS MaxClosedOrSettlementDate, (SELECT status FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE order by collectedDate,collectionID desc limit 1) AS lead_status, collected_penality AS penalCharges FROM collection col JOIN approval a ON col.leadID = a.leadID WHERE col.collectionStatus = 'Approved' and col.collectedDate<= AS_ON_DATE order by collectionID asc ), RefundDetails AS ( SELECT leadID, loanNo, collectedAmount AS `Refunded Amount`, collectedDate AS `Refund Date` FROM collection WHERE collectionStatus = 'Approved-refunded' and collectedDate <= AS_ON_DATE ), CalculatedAmounts AS ( SELECT l.leadID, l.loanNo, l.disbursalAmount, col.collectionID, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS RepayAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount AS InterestAmount, COALESCE(col.TotalCollectedAmount, 0) AS TotalCollectedAmount, (CASE WHEN LEAST(l.disbursalAmount, COALESCE(col.TotalCollectedAmount, 0))=col.TotalCollectedAmount THEN col.collectedAmount ELSE (CASE WHEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount))>0 THEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount)) else 0 END) END) AS PrincipalCollected, (CASE WHEN LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount - COALESCE(col.collectedAmount,0), 0))=(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) Then 0 ELSE LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount, 0)) END) AS InterestCollected, (CASE WHEN GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - COALESCE(col.collectedAmount,0), 0)>0 THEN col.collectedAmount ELSE GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)),0) END) AS PenalInterest, GREATEST(l.disbursalAmount - COALESCE(col.TotalCollectedAmount, 0), 0) AS POS, IFNULL((SELECT principal_amount FROM collection WHERE col.leadID=leadID AND collectionStatus='Approved' AND collectedDate < AS_ON_DATE ORDER BY collectionID DESC LIMIT 1), l.disbursalAmount) AS POSIPC,
CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE DATEDIFF(NOW(), l.disbursalDate) END AS ActualTenureDays, CASE WHEN (l.disbursalAmount > (col.actual_collected_amount)) THEN (CASE WHEN (l.disbursalAmount - (col.actual_collected_amount)) >= col.discount_waiver_amount THEN col.discount_waiver_amount ELSE (l.disbursalAmount - (col.actual_collected_amount)) END) ELSE 0 END AS `principal_waive_off` FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE ), OverdueAmounts AS ( SELECT l.leadID, l.loanNo, l.disbursalAmount AS OverduePrincipal, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount AS OverdueInterest FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN leads le ON l.leadID = le.leadID WHERE le.status = 'part payment' ), DueAmounts AS ( SELECT l.leadID, l.loanNo, ROUND( ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) + (l.disbursalAmount * 1.25 / 100 * DATEDIFF(AS_ON_DATE, a.repayDate)) - SUM(CASE WHEN co.collectionStatus = 'Approved' THEN co.collectedAmount ELSE 0 END) ) AS DueAmount, DATEDIFF(NOW(), a.repayDate) AS CurrentTenure FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN collection co ON l.leadID = co.leadID AND l.loanNo = co.loanNo LEFT JOIN leads le ON l.leadID = le.leadID WHERE (le.status = 'Disbursed' AND a.repayDate < AS_ON_DATE) OR le.status = 'part payment' GROUP BY l.leadID, l.loanNo, l.disbursalAmount, a.roi, a.tenure, a.repayDate ), AgeCategorized AS ( SELECT c.customerID, TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) AS age, CASE WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 20 AND 29 THEN '20-29' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 30 AND 39 THEN '30-39' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 40 AND 49 THEN '40-49' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 50 AND 59 THEN '50-59' ELSE '60+' END AS AgeBracket FROM customer c ), TenureCategorized AS ( SELECT a.leadID, a.tenure, CASE WHEN a.tenure BETWEEN 1 AND 15 THEN '1-15 days' WHEN a.tenure BETWEEN 16 AND 30 THEN '16-30 days' ELSE '30+ days' END AS TenureBin FROM approval a ), DisbursalAmountCategorized AS ( SELECT l.loanID, l.disbursalAmount, CASE WHEN l.disbursalAmount < 5000 THEN '<5000' WHEN l.disbursalAmount BETWEEN 5000 AND 9999 THEN '5000-10000' WHEN l.disbursalAmount BETWEEN 10000 AND 19999 THEN '10000-20000' WHEN l.disbursalAmount BETWEEN 20000 AND 29999 THEN '20000-30000' WHEN l.disbursalAmount BETWEEN 30000 AND 39999 THEN '30000-40000' WHEN l.disbursalAmount BETWEEN 40000 AND 49999 THEN '40000-80000' WHEN l.disbursalAmount BETWEEN 50000 AND 59999 THEN '50000-60000' WHEN l.disbursalAmount BETWEEN 60000 AND 69999 THEN '60000-70000' WHEN l.disbursalAmount BETWEEN 70000 AND 79999 THEN '70000-80000' WHEN l.disbursalAmount BETWEEN 80000 AND 89999 THEN '80000-90000' WHEN l.disbursalAmount BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN l.disbursalAmount BETWEEN 100000 AND 149999 THEN '100000-180000' ELSE '>180000' END AS DisbursalBracket FROM loan l ), IncomeRanking AS ( SELECT le.leadID, le.monthlyIncome, CASE WHEN le.monthlyIncome < 25000 THEN '<25000' WHEN le.monthlyIncome BETWEEN 25000 AND 29999 THEN '25000-30000' WHEN le.monthlyIncome BETWEEN 30000 AND 60000 THEN '30000-60000' WHEN le.monthlyIncome BETWEEN 60000 AND 89999 THEN '60000-90000' WHEN le.monthlyIncome BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN le.monthlyIncome BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '180000+' END AS IncomeBracket FROM leads le WHERE le.monthlyIncome IS NOT NULL ), ROICategorized AS ( SELECT a.leadID, a.roi, CASE WHEN a.roi < 0.8 THEN '<0.8' WHEN a.roi BETWEEN 0.8 AND 0.89 THEN '0.8-0.9' WHEN a.roi BETWEEN 0.9 AND 0.99 THEN '0.9-1' WHEN a.roi = 1.00 THEN '1' ELSE '>1' END AS ROIBracket FROM approval a ), Loan_POS_CTE AS ( SELECT l.loanNo, COALESCE( (SELECT POS FROM CalculatedAmounts ca WHERE ca.loanNo = l.loanNo ORDER BY ca.collectionID DESC LIMIT 1), 0) AS LastPOS FROM loan l WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE )
SELECT sum(CASE WHEN ifnull(col.TotalCollectedAmount,0)=ifnull(col.collectedAmount,0) && (from_unixtime(unix_timestamp(l.disbursalDate),'%Y-%m')=from_unixtime(unix_timestamp(AS_ON_DATE),'%Y-%m')) THEN l.disbursalAmount ELSE 0 END) AS 'Disbursal Amount', CONCAT(MONTHNAME(l.disbursalDate), ' ', YEAR(l.disbursalDate)) AS `Disbursal Month Year`, sum(CASE WHEN (from_unixtime(unix_timestamp(col.collectedDate),'%Y-%m')=from_unixtime(unix_timestamp(AS_ON_DATE),'%Y-%m')) THEN COALESCE(col.collectedAmount, 0) ELSE 0 END) AS `Total Collected Amount`, sum(CASE WHEN (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END)>l.disbursalAmount THEN l.disbursalAmount ELSE (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END) END ) AS 'Principal Collected_ipc', sum(CASE WHEN le.ipc=1 THEN col.collected_interest ELSE (CASE WHEN ca.InterestCollected=0 Then 0 else ca.InterestCollected- ifnull((select InterestCollected from CalculatedAmounts cc where ca.leadID = cc.leadID AND cc.loanNo = ca.loanNo AND cc.collectionID < ca.collectionID order by cc.collectionID desc limit 1),0) END) END) AS 'Interest Collected_ipc', sum(CASE WHEN le.ipc=1 THEN col.collected_penality ELSE ca.PenalInterest END) AS 'Late Fee Collected_ipc', sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) <=0 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `<=0`, sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 1 AND 30 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `(1-30)`, sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 31 AND 60 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `(31-60)`, sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 61 AND 90 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `(61-90)`, sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 91 AND 180 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `(91-180)`, sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 181 AND 365 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `(181-365)`, sum(CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate)>365 THEN (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN 0 ELSE lc.LastPOS END) ELSE 0 END) `>365`, sum(CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END) AS `Overdue Principal`, sum((CASE WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && ifnull(col.TotalCollectedAmount,0)=ifnull(col.collectedAmount,0) THEN lc.LastPOS ELSE 0 END)) AS `Principal Outstanding (POS)` FROM loan l JOIN leads le ON l.leadID = le.leadID JOIN customer c ON l.customerID = c.customerID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CalculatedAmounts ca ON l.leadID = ca.leadID AND l.loanNo = ca.loanNo AND col.collectionID = ca.collectionID LEFT JOIN OverdueAmounts oa ON l.leadID = oa.leadID AND l.loanNo = oa.loanNo
LEFT JOIN razorpay_payout_disbured_amount rpda ON l.leadID = rpda.leadID AND rpda.status = 'processed' LEFT JOIN DueAmounts da ON l.leadID = da.leadID AND l.loanNo = da.loanNo LEFT JOIN AgeCategorized age ON c.customerID = age.customerID LEFT JOIN TenureCategorized tenure ON a.leadID = tenure.leadID LEFT JOIN DisbursalAmountCategorized disbursal ON l.loanID = disbursal.loanID LEFT JOIN IncomeRanking income ON le.leadID = income.leadID LEFT JOIN ROICategorized roi ON a.leadID = roi.leadID LEFT JOIN Loan_POS_CTE lc ON l.loanNo = lc.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE ;
END
CREATE DEFINER=`admin`@`%` PROCEDURE `get_loan_book_data_withemi`(IN AS_ON_DATE DATE) BEGIN DECLARE tbname varchar(20); SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); DROP TABLE IF EXISTS tbname; create table tbname WITH CollectionDetails_old AS ( SELECT col.collectionID, col.leadID, col.loanNo, col.status, col.excess_amount, col.principal_amount AS principal_amount, col.collected_principal AS collected_principal, col.collected_interest AS collected_interest, col.collected_penality AS collected_penality, col.collectedDate AS collectedDate, col.referenceNo AS referenceNo, CONCAT(MONTHNAME(col.collectedDate), ' ', YEAR(col.collectedDate)) AS CollectedMonth, col.collectedAmount AS CollectedAmount, DATEDIFF(col.collectedDate, a.repayDate) AS PaymentDPDs, col.orderID AS OrderIDs, col.collectedMode, (CASE WHEN collectedMode='Waive Off' or collectedMode='DISCOUNT' THEN collectedAmount else 0 end) Waive_off_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN discount_waiver_amount ELSE 0 END) AS discount_waiver_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN collectedDate ELSE NULL END) AS WaiverDate, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' and collectedMode NOT IN ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) AS actual_collected_amount, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalCollectedAmount, (SELECT SUM(collected_principal) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalPrincipalAmount, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE ) AS MaxCollectedDate, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE AND (status='closed' OR status='Settlement')) AS MaxClosedOrSettlementDate, (SELECT status FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE order by collectionID desc limit 1) AS lead_status, collected_penality AS penalCharges, 'Payday' as productType, 0 AS emiAmount FROM collection col JOIN approval a ON col.leadID = a.leadID WHERE col.collectionStatus = 'Approved' and col.collectedDate<= AS_ON_DATE and collectedMode NOT IN ('Waive Off','DISCOUNT') order by collectionID ASC ), CollectionDetails AS ( select * from CollectionDetails_old union all SELECT concat(t.leadID,t.id) AS collectionID, emi.leadID, t.loanNo, t.status, ifnull(emi.accessAmount,0) AS excess_amount, ifnull(emi.principal,0) AS principal_amount, tt.collected_principal, tt.collected_interest, tt.collected_penality, t.createdAt AS collectedDate, t.referenceNo AS referenceNo, CONCAT(MONTHNAME(t.createdAt), ' ', YEAR(t.createdAt)) AS CollectedMonth, t.amount AS CollectedAmount, DATEDIFF(t.createdAt, emi.dueDate) AS PaymentDPDs, t.orderId AS OrderIDs, t.mode as collectedMode, (CASE WHEN t.mode='Waive Off' or t.mode='DISCOUNT' THEN t.amount else 0 end) Waive_off_amount, (CASE WHEN t.mode IN ('Waive Off', 'DISCOUNT') THEN t.amount ELSE 0 END) AS discount_waiver_amount, (CASE WHEN t.mode IN ('Waive Off', 'DISCOUNT') THEN t.createdAt ELSE NULL END) AS WaiverDate, (SELECT SUM(amount) FROM transactions WHERE leadID=t.leadID AND status=1 and (mode IS NULL OR mode NOT IN ('Waive Off','DISCOUNT')) and ( CASE WHEN transactionDate IS NULL THEN createdAt ELSE transactionDate END )<= DATE_FORMAT(AS_ON_DATE,'%Y-%m-%d 23:59:59')) AS actual_collected_amount, (SELECT SUM(amount) FROM transactions WHERE leadID=t.leadID and (mode IS NULL OR mode NOT IN ('Waive Off','DISCOUNT'))AND status=1 AND id<=t.id AND `type`='collection' AND ( CASE WHEN transactionDate IS NULL THEN createdAt ELSE transactionDate END )<= DATE_FORMAT(AS_ON_DATE,'%Y-%m-%d 23:59:59')) AS TotalCollectedAmount, (SELECT SUM(principal) FROM transactions inner join emi_transactions on transactions.id=emi_transactions.transaction_id WHERE leadID=t.leadID and (mode IS NULL OR mode NOT IN ('Waive Off','DISCOUNT')) AND status=1 AND id<=t.id AND ( CASE WHEN transactionDate IS NULL THEN createdAt ELSE transactionDate END )<= DATE_FORMAT(AS_ON_DATE,'%Y-%m-%d 23:59:59')) as TotalPrincipalAmount, (SELECT MAX( CASE WHEN transactionDate IS NULL THEN createdAt ELSE transactionDate END ) FROM transactions WHERE leadID=t.leadID and (mode IS NULL OR mode NOT IN ('Waive Off','DISCOUNT')) AND status=1 AND ( CASE WHEN transactionDate IS NULL THEN createdAt ELSE transactionDate END )<= DATE_FORMAT(AS_ON_DATE,'%Y-%m-%d 23:59:59') AND `type`='collection' ) AS MaxCollectedDate, 0 AS MaxClosedOrSettlementDate, payment_transaction_status AS lead_status, 0 AS penalCharges, 'EMI' as productType, amountPayable AS emiAmount FROM transactions t inner join (select emi_id,transaction_id,sum(ifnull((et.principal),0)) AS collected_principal, sum(ifnull((et.interest),0)) AS collected_interest, sum((ifnull(et.penalty,0)+ifnull(et.dpd_amount,0))) AS collected_penality from emi_transactions et group by et.transaction_id) tt on tt.transaction_id=t.id JOIN equated_monthly_installments emi on emi.emiID=tt.emi_id WHERE t.status = 1 and type='collection' and ( CASE WHEN t.transactionDate IS NULL THEN t.createdAt ELSE t.transactionDate END )<= DATE_FORMAT(AS_ON_DATE,'%Y-%m-%d 23:59:59') and (t.mode IS NULL OR mode NOT IN ('Waive Off','DISCOUNT')) order by collectionID ),
CalculatedAmounts AS ( SELECT l.leadID, l.loanNo, l.disbursalAmount, (col.collectionID) collectionID, (CASE WHEN col.productType='EMI' THEN (select sum(amountPayable) from equated_monthly_installments where is_deleted=0 and leadID=l.leadID) ELSE ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) END) AS RepayAmount, (CASE WHEN col.productType='EMI' THEN (select sum(interest) from equated_monthly_installments where is_deleted=0 and leadID=l.leadID) ELSE ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount END) AS InterestAmount, (CASE WHEN col.productType='EMI' THEN COALESCE(col.TotalCollectedAmount, 0) ELSE COALESCE(col.TotalCollectedAmount, 0) END) AS TotalCollectedAmount, (CASE WHEN col.productType='EMI' THEN col.collected_principal ELSE (CASE WHEN LEAST(l.disbursalAmount, COALESCE(col.TotalCollectedAmount, 0))=col.TotalCollectedAmount THEN col.collectedAmount ELSE (CASE WHEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount))>0 THEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount)) else 0 END) END) END) AS PrincipalCollected, (CASE WHEN col.productType='EMI' THEN col.collected_interest ELSE (CASE WHEN LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount - COALESCE(col.collectedAmount,0), 0))=(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) Then 0 ELSE LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount, 0)) END) END) AS InterestCollected, (CASE WHEN col.productType='EMI' THEN col.collected_penality ELSE (CASE WHEN GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - COALESCE(col.collectedAmount,0), 0)>0 THEN col.collectedAmount ELSE GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)),0) END) END) AS PenalInterest, (CASE WHEN col.productType='EMI' THEN GREATEST(l.disbursalAmount - COALESCE(col.TotalPrincipalAmount, 0), 0) ELSE GREATEST(l.disbursalAmount - COALESCE(col.TotalCollectedAmount, 0), 0) END) AS POS, IFNULL((SELECT principal_amount FROM collection WHERE col.leadID=leadID AND collectionStatus='Approved' AND collectedDate <=AS_ON_DATE ORDER BY collectionID DESC LIMIT 1), l.disbursalAmount) AS POSIPC,
CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE DATEDIFF(NOW(), l.disbursalDate) END AS ActualTenureDays, CASE WHEN (l.disbursalAmount > (col.actual_collected_amount)) and (col.lead_status='Closed' or col.lead_status='Settlement') THEN (l.disbursalAmount - (col.actual_collected_amount)) ELSE 0 END AS `principal_waive_off`, col.lead_status FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE ),
DueAmounts AS ( SELECT l.leadID, l.loanNo, ROUND( ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) + (l.disbursalAmount * 1.25 / 100 * DATEDIFF(AS_ON_DATE, a.repayDate)) - SUM(CASE WHEN co.collectionStatus = 'Approved' and co.collectedMode NOT IN ('Waive Off','DISCOUNT') THEN co.collectedAmount ELSE 0 END) ) AS DueAmount, DATEDIFF(NOW(), a.repayDate) AS CurrentTenure FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN collection co ON l.leadID = co.leadID AND l.loanNo = co.loanNo LEFT JOIN leads le ON l.leadID = le.leadID WHERE ((le.status = 'Disbursed' AND a.repayDate < AS_ON_DATE) OR le.status = 'part payment' ) and le.productID=2 GROUP BY l.leadID, l.loanNo, l.disbursalAmount, a.roi, a.tenure, a.repayDate ), DueAmountsEMI AS ( SELECT l.leadID, l.loanNo, sum(amountPayable) AS DueAmount, DATEDIFF(NOW(), min(emi.dueDate)) AS CurrentTenure FROM equated_monthly_installments emi JOIN loan l ON l.leadID = emi.leadID WHERE l.status = 'Disbursed' AND emi.dueDate < AS_ON_DATE and (emi.status <> 'paid' or emi.actualPaymentDate>=AS_ON_DATE) GROUP BY emi.leadID ), AgeCategorized AS ( SELECT c.customerID, TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) AS age, CASE WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 20 AND 29 THEN '20-29' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 30 AND 39 THEN '30-39' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 40 AND 49 THEN '40-49' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 50 AND 59 THEN '50-59' ELSE '60+' END AS AgeBracket FROM customer c ), TenureCategorized AS ( SELECT a.leadID, a.tenure, CASE WHEN a.tenure BETWEEN 1 AND 15 THEN '1-15 days' WHEN a.tenure BETWEEN 16 AND 30 THEN '16-30 days' ELSE '30+ days' END AS TenureBin FROM approval a ), CIBILScore AS ( select * from (Select customerID, score from cibil_score union all select customerID,score from credit_reports where score is not null) t group by t.customerID ), DisbursalAmountCategorized AS ( SELECT l.loanID, l.disbursalAmount, CASE WHEN l.disbursalAmount < 5000 THEN '<5000' WHEN l.disbursalAmount BETWEEN 5000 AND 9999 THEN '5000-10000' WHEN l.disbursalAmount BETWEEN 10000 AND 19999 THEN '10000-20000' WHEN l.disbursalAmount BETWEEN 20000 AND 29999 THEN '20000-30000' WHEN l.disbursalAmount BETWEEN 30000 AND 39999 THEN '30000-40000' WHEN l.disbursalAmount BETWEEN 40000 AND 49999 THEN '40000-80000' WHEN l.disbursalAmount BETWEEN 50000 AND 59999 THEN '50000-60000' WHEN l.disbursalAmount BETWEEN 60000 AND 69999 THEN '60000-70000' WHEN l.disbursalAmount BETWEEN 70000 AND 79999 THEN '70000-80000' WHEN l.disbursalAmount BETWEEN 80000 AND 89999 THEN '80000-90000' WHEN l.disbursalAmount BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN l.disbursalAmount BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '>150000' END AS DisbursalBracket FROM loan l ), IncomeRanking AS ( SELECT le.leadID, le.monthlyIncome, CASE WHEN le.monthlyIncome < 25000 THEN '<25000' WHEN le.monthlyIncome BETWEEN 25000 AND 29999 THEN '25000-30000' WHEN le.monthlyIncome BETWEEN 30000 AND 60000 THEN '30000-60000' WHEN le.monthlyIncome BETWEEN 60000 AND 89999 THEN '60000-90000' WHEN le.monthlyIncome BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN le.monthlyIncome BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '180000+' END AS IncomeBracket FROM leads le WHERE le.monthlyIncome IS NOT NULL ), ROICategorized AS ( SELECT a.leadID, a.roi, CASE WHEN a.roi < 0.8 THEN '<0.8' WHEN a.roi BETWEEN 0.8 AND 0.89 THEN '0.8-0.9' WHEN a.roi BETWEEN 0.9 AND 0.99 THEN '0.9-1' WHEN a.roi = 1.00 THEN '1' ELSE '>1' END AS ROIBracket FROM approval a ), Loan_POS_CTE AS ( SELECT l.loanNo, COALESCE( (SELECT (CASE WHEN ca.lead_status in('Closed','Settlement') then 0 else (CASE WHEN le.productID=2 and le.ipc=1 then POSIPC ELSE POS END) END) FROM CalculatedAmounts ca WHERE ca.loanNo = l.loanNo ORDER BY ca.TotalCollectedAmount DESC LIMIT 1), 0) AS LastPOS FROM loan l inner join leads le on l.leadID=le.leadID WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE )
SELECT c.customerID AS UserID, l.loanNo AS LoanID, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE l.disbursalAmount END) AS 'Disbursal Amount', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE a.adminFee END) AS 'PF', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE a.GstOfAdminFee END) AS `GST amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (l.disbursalAmount - a.adminFee - a.GstOfAdminFee) END) AS `Net Disbursal Amount`, l.disbursalDate AS `Disbursal Date`, CONCAT(MONTHNAME(l.disbursalDate), ' ', YEAR(l.disbursalDate)) AS `Disbursal Month Year`, a.repayDate AS `Due Date`, CONCAT(MONTHNAME(a.repayDate), ' ', YEAR(a.repayDate)) AS `Due Date Month Year`, IFNULL(col.status,'Disbursed') AS paymentStatus, col.collectedMode AS Modeofpayment, (CASE WHEN le.productID=1 THEN 'EMI' ELSE 'Payday' END) AS `ProductID or Name`, cs.score AS `CIBIL Score`, a.roi AS Interest_Rate, a.tenure AS Tenure, DATEDIFF(a.repayDate, l.disbursalDate) AS DISB_TENURE, CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE NULL END AS ACTUAL_TENURE, col.MaxCollectedDate AS `Date of Collection (Most Recent)`, col.CollectedDate AS `Collected Date`, col.CollectedMonth AS `Collected Month`, col.CollectedAmount AS `Collected Amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE COALESCE(ca.RepayAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) END) AS 'DD Repay Amount', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE COALESCE(ca.InterestAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) END) AS 'DD Interest Amount', COALESCE(col.TotalCollectedAmount, 0) AS `Total Collected Amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (select sum(collectedAmount) from collection where leadID=l.leadID and collectionStatus='Approved-refunded') END) AS 'Refunded Amount', (CASE WHEN (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END)>l.disbursalAmount THEN l.disbursalAmount ELSE (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END) END ) AS 'Principal Collected_ipc', (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE (CASE WHEN ca.InterestCollected=0 Then 0 else ca.InterestCollected- ifnull((select InterestCollected from CalculatedAmounts cc where ca.leadID = cc.leadID AND cc.loanNo = ca.loanNo AND cc.collectionID < ca.collectionID order by cc.collectionID desc limit 1),0) END) END) AS 'Interest Collected_ipc', (CASE WHEN le.ipc=1 THEN col.collected_penality ELSE ca.PenalInterest END) AS 'Late Fee Collected_ipc', IFNULL(col.PaymentDPDs,0) AS `Payment DPDs`, CASE WHEN IFNULL(col.PaymentDPDs,0) <= 0 THEN '(<=0)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 1 AND 30 THEN '(1-30)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 31 AND 60 THEN '(31-60)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 61 AND 90 THEN '(61-90)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 91 AND 180 THEN '(91-180)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 181 AND 365 THEN '(181-365)' ELSE '(>365)' END AS `Payment DPD bins`, CASE WHEN DATEDIFF(AS_ON_DATE,a.repayDate) <= 0 THEN 'Standard Assets' WHEN IFNULL(MaxClosedOrSettlementDate,0)>0 THEN 'Closed Assets' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) <= 0 THEN '(<=0)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 1 AND 30 THEN '(1-30)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 31 AND 60 THEN '(31-60)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 61 AND 90 THEN '(61-90)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 91 AND 180 THEN '(91-180)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 181 AND 365 THEN '(181-365)' ELSE '(>365)' END AS `Loan DPD bins`, (CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END) AS `Overdue Principal`, COALESCE((ca.InterestAmount - (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE ca.InterestCollected END)), 0) AS `Overdue Interest`, COALESCE((CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END),0) + COALESCE((ca.InterestAmount - (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE ca.InterestCollected END)), 0) AS `Overdue Amount`, IFNULL(col.lead_status,'Disbursed') AS `lead_status`, le.createdDate AS `Status Date`, le.ipc AS `IPC FLAG`, le.fbLeads AS `Customer type`, ifnull((CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END),l.disbursalAmount) AS `Principal Outstanding (POS)`, (CASE WHEN le.productID=1 THEN dm.DueAmount ELSE da.DueAmount END)AS `Due Amount on Current Date`, (CASE WHEN le.productID=1 THEN dm.CurrentTenure ELSE da.CurrentTenure END) AS `Current Tenure`, le.pincode AS `Pincode`,
(CASE WHEN col.TotalCollectedAmount<>col.collectedAmount or IFNULL(MaxClosedOrSettlementDate,0)<>0 THEN '-' ELSE lc.LastPOS END) AS `Loan_POS`, col.Waive_off_amount, c.employeeType AS `Employment Type`, c.designation AS `Designation`, age.AgeBracket AS `Age Bracket`, tenure.TenureBin AS `Tenure Bracket`, disbursal.DisbursalBracket AS `Disbursal Amount Bracket`, income.IncomeBracket AS `Income Bracket`, roi.ROIBracket AS `ROI Bracket`, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays)) AS `Actual Repay Amount`, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays)) - l.disbursalAmount AS `Actual Interest Amount`, (CASE WHEN le.ipc = 1 THEN col.excess_amount ELSE CASE WHEN (col.actual_collected_amount - (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays))) < 0 THEN 0 ELSE (col.actual_collected_amount - (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays))) END END) AS 'Excess Amount', CASE WHEN l.writeoff_status=1 THEN 'Yes' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) >30 && l.writeoff_status=0 THEN 'Yes' ELSE 'No' END AS WriteOffFlag, CASE WHEN l.writeoff_status=1 THEN DATE_FORMAT(writeoff_date, '%M-%Y') WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && l.writeoff_status=0 && DATEDIFF(AS_ON_DATE,a.repayDate) >30 THEN DATE_FORMAT(AS_ON_DATE, '%M-%Y') ELSE '' END AS WriteOffDate,
CASE WHEN DATEDIFF(collectedDate,repayDate) >30 THEN 'Yes' ELSE 'No' END AS WriteOffPaymentFlag, col.excess_amount, CASE WHEN le.ipc = 1 THEN col.penalCharges ELSE 0 END AS `Penal Charges`, CASE WHEN le.ipc = 0 THEN ca.PenalInterest ELSE 0 END AS `Penal Interest`, col.discount_waiver_amount AS `Discount Waiver Amount`, col.WaiverDate AS `Waiver Date`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (CASE WHEN le.ipc=1 and (col.lead_status='Closed' or col.lead_status='Settlement') THEN (select (CASE WHEN l.disbursalAmount>sum(collected_principal) THEN l.disbursalAmount-sum(collected_principal) else 0 end) from collection where leadID=l.leadID and collectionStatus='Approved' and collectedMode not in ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) else ca.principal_waive_off end) end) AS principal_waive_off, (CASE WHEN ca.principal_waive_off=0 THEN col.discount_waiver_amount ELSE (col.discount_waiver_amount-ca.principal_waive_off) END) AS `interest_waive_off`, l.utr AS utr,CONCAT('"',col.OrderIDs,'"') AS `Collection Order IDs`,CONCAT('"',col.referenceNo,'"') AS razorpayOrderId
FROM loan l JOIN leads le ON l.leadID = le.leadID JOIN customer c ON l.customerID = c.customerID LEFT JOIN CIBILScore cs on cs.customerID=c.customerID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CalculatedAmounts ca ON l.leadID = ca.leadID AND l.loanNo = ca.loanNo AND col.collectionID = ca.collectionID
LEFT JOIN razorpay_payout_disbured_amount rpda ON l.leadID = rpda.leadID AND rpda.status = 'processed' LEFT JOIN DueAmounts da ON l.leadID = da.leadID AND l.loanNo = da.loanNo LEFT JOIN DueAmountsEMI dm ON l.leadID = dm.leadID AND l.loanNo = dm.loanNo LEFT JOIN AgeCategorized age ON c.customerID = age.customerID LEFT JOIN TenureCategorized tenure ON a.leadID = tenure.leadID LEFT JOIN DisbursalAmountCategorized disbursal ON l.loanID = disbursal.loanID LEFT JOIN IncomeRanking income ON le.leadID = income.leadID LEFT JOIN ROICategorized roi ON a.leadID = roi.leadID LEFT JOIN Loan_POS_CTE lc ON l.loanNo = lc.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE;
SET @query = CONCAT('RENAME TABLE tbname TO loanbook',replace(AS_ON_DATE,'-','')); PREPARE stmt FROM @query; EXECUTE stmt; DEALLOCATE PREPARE stmt; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_loan_book_data_withemi_specific`(IN AS_ON_DATE DATE) BEGIN DECLARE tbname varchar(20); SET sql_mode=(SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); DROP TABLE IF EXISTS tbname; create table tbname WITH CollectionDetails AS ( SELECT col.collectionID, col.leadID, col.loanNo, col.status, col.excess_amount, col.principal_amount AS principal_amount, col.collected_principal AS collected_principal, col.collected_interest AS collected_interest, col.collected_penality AS collected_penality, col.collectedDate AS collectedDate, col.referenceNo AS referenceNo, CONCAT(MONTHNAME(col.collectedDate), ' ', YEAR(col.collectedDate)) AS CollectedMonth, col.collectedAmount AS CollectedAmount, DATEDIFF(col.collectedDate, a.repayDate) AS PaymentDPDs, col.orderID AS OrderIDs, col.collectedMode, (CASE WHEN collectedMode='Waive Off' or collectedMode='DISCOUNT' THEN collectedAmount else 0 end) Waive_off_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN discount_waiver_amount ELSE 0 END) AS discount_waiver_amount, (CASE WHEN collectedMode IN ('Waive Off', 'DISCOUNT') THEN collectedDate ELSE NULL END) AS WaiverDate, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' and collectedMode NOT IN ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) AS actual_collected_amount, (SELECT SUM(collectedAmount) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalCollectedAmount, (SELECT SUM(collected_principal) FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectionID<=col.collectionID AND collectedDate<= AS_ON_DATE) AS TotalPrincipalAmount, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE ) AS MaxCollectedDate, (SELECT MAX(collectedDate) FROM collection WHERE leadID=col.leadID and collectedMode NOT IN ('Waive Off','DISCOUNT') AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE AND (status='closed' OR status='Settlement')) AS MaxClosedOrSettlementDate, (SELECT status FROM collection WHERE leadID=col.leadID AND collectionStatus='Approved' AND collectedDate<= AS_ON_DATE order by collectionID desc limit 1) AS lead_status, collected_penality AS penalCharges, 'Payday' as productType, 0 AS emiAmount FROM collection col JOIN approval a ON col.leadID = a.leadID WHERE col.loanNo in ('HC202407041415469007','HC202408161442274907','HC202408271708451264','HC202409281453345894','HC202410181214008798','HC202411061146264070','HC202411071329156136','HC202412051641505703','HC202412052129422677','HC202412052310525858','HC202412061004529324','HC202412062002218941','HC202412071400229580','HC202412301038144980','HC202412301054083247','HC202412310812101316','HC202501011723172152','HC202501030751388871','HC202501061739448327','HC202501081523075011','HC202501112237518675','HC202501141727319196','HC202501161058563049','HC202501161208364556','HC202501171521528532','HC202501180845367677','HC202501241722083773','HC202501311157441049','HC202501311911176947','HC202501301054077901','HC202412091742411590','HC202407030902575678','HC202412071108371338','HC202408311231518472','HC202501261057525370','HC202408011217501726','HC202410291539299830','HC202410081954162405') and col.collectionStatus = 'Approved' and col.collectedDate<= AS_ON_DATE and collectedMode NOT IN ('Waive Off','DISCOUNT') order by collectionID ASC ),
CalculatedAmounts AS ( SELECT l.leadID, l.loanNo, l.disbursalAmount, (col.collectionID) collectionID, (CASE WHEN col.productType='EMI' THEN (select sum(amountPayable) from equated_monthly_installments where is_deleted=0 and leadID=l.leadID) ELSE ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) END) AS RepayAmount, (CASE WHEN col.productType='EMI' THEN (select sum(interest) from equated_monthly_installments where is_deleted=0 and leadID=l.leadID) ELSE ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount END) AS InterestAmount, (CASE WHEN col.productType='EMI' THEN COALESCE(col.TotalCollectedAmount, 0) ELSE COALESCE(col.TotalCollectedAmount, 0) END) AS TotalCollectedAmount, (CASE WHEN col.productType='EMI' THEN col.collected_principal ELSE (CASE WHEN LEAST(l.disbursalAmount, COALESCE(col.TotalCollectedAmount, 0))=col.TotalCollectedAmount THEN col.collectedAmount ELSE (CASE WHEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount))>0 THEN (col.collectedAmount-(col.TotalCollectedAmount-l.disbursalAmount)) else 0 END) END) END) AS PrincipalCollected, (CASE WHEN col.productType='EMI' THEN col.collected_interest ELSE (CASE WHEN LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount - COALESCE(col.collectedAmount,0), 0))=(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) Then 0 ELSE LEAST(ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount, GREATEST(COALESCE(col.TotalCollectedAmount, 0) - l.disbursalAmount, 0)) END) END) AS InterestCollected, (CASE WHEN col.productType='EMI' THEN col.collected_penality ELSE (CASE WHEN GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - COALESCE(col.collectedAmount,0), 0)>0 THEN col.collectedAmount ELSE GREATEST(COALESCE(col.TotalCollectedAmount, 0) - ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)),0) END) END) AS PenalInterest, (CASE WHEN col.productType='EMI' THEN GREATEST(l.disbursalAmount - COALESCE(col.TotalPrincipalAmount, 0), 0) ELSE GREATEST(l.disbursalAmount - COALESCE(col.TotalCollectedAmount, 0), 0) END) AS POS, IFNULL((SELECT principal_amount FROM collection WHERE col.leadID=leadID AND collectionStatus='Approved' AND collectedDate <=AS_ON_DATE ORDER BY collectionID DESC LIMIT 1), l.disbursalAmount) AS POSIPC,
CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE DATEDIFF(NOW(), l.disbursalDate) END AS ActualTenureDays, CASE WHEN (l.disbursalAmount > (col.actual_collected_amount)) and (col.lead_status='Closed' or col.lead_status='Settlement') THEN (l.disbursalAmount - (col.actual_collected_amount)) ELSE 0 END AS `principal_waive_off`, col.lead_status FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE ),
DueAmounts AS ( SELECT l.leadID, l.loanNo, ROUND( ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) + (l.disbursalAmount * 1.25 / 100 * DATEDIFF(AS_ON_DATE, a.repayDate)) - SUM(CASE WHEN co.collectionStatus = 'Approved' and co.collectedMode NOT IN ('Waive Off','DISCOUNT') THEN co.collectedAmount ELSE 0 END) ) AS DueAmount, DATEDIFF(NOW(), a.repayDate) AS CurrentTenure FROM loan l LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN collection co ON l.leadID = co.leadID AND l.loanNo = co.loanNo LEFT JOIN leads le ON l.leadID = le.leadID WHERE ((le.status = 'Disbursed' AND a.repayDate < AS_ON_DATE) OR le.status = 'part payment' ) and le.productID=2 GROUP BY l.leadID, l.loanNo, l.disbursalAmount, a.roi, a.tenure, a.repayDate ), DueAmountsEMI AS ( SELECT l.leadID, l.loanNo, sum(amountPayable) AS DueAmount, DATEDIFF(NOW(), min(emi.dueDate)) AS CurrentTenure FROM equated_monthly_installments emi JOIN loan l ON l.leadID = emi.leadID WHERE l.status = 'Disbursed' AND emi.dueDate < AS_ON_DATE and (emi.status <> 'paid' or emi.actualPaymentDate>=AS_ON_DATE) GROUP BY emi.leadID ), AgeCategorized AS ( SELECT c.customerID, TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) AS age, CASE WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 20 AND 29 THEN '20-29' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 30 AND 39 THEN '30-39' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 40 AND 49 THEN '40-49' WHEN TIMESTAMPDIFF(YEAR, c.dob, c.createdDate) BETWEEN 50 AND 59 THEN '50-59' ELSE '60+' END AS AgeBracket FROM customer c ), TenureCategorized AS ( SELECT a.leadID, a.tenure, CASE WHEN a.tenure BETWEEN 1 AND 15 THEN '1-15 days' WHEN a.tenure BETWEEN 16 AND 30 THEN '16-30 days' ELSE '30+ days' END AS TenureBin FROM approval a ), CIBILScore AS ( select * from (Select customerID, score from cibil_score union all select customerID,score from credit_reports where score is not null) t group by t.customerID ), DisbursalAmountCategorized AS ( SELECT l.loanID, l.disbursalAmount, CASE WHEN l.disbursalAmount < 5000 THEN '<5000' WHEN l.disbursalAmount BETWEEN 5000 AND 9999 THEN '5000-10000' WHEN l.disbursalAmount BETWEEN 10000 AND 19999 THEN '10000-20000' WHEN l.disbursalAmount BETWEEN 20000 AND 29999 THEN '20000-30000' WHEN l.disbursalAmount BETWEEN 30000 AND 39999 THEN '30000-40000' WHEN l.disbursalAmount BETWEEN 40000 AND 49999 THEN '40000-80000' WHEN l.disbursalAmount BETWEEN 50000 AND 59999 THEN '50000-60000' WHEN l.disbursalAmount BETWEEN 60000 AND 69999 THEN '60000-70000' WHEN l.disbursalAmount BETWEEN 70000 AND 79999 THEN '70000-80000' WHEN l.disbursalAmount BETWEEN 80000 AND 89999 THEN '80000-90000' WHEN l.disbursalAmount BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN l.disbursalAmount BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '>150000' END AS DisbursalBracket FROM loan l ), IncomeRanking AS ( SELECT le.leadID, le.monthlyIncome, CASE WHEN le.monthlyIncome < 25000 THEN '<25000' WHEN le.monthlyIncome BETWEEN 25000 AND 29999 THEN '25000-30000' WHEN le.monthlyIncome BETWEEN 30000 AND 60000 THEN '30000-60000' WHEN le.monthlyIncome BETWEEN 60000 AND 89999 THEN '60000-90000' WHEN le.monthlyIncome BETWEEN 90000 AND 99999 THEN '90000-100000' WHEN le.monthlyIncome BETWEEN 100000 AND 149999 THEN '100000-150000' ELSE '180000+' END AS IncomeBracket FROM leads le WHERE le.monthlyIncome IS NOT NULL ), ROICategorized AS ( SELECT a.leadID, a.roi, CASE WHEN a.roi < 0.8 THEN '<0.8' WHEN a.roi BETWEEN 0.8 AND 0.89 THEN '0.8-0.9' WHEN a.roi BETWEEN 0.9 AND 0.99 THEN '0.9-1' WHEN a.roi = 1.00 THEN '1' ELSE '>1' END AS ROIBracket FROM approval a ), Loan_POS_CTE AS ( SELECT l.loanNo, COALESCE( (SELECT (CASE WHEN ca.lead_status in('Closed','Settlement') then 0 else (CASE WHEN le.productID=2 and le.ipc=1 then POSIPC ELSE POS END) END) FROM CalculatedAmounts ca WHERE ca.loanNo = l.loanNo ORDER BY ca.TotalCollectedAmount DESC LIMIT 1), 0) AS LastPOS FROM loan l inner join leads le on l.leadID=le.leadID WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE )
SELECT c.customerID AS UserID, l.loanNo AS LoanID, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE l.disbursalAmount END) AS 'Disbursal Amount', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE a.adminFee END) AS 'PF', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE a.GstOfAdminFee END) AS `GST amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (l.disbursalAmount - a.adminFee - a.GstOfAdminFee) END) AS `Net Disbursal Amount`, l.disbursalDate AS `Disbursal Date`, CONCAT(MONTHNAME(l.disbursalDate), ' ', YEAR(l.disbursalDate)) AS `Disbursal Month Year`, a.repayDate AS `Due Date`, CONCAT(MONTHNAME(a.repayDate), ' ', YEAR(a.repayDate)) AS `Due Date Month Year`, IFNULL(col.status,'Disbursed') AS paymentStatus, col.collectedMode AS Modeofpayment, (CASE WHEN le.productID=1 THEN 'EMI' ELSE 'Payday' END) AS `ProductID or Name`, cs.score AS `CIBIL Score`, a.roi AS Interest_Rate, a.tenure AS Tenure, DATEDIFF(a.repayDate, l.disbursalDate) AS DISB_TENURE, CASE WHEN col.MaxClosedOrSettlementDate IS NOT NULL THEN DATEDIFF(col.MaxClosedOrSettlementDate, l.disbursalDate) ELSE NULL END AS ACTUAL_TENURE, col.MaxCollectedDate AS `Date of Collection (Most Recent)`, col.CollectedDate AS `Collected Date`, col.CollectedMonth AS `Collected Month`, col.CollectedAmount AS `Collected Amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE COALESCE(ca.RepayAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure))) END) AS 'DD Repay Amount', (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE COALESCE(ca.InterestAmount, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) - l.disbursalAmount) END) AS 'DD Interest Amount', COALESCE(col.TotalCollectedAmount, 0) AS `Total Collected Amount`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (select sum(collectedAmount) from collection where leadID=l.leadID and collectionStatus='Approved-refunded') END) AS 'Refunded Amount', (CASE WHEN (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END)>l.disbursalAmount THEN l.disbursalAmount ELSE (CASE WHEN le.ipc=1 THEN col.collected_principal ELSE ca.PrincipalCollected END) END ) AS 'Principal Collected_ipc', (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE (CASE WHEN ca.InterestCollected=0 Then 0 else ca.InterestCollected- ifnull((select InterestCollected from CalculatedAmounts cc where ca.leadID = cc.leadID AND cc.loanNo = ca.loanNo AND cc.collectionID < ca.collectionID order by cc.collectionID desc limit 1),0) END) END) AS 'Interest Collected_ipc', (CASE WHEN le.ipc=1 THEN col.collected_penality ELSE ca.PenalInterest END) AS 'Late Fee Collected_ipc', IFNULL(col.PaymentDPDs,0) AS `Payment DPDs`, CASE WHEN IFNULL(col.PaymentDPDs,0) <= 0 THEN '(<=0)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 1 AND 30 THEN '(1-30)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 31 AND 60 THEN '(31-60)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 61 AND 90 THEN '(61-90)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 91 AND 180 THEN '(91-180)' WHEN IFNULL(col.PaymentDPDs,0) BETWEEN 181 AND 365 THEN '(181-365)' ELSE '(>365)' END AS `Payment DPD bins`, CASE WHEN DATEDIFF(AS_ON_DATE,a.repayDate) <= 0 THEN 'Standard Assets' WHEN IFNULL(MaxClosedOrSettlementDate,0)>0 THEN 'Closed Assets' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) <= 0 THEN '(<=0)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 1 AND 30 THEN '(1-30)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 31 AND 60 THEN '(31-60)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 61 AND 90 THEN '(61-90)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 91 AND 180 THEN '(91-180)' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) BETWEEN 181 AND 365 THEN '(181-365)' ELSE '(>365)' END AS `Loan DPD bins`, (CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END) AS `Overdue Principal`, COALESCE((ca.InterestAmount - (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE ca.InterestCollected END)), 0) AS `Overdue Interest`, COALESCE((CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END),0) + COALESCE((ca.InterestAmount - (CASE WHEN le.ipc=1 THEN col.collected_interest ELSE ca.InterestCollected END)), 0) AS `Overdue Amount`, IFNULL(col.lead_status,'Disbursed') AS `lead_status`, le.createdDate AS `Status Date`, le.ipc AS `IPC FLAG`, le.fbLeads AS `Customer type`, ifnull((CASE WHEN le.ipc=1 THEN ca.POSIPC ELSE ca.POS END),l.disbursalAmount) AS `Principal Outstanding (POS)`, (CASE WHEN le.productID=1 THEN dm.DueAmount ELSE da.DueAmount END)AS `Due Amount on Current Date`, (CASE WHEN le.productID=1 THEN dm.CurrentTenure ELSE da.CurrentTenure END) AS `Current Tenure`, le.pincode AS `Pincode`,
(CASE WHEN col.TotalCollectedAmount<>col.collectedAmount or IFNULL(MaxClosedOrSettlementDate,0)<>0 THEN '-' ELSE lc.LastPOS END) AS `Loan_POS`, col.Waive_off_amount, c.employeeType AS `Employment Type`, c.designation AS `Designation`, age.AgeBracket AS `Age Bracket`, tenure.TenureBin AS `Tenure Bracket`, disbursal.DisbursalBracket AS `Disbursal Amount Bracket`, income.IncomeBracket AS `Income Bracket`, roi.ROIBracket AS `ROI Bracket`, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays)) AS `Actual Repay Amount`, ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays)) - l.disbursalAmount AS `Actual Interest Amount`, (CASE WHEN le.ipc = 1 THEN col.excess_amount ELSE CASE WHEN (col.actual_collected_amount - (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays))) < 0 THEN 0 ELSE (col.actual_collected_amount - (l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * ca.ActualTenureDays))) END END) AS 'Excess Amount', CASE WHEN l.writeoff_status=1 THEN 'Yes' WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && DATEDIFF(AS_ON_DATE,a.repayDate) >30 && l.writeoff_status=0 THEN 'Yes' ELSE 'No' END AS WriteOffFlag, CASE WHEN l.writeoff_status=1 THEN DATE_FORMAT(writeoff_date, '%M-%Y') WHEN IFNULL(MaxClosedOrSettlementDate,0)=0 && l.writeoff_status=0 && DATEDIFF(AS_ON_DATE,a.repayDate) >30 THEN DATE_FORMAT(AS_ON_DATE, '%M-%Y') ELSE '' END AS WriteOffDate,
CASE WHEN DATEDIFF(collectedDate,repayDate) >30 THEN 'Yes' ELSE 'No' END AS WriteOffPaymentFlag, col.excess_amount, CASE WHEN le.ipc = 1 THEN col.penalCharges ELSE 0 END AS `Penal Charges`, CASE WHEN le.ipc = 0 THEN ca.PenalInterest ELSE 0 END AS `Penal Interest`, col.discount_waiver_amount AS `Discount Waiver Amount`, col.WaiverDate AS `Waiver Date`, (CASE WHEN col.TotalCollectedAmount<>col.collectedAmount THEN '-' ELSE (CASE WHEN le.ipc=1 and (col.lead_status='Closed' or col.lead_status='Settlement') THEN (select (CASE WHEN l.disbursalAmount>sum(collected_principal) THEN l.disbursalAmount-sum(collected_principal) else 0 end) from collection where leadID=l.leadID and collectionStatus='Approved' and collectedMode not in ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) else (CASE WHEN le.ipc=1 THEN (select sum(collected_principal) from collection where leadID=l.leadID and collectionStatus='Approved' and collectedMode in ('Waive Off','DISCOUNT') and collectedDate<= AS_ON_DATE) else ca.principal_waive_off end) end) end) AS principal_waive_off, (CASE WHEN ca.principal_waive_off=0 THEN col.discount_waiver_amount ELSE (col.discount_waiver_amount-ca.principal_waive_off) END) AS `interest_waive_off`, l.utr AS utr,CONCAT('"',col.OrderIDs,'"') AS `Collection Order IDs`,CONCAT('"',col.referenceNo,'"') AS razorpayOrderId
FROM loan l JOIN leads le ON l.leadID = le.leadID JOIN customer c ON l.customerID = c.customerID LEFT JOIN CIBILScore cs on cs.customerID=c.customerID LEFT JOIN CollectionDetails col ON l.leadID = col.leadID AND l.loanNo = col.loanNo LEFT JOIN approval a ON l.leadID = a.leadID LEFT JOIN CalculatedAmounts ca ON l.leadID = ca.leadID AND l.loanNo = ca.loanNo AND col.collectionID = ca.collectionID
LEFT JOIN razorpay_payout_disbured_amount rpda ON l.leadID = rpda.leadID AND rpda.status = 'processed' LEFT JOIN DueAmounts da ON l.leadID = da.leadID AND l.loanNo = da.loanNo LEFT JOIN DueAmountsEMI dm ON l.leadID = dm.leadID AND l.loanNo = dm.loanNo LEFT JOIN AgeCategorized age ON c.customerID = age.customerID LEFT JOIN TenureCategorized tenure ON a.leadID = tenure.leadID LEFT JOIN DisbursalAmountCategorized disbursal ON l.loanID = disbursal.loanID LEFT JOIN IncomeRanking income ON le.leadID = income.leadID LEFT JOIN ROICategorized roi ON a.leadID = roi.leadID LEFT JOIN Loan_POS_CTE lc ON l.loanNo = lc.loanNo WHERE l.status = 'Disbursed' and l.disbursalDate <= AS_ON_DATE and l.loanNo in ('HC202407041415469007','HC202408161442274907','HC202408271708451264','HC202409281453345894','HC202410181214008798','HC202411061146264070','HC202411071329156136','HC202412051641505703','HC202412052129422677','HC202412052310525858','HC202412061004529324','HC202412062002218941','HC202412071400229580','HC202412301038144980','HC202412301054083247','HC202412310812101316','HC202501011723172152','HC202501030751388871','HC202501061739448327','HC202501081523075011','HC202501112237518675','HC202501141727319196','HC202501161058563049','HC202501161208364556','HC202501171521528532','HC202501180845367677','HC202501241722083773','HC202501311157441049','HC202501311911176947','HC202501301054077901','HC202412091742411590','HC202407030902575678','HC202412071108371338','HC202408311231518472','HC202501261057525370','HC202408011217501726','HC202410291539299830','HC202410081954162405');
SET @query = CONCAT('RENAME TABLE tbname TO specificloanbook',replace(AS_ON_DATE,'-','')); PREPARE stmt FROM @query; EXECUTE stmt; DEALLOCATE PREPARE stmt; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_loan_book_data_withemi_static`(IN AS_ON_DATE DATE) BEGIN SET @query = CONCAT('SELECT * FROM loanbook',replace(AS_ON_DATE,'-','')); PREPARE stmt FROM @query; EXECUTE stmt; DEALLOCATE PREPARE stmt; END
