CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `get_loan_book_data_withemi_static90`(IN AS_ON_DATE DATE) BEGIN SET @query = CONCAT('SELECT * FROM loanbook',replace(AS_ON_DATE,'-','')); PREPARE stmt FROM @query; EXECUTE stmt; DEALLOCATE PREPARE stmt; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `GetCountsFromAllTables`() BEGIN DECLARE done INT DEFAULT FALSE; DECLARE tbl_name VARCHAR(255); DECLARE ts_column VARCHAR(255); DECLARE sql_query TEXT;
DECLARE table_cursor CURSOR FOR SELECT table_name FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name IN ('approval', 'leads', 'customer', 'users', 'loan', 'collection', 'transactions', 'emis', 'emi_transactions', 'callhistory', 'onlinePyanentlog', 'onlinepayment'); DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE; OPEN table_cursor; read_loop: LOOP SET ts_column = NULL; FETCH table_cursor INTO tbl_name; IF done THEN LEAVE read_loop; END IF;
SET ts_column = ( SELECT COLUMN_NAME FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = tbl_name AND DATA_TYPE = 'timestamp' LIMIT 1 );
IF ts_column IS NULL THEN ITERATE read_loop; END IF;
SET @sql_query = CONCAT( 'INSERT INTO record_counts_by_date2 (table_name, event_date, total_count) ', 'SELECT ''', tbl_name, ''', DATE(', ts_column, '), COUNT(*) ', 'FROM `', tbl_name, '` ', 'GROUP BY DATE(', ts_column,');' );
SELECT CONCAT('Executing: ', @sql_query) AS executing_query; PREPARE stmt FROM @sql_query; EXECUTE stmt; DEALLOCATE PREPARE stmt; END LOOP; CLOSE table_cursor; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `GetLoanbookSummaryRange`( IN disbursalStart DATE, IN disbursalEnd DATE, IN collectedStart DATE, IN collectedEnd DATE ) BEGIN DECLARE disbursalCursor DATE; DECLARE collectedCursor DATE; DECLARE tableDateSuffix VARCHAR(8); DECLARE tableName VARCHAR(64); DECLARE query TEXT;
SET collectedCursor = collectedStart;
WHILE collectedCursor <= collectedEnd DO
SET @lastDayOfMonth = LAST_DAY(collectedCursor); SET tableDateSuffix = DATE_FORMAT(@lastDayOfMonth, '%Y%m%d'); SET tableName = CONCAT('loanbook', tableDateSuffix);
SET disbursalCursor = disbursalStart;
WHILE disbursalCursor <= disbursalEnd DO
SET @disbursalMonthStr = DATE_FORMAT(disbursalCursor, '%M %Y'); SET @collectedMonthStr = DATE_FORMAT(collectedCursor, '%M %Y');
SET @query = CONCAT(' SELECT "', @disbursalMonthStr, '" AS DisbursalMonth, "', @collectedMonthStr, '" AS CollectedMonth, "', tableName, '" AS TableName, SUM(CASE WHEN `Disbursal Month Year` = ? THEN `Disbursal Amount` ELSE 0 END) AS DisbursalAmount, SUM(CASE WHEN `Collected Month` = ? THEN `Collected Amount` ELSE 0 END) AS CollectedAmount, SUM(CASE WHEN `Collected Month` = ? THEN `Interest Collected_ipc` ELSE 0 END) AS InterestIncome, SUM(CASE WHEN `Disbursal Month Year` = ? THEN PF ELSE 0 END) AS PFINCOME, SUM(CASE WHEN `Collected Month` = ? THEN `Late Fee Collected_ipc` ELSE 0 END) AS LateFee, SUM(CASE WHEN WriteOffFlag = "YES" THEN Loan_POS ELSE 0 END) AS WriteOffAmount, SUM(CASE WHEN WriteOffPaymentFlag = "YES" AND `Collected Month` = ? THEN `Principal Collected_ipc` ELSE 0 END) AS WriteoffPrincipalCollection, SUM(CASE WHEN WriteOffPaymentFlag = "YES" AND `Collected Month` = ? THEN `Collected Amount` ELSE 0 END) AS WriteoffTotalCollection, SUM(CASE WHEN WriteOffDate = "" THEN Loan_POS ELSE 0 END) AS AUM FROM ', tableName);
PREPARE stmt FROM @query; EXECUTE stmt USING @disbursalMonthStr, @collectedMonthStr, @collectedMonthStr, @disbursalMonthStr, @collectedMonthStr, @collectedMonthStr, @collectedMonthStr; DEALLOCATE PREPARE stmt;
SET disbursalCursor = DATE_ADD(disbursalCursor, INTERVAL 1 MONTH); END WHILE;
SET collectedCursor = DATE_ADD(collectedCursor, INTERVAL 1 MONTH); END WHILE; END
CREATE DEFINER=`admin`@`%` PROCEDURE `grant_loanbook_access`() BEGIN DECLARE done INT DEFAULT 0; DECLARE tbl VARCHAR(255);
DECLARE cur CURSOR FOR SELECT table_name FROM information_schema.tables WHERE table_schema = 'ramfin' AND table_name LIKE 'loanbook%';
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
OPEN cur;
loop_tables: LOOP FETCH cur INTO tbl; IF done THEN LEAVE loop_tables; END IF;
SET @sql = CONCAT('GRANT SELECT ON ramfin.', tbl, " TO 'view_ramfinuser'@'%'"); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt; END LOOP;
CLOSE cur; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `leads_not_completed_status_report_data`( IN from_date varchar(20), IN to_date varchar(20)) BEGIN SELECT IFNULL(Date, 'TOTAL') AS Date, SUM(Enter_Name) AS Enter_Name, SUM(Enter_PAN) AS Enter_PAN, SUM(Confirm_PAN) AS Confirm_PAN, SUM(Adh_Digi_select) AS Adh_Digi_select, SUM(EnterAadharActivity) AS EnterAadharActivity, SUM(VerifyAadharActivity) AS VerifyAadharActivity, SUM(SelfieActivity) AS SelfieActivity, SUM(LoanPurpose) AS LoanPurpose, SUM(LoanAmount_Activity) AS LoanAmount_Activity, SUM(Personal_info_Activity) AS Personal_info_Activity, SUM(MaritalActivity) AS MaritalActivity, SUM(Education) AS Education, SUM(EmploymentDetails_Activity) AS EmploymentDetails_Activity, SUM(ModeofPayment) AS ModeofPayment, SUM(CompanyName) AS CompanyName, SUM(IndustryActivity) AS IndustryActivity, SUM(DesignationActivity) AS DesignationActivity, SUM(MonthlyIncome) AS MonthlyIncome, SUM(WorkExperience) AS WorkExperience, SUM(DateOfSalaryActivity) AS DateOfSalaryActivity, SUM(YourResidenceActivity) AS YourResidenceActivity, SUM(EnterAddress) AS EnterAddress, SUM(ConfirmAddress) AS ConfirmAddress, SUM(Summary) AS Summary, SUM(LinkBankFinBoxUpdatedActivity) AS LinkBankFinBoxUpdatedActivity, SUM(LoanApprovedActivity) AS LoanApprovedActivity, SUM(ReferenceActivityTwo) AS ReferenceActivityTwo, SUM(BankDetailsActivity) AS BankDetailsActivity, SUM(RecordVideoActivity) AS RecordVideoActivity, SUM(EmandateActivity) AS EmandateActivity, SUM(PennyDrop) AS PennyDrop, SUM(BankSelectionActivity) AS BankSelectionActivity FROM ( SELECT IFNULL(DATE_FORMAT(createdDate, '%Y-%m-%d'), 'TOTAL') AS Date, COUNT(DISTINCT CASE WHEN step = 'Common 1/3' THEN customerID END) AS Enter_Name, COUNT(DISTINCT CASE WHEN step = 'Common 2/3' THEN customerID END) AS Enter_PAN, COUNT(DISTINCT CASE WHEN step = 'Common 3/3' THEN customerID END) AS Confirm_PAN, COUNT(DISTINCT CASE WHEN step = 'Long 1/29' THEN customerID END) AS Adh_Digi_select, COUNT(DISTINCT CASE WHEN step = 'Long 2/29' THEN customerID END) AS EnterAadharActivity, COUNT(DISTINCT CASE WHEN step = 'Long 3/29' THEN customerID END) AS VerifyAadharActivity, COUNT(DISTINCT CASE WHEN step = 'Long 4/29' THEN customerID END) AS SelfieActivity, COUNT(DISTINCT CASE WHEN step = 'Long 5/29' THEN customerID END) AS LoanPurpose, COUNT(DISTINCT CASE WHEN step = 'Long 6/29' THEN customerID END) AS LoanAmount_Activity, COUNT(DISTINCT CASE WHEN step = 'Long 7/29' THEN customerID END) AS Personal_info_Activity, COUNT(DISTINCT CASE WHEN step = 'Long 8/29' THEN customerID END) AS MaritalActivity, COUNT(DISTINCT CASE WHEN step = 'Long 9/29' THEN customerID END) AS Education, COUNT(DISTINCT CASE WHEN step = 'Long 10/29' THEN customerID END) AS EmploymentDetails_Activity, COUNT(DISTINCT CASE WHEN step = 'Long 11/29' THEN customerID END) AS ModeofPayment, COUNT(DISTINCT CASE WHEN step = 'Long 12/29' THEN customerID END) AS CompanyName, COUNT(DISTINCT CASE WHEN step = 'Long 13/29' THEN customerID END) AS IndustryActivity, COUNT(DISTINCT CASE WHEN step = 'Long 14/29' THEN customerID END) AS DesignationActivity, COUNT(DISTINCT CASE WHEN step = 'Long 15/29' THEN customerID END) AS MonthlyIncome, COUNT(DISTINCT CASE WHEN step = 'Long 16/29' THEN customerID END) AS WorkExperience, COUNT(DISTINCT CASE WHEN step = 'Long 17/29' THEN customerID END) AS DateOfSalaryActivity, COUNT(DISTINCT CASE WHEN step = 'Long 18/29' THEN customerID END) AS YourResidenceActivity, COUNT(DISTINCT CASE WHEN step = 'Long 19/29' THEN customerID END) AS EnterAddress, COUNT(DISTINCT CASE WHEN step = 'Long 20/29' THEN customerID END) AS ConfirmAddress, COUNT(DISTINCT CASE WHEN step = 'Long 21/29' THEN customerID END) AS Summary, COUNT(DISTINCT CASE WHEN step = 'Long 22/29' THEN customerID END) AS LinkBankFinBoxUpdatedActivity, COUNT(DISTINCT CASE WHEN step = 'Long 23/29' THEN customerID END) AS LoanApprovedActivity, COUNT(DISTINCT CASE WHEN step = 'Long 24/29' THEN customerID END) AS ReferenceActivityTwo, COUNT(DISTINCT CASE WHEN step = 'Long 25/29' THEN customerID END) AS BankDetailsActivity, COUNT(DISTINCT CASE WHEN step = 'Long 26/29' THEN customerID END) AS RecordVideoActivity, COUNT(DISTINCT CASE WHEN step = 'Long 27/29' THEN customerID END) AS EmandateActivity, COUNT(DISTINCT CASE WHEN step = 'Long 28/29' THEN customerID END) AS PennyDrop, COUNT(DISTINCT CASE WHEN step = 'Long 29/29' THEN customerID END) AS BankSelectionActivity FROM customerApp WHERE createdDate >= from_date AND createdDate < to_date GROUP BY DATE_FORMAT(createdDate, '%Y-%m-%d') WITH ROLLUP ) AS subquery GROUP BY Date;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `log_shifting_api_req_res_log`(IN input_date DATE) BEGIN DECLARE table_name VARCHAR(64); DECLARE end_datetime DATETIME; DECLARE create_query TEXT; DECLARE delete_query TEXT;
SET table_name = CONCAT('api_req_res_logs_', DATE_FORMAT(input_date, '%Y_%m_%d'));
SET @create_query = CONCAT( 'CREATE TABLE ', table_name, ' AS SELECT * FROM api_req_res_logs WHERE DATE(created_at) = \'', input_date, '\'' );
SET end_datetime = CONCAT(input_date, ' 23:59:59'); SET @delete_query = CONCAT( 'DELETE FROM api_req_res_logs WHERE created_at <= \'', end_datetime, '\'' );
PREPARE stmt_create FROM @create_query; EXECUTE stmt_create; DEALLOCATE PREPARE stmt_create;
PREPARE stmt_delete FROM @delete_query; EXECUTE stmt_delete; DEALLOCATE PREPARE stmt_delete; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `mom_repeat_report`(IN from_date VARCHAR(20)) BEGIN SELECT DATE_FORMAT(t1.disbursalDate, '%b %Y') AS Month, COUNT(DISTINCT t2.customerID) AS 'Reloan_Number', COUNT(DISTINCT CASE WHEN TIMESTAMPDIFF(MONTH, t2.disbursalDate, t1.disbursalDate) = 1 THEN t2.customerID ELSE NULL END) AS 'Prior_1_month', COUNT(DISTINCT CASE WHEN TIMESTAMPDIFF(MONTH, t2.disbursalDate, t1.disbursalDate) = 2 THEN t2.customerID ELSE NULL END) AS 'Prior_2_months', COUNT(DISTINCT CASE WHEN TIMESTAMPDIFF(MONTH, t2.disbursalDate, t1.disbursalDate) BETWEEN 3 AND 6 THEN t2.customerID ELSE NULL END) AS 'Prior_3_to_6_months', COUNT(DISTINCT CASE WHEN TIMESTAMPDIFF(MONTH, t2.disbursalDate, t1.disbursalDate) BETWEEN 7 AND 12 THEN t2.customerID ELSE NULL END) AS 'Prior_7_to_12_months', COUNT(DISTINCT CASE WHEN TIMESTAMPDIFF(MONTH, t2.disbursalDate, t1.disbursalDate) > 12 THEN t2.customerID ELSE NULL END) AS 'Before_13_months' FROM loan t1 LEFT JOIN loan t2 ON t1.customerID = t2.customerID AND t1.loanID <> t2.loanID WHERE t1.disbursalDate >= from_date GROUP BY DATE_FORMAT(t1.disbursalDate, '%Y-%m') ORDER BY t1.disbursalDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `not_active_customer`( IN start_date DATE, IN end_date DATE ) BEGIN SELECT c.customerID, last_closed_loan.last_repayment_date, last_closed_loan.loanAmtApproved, loan_count.loan_frequency FROM customer c INNER JOIN (
SELECT col.customerID, MAX(col.collectedDate) AS last_repayment_date, col.leadID, a.loanAmtApproved FROM collection col INNER JOIN loan l ON col.leadID = l.leadID AND col.customerID = l.customerID INNER JOIN approval a ON l.leadID = a.leadID AND l.customerID = a.customerID WHERE col.status = 'Closed' AND col.collectionStatus='Approved'
AND DATEDIFF(col.collectedDate, a.repayDate) <= 2
AND col.collectedDate BETWEEN start_date AND end_date
AND DATEDIFF(CURDATE(), col.collectedDate) >= 60 GROUP BY col.customerID, a.loanAmtApproved HAVING
last_repayment_date = ( SELECT MAX(col2.collectedDate) FROM collection col2 INNER JOIN loan l2 ON col2.leadID = l2.leadID AND col2.customerID = l2.customerID WHERE col2.customerID = col.customerID AND col2.status = 'Closed' AND col2.collectionStatus='Approved' ) ) last_closed_loan ON c.customerID = last_closed_loan.customerID INNER JOIN (
SELECT l.customerID, COUNT(DISTINCT l.loanID) AS loan_frequency FROM loan l GROUP BY l.customerID ) loan_count ON c.customerID = loan_count.customerID WHERE
NOT EXISTS ( SELECT 1 FROM leads ld3 INNER JOIN loan l3 ON ld3.leadID = l3.leadID AND ld3.customerID = l3.customerID WHERE ld3.customerID = c.customerID AND ld3.createdDate > last_closed_loan.last_repayment_date AND ld3.leadID != last_closed_loan.leadID AND ld3.status IN ('Approved', 'Disbursed', 'Closed') ) ORDER BY last_closed_loan.last_repayment_date DESC; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `NotCompletedReport`( IN start_date DATE, IN end_date DATE ) BEGIN SELECT ca.customerID AS userID, MAX(ca.utmSource) AS 'Source', ca.name AS Name, ca.mobile AS Mobile, ca.email AS Email, ca.loanRequeried AS 'Loan Required Amount', ca.monthlyIncome AS 'Monthly Income', ca.city AS City, ca.pincode, CASE WHEN MAX(ldd.modelName IS NOT NULL AND ldd.android_version IS NOT NULL AND ldd.modelName <> '' AND ldd.android_version <> '') THEN 'Android' ELSE 'Web' END AS 'Device Type', CASE WHEN MAX(LOCATE('Repeat', ca.step)) > 0 THEN 'Long' WHEN MAX(LOCATE('Short', ca.step)) > 0 THEN 'Short' WHEN MAX(LOCATE('Long', ca.step)) > 0 THEN 'Long' WHEN MAX(LOCATE('Common', ca.step)) > 0 THEN 'Common' WHEN MAX(LOCATE('Existing', ca.step)) > 0 THEN 'Existing' WHEN MAX(LOCATE('1_page', ca.step)) > 0 THEN '1_page' WHEN MAX(LOCATE('apps', ca.step)) > 0 THEN 'Old App' WHEN (NOT MAX(LOCATE('APP_V', ca.utmsource)) AND COALESCE(MAX(ca.step), '') = '') THEN 'Not Captured' ELSE 'Web' END AS 'Stage', MAX(ca.createdDate) AS 'Date' FROM customerApp ca LEFT JOIN login_device_detail ldd ON ca.mobile = ldd.mobile WHERE ca.createdDate BETWEEN start_date AND end_date GROUP BY ca.customerID, ca.name, ca.mobile, ca.email, ca.loanRequeried, ca.monthlyIncome, ca.city, ca.pincode; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `PartPayment`( IN startDate DATE, IN endDate DATE ) BEGIN WITH LastSettlement AS ( SELECT loanNo, MAX(CASE WHEN status = 'Part Payment' THEN collectedDate ELSE NULL END) AS lastSettlementDate FROM collection GROUP BY loanNo ), TotalCollected AS ( SELECT col.loanNo, SUM(col.collectedAmount) AS totalCollectedAmount FROM collection col JOIN LastSettlement ls ON col.loanNo = ls.loanNo WHERE col.collectionStatus = 'Approved' AND col.collectedMode <> 'Waive Off' AND col.collectedDate <= ls.lastSettlementDate GROUP BY col.loanNo ) SELECT l.loanNo AS 'Loan No', ld.customerID AS 'CustomerID', ld.leadID AS 'leadID', c.name AS 'Name', MAX(CASE WHEN cf.followType = 'Call' THEN cf.createdDate ELSE NULL END) AS 'Call Date', MAX(CASE WHEN cf.followType = 'Call' THEN cf.followType ELSE NULL END) AS 'Contact Type', MAX(cf.statusType) AS 'Status', MAX(CASE WHEN cf.statusType = 'PTP' THEN cf.statusTypeDate ELSE NULL END) AS 'PTP Date', MAX(cf.remark) AS 'Remark', l.disbursalAmount AS 'Loan Amount', a.tenure AS 'Tenure', a.roi AS 'ROI', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay Amount', a.repayDate AS 'Repay Date', COALESCE(tc.totalCollectedAmount, 0) AS 'Total Collected Amount', MAX(col.status) AS 'Collection Status', l.disbursalDate AS 'Date', MAX(addr.address) AS 'Address', MONTHNAME(l.disbursalDate) AS 'Disbursal Month', ld.fbLeads AS 'Loan Type', MAX(u.name) AS 'Credited By', lf.LoanFrequency AS 'Loan Frequency', c.employeeType AS 'Employee Type', MAX(cf.createdDate) AS 'Max Follow-up Date' FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN customer c ON ld.customerID = c.customerID LEFT JOIN collectionFollowup cf ON ld.leadID = cf.leadID LEFT JOIN collection col ON l.loanNo = col.loanNo LEFT JOIN address addr ON c.customerID = addr.customerID LEFT JOIN users u ON a.creditedby = u.userID JOIN ( SELECT customerID, COUNT(DISTINCT loanNo) AS LoanFrequency FROM loan WHERE status = 'Disbursed' GROUP BY customerID ) lf ON c.customerID = lf.customerID LEFT JOIN TotalCollected tc ON l.loanNo = tc.loanNo WHERE a.repayDate BETWEEN startDate AND endDate AND l.status = 'Disbursed' AND col.status = 'Part Payment' GROUP BY l.loanNo, ld.customerID, ld.leadID, c.name, l.disbursalAmount, a.tenure, a.roi, a.repayDate, l.disbursalDate, ld.fbLeads, lf.LoanFrequency, c.employeeType, tc.totalCollectedAmount ORDER BY a.repayDate; END
DELIMITER $$
CREATE DEFINER=`admin`@`%` PROCEDURE `payday_pending_emi_report`( IN p_start_date DATE, IN p_end_date DATE ) BEGIN
DECLARE v_secret_key VARCHAR(500); DECLARE v_iv VARCHAR(100); SET sql_mode = (SELECT REPLACE(@@sql_mode,'ONLY_FULL_GROUP_BY','')); SET block_encryption_mode = 'aes-256-cbc';
-- ------------------------------------------------------- -- Fetch encryption key & IV from the keys table -- ------------------------------------------------------- SELECT secret_key, iv INTO v_secret_key, v_iv FROM encryption_keys WHERE key_name = 'mobile_encryption' AND is_active = 1 LIMIT 1; -- Guard: abort if no active key found IF v_secret_key IS NULL OR v_iv IS NULL THEN SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Encryption key not found or inactive in encryption_keys table'; END IF;
SELECT
COALESCE( ( SELECT name FROM users WHERE userID = leads.alloUID LIMIT 1 ), '') AS 'Allocated Agent',
leads.leadID AS 'Lead Id',
loan.loanNo AS 'Loan No.',
leads.purpose AS 'Loan Purpose',
leads.state AS State,
leads.city AS City,
customer.name AS Name,
customer.gender AS Gender,
customer.email AS Email,
TO_BASE64( AES_ENCRYPT( customer.mobile, UNHEX(v_secret_key), UNHEX(v_iv) )) AS Mobile,
customer.dob AS DOB,
(YEAR(CURDATE()) - YEAR(customer.dob)) AS Age,
customer.pancard AS 'PAN No.',
( SELECT COUNT(*) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status = 'paid' AND is_deleted = 0 ) AS 'Paid EMI',
( SELECT COUNT(*) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status = 'due' AND dueDate >= CURDATE() AND is_deleted = 0 ) AS 'Due EMI',
( SELECT COUNT(*) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status = 'due' AND dueDate < CURDATE() AND is_deleted = 0 ) + ( SELECT COUNT(*) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status = 'partially-paid' AND is_deleted = 0 ) AS 'OverDue EMI',
CASE
WHEN ( SELECT SUM( CASE WHEN DATEDIFF(CURDATE(), dueDate) > 0 THEN DATEDIFF(CURDATE(), dueDate) ELSE 0 END ) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ) BETWEEN 1 AND 30 THEN '1-30 Bucket 1'
WHEN ( SELECT SUM( CASE WHEN DATEDIFF(CURDATE(), dueDate) > 0 THEN DATEDIFF(CURDATE(), dueDate) ELSE 0 END ) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ) BETWEEN 31 AND 60 THEN '31-60 Bucket 2'
WHEN ( SELECT SUM( CASE WHEN DATEDIFF(CURDATE(), dueDate) > 0 THEN DATEDIFF(CURDATE(), dueDate) ELSE 0 END ) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ) BETWEEN 61 AND 90 THEN '61-90 Bucket 3'
WHEN ( SELECT SUM( CASE WHEN DATEDIFF(CURDATE(), dueDate) > 0 THEN DATEDIFF(CURDATE(), dueDate) ELSE 0 END ) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ) > 90 THEN '91+ Bucket 4'
ELSE 'No Bucket'
END AS 'DPD Bucket',
loan.disbursalAmount AS 'Loan Amount',
( SELECT amountPayable FROM equated_monthly_installments WHERE leadID = leads.leadID AND is_deleted = 0 LIMIT 1 ) AS 'EMI Amount',
COALESCE( ( SELECT SUM(amountPayable - COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND dueDate <= CURDATE() AND status != 'paid' AND is_deleted = 0 ), 0) AS 'Due Date Repay Amount',
COALESCE( ( SELECT SUM( CASE WHEN DATEDIFF(CURDATE(), dueDate) > 0 THEN DATEDIFF(CURDATE(), dueDate) ELSE 0 END ) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ), 0) AS 'Days Past Due',
customer.employeeType AS 'Employee Type',
leads.fbLeads AS 'Loan Type',
DATE_FORMAT(loan.disbursalDate, '%d-%M-%Y') AS 'Disbursed Date',
DATE_FORMAT(loan.disbursalDate, '%M-%Y') AS 'Disbursed Month',
DATE_FORMAT(approval.repayDate, '%d-%M-%Y') AS 'Repay Date',
DATE_FORMAT(approval.repayDate, '%M-%Y') AS 'Repay Month',
COALESCE( ( SELECT SUM(amountPayable - COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ), 0) AS 'Remaining Collection',
COALESCE( ( SELECT SUM(COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND is_deleted = 0 ), 0) AS 'Total Collection',
COALESCE( ( SELECT SUM(COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND is_deleted = 0 ), 0) AS 'EMI Collection',
CONCAT(COALESCE(credits.tenure, '0'), ' Months') AS Tenure,
CONCAT(COALESCE(credits.tenure, '0'), ' Months') AS 'Loan Tenure',
approval.roi AS ROI,
COALESCE( ( SELECT name FROM users WHERE userID = approval.creditedBy LIMIT 1 ), 'Unknown') AS 'Credit By',
leads.createdDate AS Date,
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = customer.customerID AND type = 'Permanent' LIMIT 1 ), '') AS 'Permanent Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = customer.customerID AND type = 'Current Address' LIMIT 1 ), '') AS 'Current Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = customer.customerID AND type = 'Rent' LIMIT 1 ), '') AS 'Rent Address',
COALESCE( ( SELECT CONCAT_WS( ' ', employerName, empEmail, empDesignation, address, city, state, pincode ) FROM employer WHERE customerID = customer.customerID LIMIT 1 ), '') AS 'Employment Detail',
( SELECT COUNT(*) FROM `reference` WHERE customerID = customer.customerID AND reference_verify = '0' ) AS References_Count
FROM customer
JOIN leads ON customer.customerID = leads.customerID
JOIN approval ON leads.leadID = approval.leadID
JOIN loan ON loan.leadID = leads.leadID
JOIN credits ON credits.leadID = leads.leadID
JOIN ( SELECT * FROM equated_monthly_installments e WHERE ( e.status = 'due' OR e.status = 'partially-paid' ) AND e.is_deleted = 0 ) AS emi ON leads.leadID = emi.leadID
WHERE leads.status IN ('Disbursed', 'Part Payment')
AND leads.productID = 1
AND loan.payout_status = 2
AND emi.dueDate BETWEEN p_start_date AND p_end_date
AND customer.customerID NOT IN ( SELECT customer_dnd.customerID FROM customer_dnd WHERE expiry_date >= CURDATE() AND is_deleted = '0' AND customer_dnd.id = ( SELECT MAX(cd.id) FROM customer_dnd cd WHERE cd.customerID = customer_dnd.customerID ) )
ORDER BY leads.leadID DESC;
END $$
DELIMITER ;
DELIMITER $$
