COALESCE( ( SELECT SUM(amountPayable - COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND dueDate <= CURDATE() AND status != 'paid' AND is_deleted = 0 ), 0) AS 'Due Date Repay Amount',
COALESCE( ( SELECT SUM( CASE WHEN DATEDIFF(CURDATE(), dueDate) > 0 THEN DATEDIFF(CURDATE(), dueDate) ELSE 0 END ) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ), 0) AS 'Days Past Due',
customer.employeeType AS 'Employee Type',
leads.fbLeads AS 'Loan Type',
DATE_FORMAT(loan.disbursalDate, '%d-%M-%Y') AS 'Disbursed Date',
DATE_FORMAT(loan.disbursalDate, '%M-%Y') AS 'Disbursed Month',
DATE_FORMAT(approval.repayDate, '%d-%M-%Y') AS 'Repay Date',
DATE_FORMAT(approval.repayDate, '%M-%Y') AS 'Repay Month',
COALESCE( ( SELECT SUM(amountPayable - COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND status != 'paid' AND is_deleted = 0 ), 0) AS 'Remaining Collection',
COALESCE( ( SELECT SUM(COALESCE(paymentReceived, 0)) FROM equated_monthly_installments WHERE leadID = leads.leadID AND is_deleted = 0 ), 0) AS 'Total Collection',
