COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = customer.customerID AND type = 'Current Address' LIMIT 1 ), '') AS 'Current Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = customer.customerID AND type = 'Rent' LIMIT 1 ), '') AS 'Rent Address',
