CREATE DEFINER=`admin`@`%` PROCEDURE `payday_pending_report`(IN p_start_date DATE, IN p_end_date DATE) BEGIN
DECLARE today DATE DEFAULT CURDATE(); DECLARE v_secret_key VARCHAR(500); DECLARE v_iv VARCHAR(100); SET block_encryption_mode = 'aes-256-cbc';
-- ------------------------------------------------------- -- Fetch encryption key & IV from the keys table -- ------------------------------------------------------- SELECT secret_key, iv INTO v_secret_key, v_iv FROM encryption_keys WHERE key_name = 'mobile_encryption' AND is_active = 1 LIMIT 1; -- Guard: abort if no active key found IF v_secret_key IS NULL OR v_iv IS NULL THEN SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Encryption key not found or inactive in encryption_keys table'; END IF;
SELECT COALESCE((SELECT name FROM users WHERE userID = l.alloUID LIMIT 1), '') AS 'Allocated Agent',
l.leadID AS 'Lead Id',
loan.loanNo AS 'Loan No.',
l.purpose AS 'Loan Purpose',
l.state AS State,
l.city AS City,
c.name AS Name,
c.gender AS Gender,
c.email AS Email,
TO_BASE64( AES_ENCRYPT( c.mobile, UNHEX(v_secret_key), UNHEX(v_iv) )) AS Mobile,
c.dob AS DOB,
(YEAR(CURDATE()) - YEAR(c.dob)) AS Age,
c.pancard AS 'PAN No.',
loan.disbursalAmount AS 'Loan Amount',
ROUND( loan.disbursalAmount + ( loan.disbursalAmount * (a.roi / 100) * DATEDIFF(a.repayDate, loan.disbursalDate) ), 2) AS 'Due Date Repay Amount',
ROUND( loan.disbursalAmount + ( loan.disbursalAmount * (a.roi / 100) * DATEDIFF(CURDATE(), loan.disbursalDate) ), 2) AS 'Repay Amount',
DATEDIFF(CURDATE(), a.repayDate) AS 'Days Past Due',
c.employeeType AS 'Employee Type',
l.fbLeads AS 'Loan Type',
( SELECT COUNT(*) FROM leads l2 WHERE l2.customerID = c.customerID AND l2.status IN ('Closed', 'Settlement', 'Disbursed') ) AS 'Loan Frequency',
DATE_FORMAT(loan.disbursalDate, '%d-%M-%Y') AS 'Disbursed Date',
DATE_FORMAT(loan.disbursalDate, '%M-%Y') AS 'Disbursed Month',
DATE_FORMAT(a.repayDate, '%d-%M-%Y') AS 'Repay Date',
DATE_FORMAT(a.repayDate, '%M-%Y') AS 'Repay Month',
( ROUND( loan.disbursalAmount + ( loan.disbursalAmount * (a.roi / 100) * DATEDIFF(CURDATE(), loan.disbursalDate) ), 2) - COALESCE( ( SELECT SUM(collectedAmount) FROM collection WHERE leadID = loan.leadID AND collectionStatus = 'Approved' ), 0) ) AS 'Remaining Collection',
COALESCE( ( SELECT SUM(collectedAmount) FROM collection WHERE leadID = loan.leadID AND collectionStatus = 'Approved' ), 0) AS 'Total Collection',
DATEDIFF(CURDATE(), loan.disbursalDate) AS Tenure,
DATEDIFF(a.repayDate, loan.disbursalDate) AS 'Loan Tenure',
a.roi AS ROI,
COALESCE( ( SELECT name FROM users WHERE userID = a.creditedBy LIMIT 1 ), '') AS 'Credit By',
l.createdDate AS Date,
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = c.customerID AND type NOT IN ('Current Address', 'Rent') LIMIT 1 ), '') AS 'Permanent Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = c.customerID AND type = 'Current Address' LIMIT 1 ), '') AS 'Current Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = c.customerID AND type = 'Rent' LIMIT 1 ), '') AS 'Rent Address',
COALESCE( ( SELECT CONCAT_WS( ' ', employerName, empEmail, empDesignation, address, city, state, pincode ) FROM employer WHERE customerID = c.customerID LIMIT 1 ), '') AS 'Employment Detail',
COALESCE( ( SELECT CONCAT( relation, ': ', name, ' - ', contactNo ) FROM `reference` WHERE customerID = c.customerID AND reference_verify = '0' ORDER BY referenceID LIMIT 1 ), '') AS 'Reference 1',
COALESCE( ( SELECT CONCAT( relation, ': ', name, ' - ', contactNo ) FROM `reference` WHERE customerID = c.customerID AND reference_verify = '0' ORDER BY referenceID LIMIT 1,1 ), '') AS 'Reference 2'
FROM leads l
LEFT JOIN loan ON l.leadID = loan.leadID
LEFT JOIN approval a ON loan.leadID = a.leadID
LEFT JOIN customer c ON l.customerID = c.customerID
WHERE l.status IN ('Disbursed', 'Part Payment') AND l.productID = 2 AND a.repayDate BETWEEN p_start_date AND p_end_date;
END $$
DELIMITER ;
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `payday_pending_report_optimized`( IN startDate DATE, IN endDate DATE ) BEGIN DECLARE today DATE DEFAULT CURDATE(); DECLARE v_secret_key VARCHAR(500); DECLARE v_iv VARCHAR(100);
SET SESSION sql_mode = ''; SET block_encryption_mode = 'aes-256-cbc';
SELECT secret_key, iv INTO v_secret_key, v_iv FROM encryption_keys WHERE key_name = 'mobile_encryption' AND is_active = 1 LIMIT 1;
IF v_secret_key IS NULL OR v_iv IS NULL THEN SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Encryption key not found or inactive'; END IF;
WITH
collection_summary AS ( SELECT leadID, GROUP_CONCAT( CONCAT(collectedAmount, '-', DATE(collectedDate)) ORDER BY createdDate SEPARATOR '\\' ) AS collectionHistory, SUM(collectedAmount) AS totalCollection FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ),
latest_part_payment AS ( SELECT * FROM ( SELECT col.*, ROW_NUMBER() OVER ( PARTITION BY col.leadID ORDER BY col.collectionID DESC ) rn FROM collection col WHERE col.status = 'Part Payment' AND col.collectionStatus = 'Approved' ) t WHERE rn = 1 )
SELECT l.leadID, l.lenderID, ld.name AS lenderName, ln.loanNo, l.purpose, l.state, l.city, c.name AS customerName, c.gender, c.email,
TO_BASE64( AES_ENCRYPT( c.mobile, UNHEX(v_secret_key), UNHEX(v_iv) ) ) AS mobile,
c.dob, TIMESTAMPDIFF(YEAR, c.dob, CURDATE()) AS age, c.pancard, ln.disbursalAmount, len.name AS lender_name,
(ln.disbursalAmount + ((ln.disbursalAmount * (ap.roi / 100)) * DATEDIFF(ap.repayDate, ln.disbursalDate)) ) AS Due_Date_Repay_Amount,
-- ✅ MAIN LOGIC (only replaced subquery with join) CASE WHEN l.ipc = 1 THEN CASE WHEN l.status = 'Disbursed' THEN CASE WHEN CURDATE() <= ap.repayDate THEN ln.disbursalAmount + (ln.disbursalAmount * (ap.roi / 100) * DATEDIFF(CURDATE(), ln.disbursalDate)) ELSE ln.disbursalAmount + (ln.disbursalAmount * (ap.roi / 100) * (DATEDIFF(ap.repayDate, ln.disbursalDate) + DATEDIFF(CURDATE(), ap.repayDate))) + (ln.disbursalAmount * (0.1 / 100) * DATEDIFF(CURDATE(), ap.repayDate)) + (500 + (500 * 0.18)) END
WHEN l.status = 'Part Payment' THEN COALESCE( ( lpp.closing_balance + (lpp.principal_amount * (ap.roi / 100) * CASE WHEN CURDATE() <= ap.repayDate THEN DATEDIFF(CURDATE(), lpp.collectedDate) ELSE DATEDIFF(ap.repayDate, lpp.collectedDate) + DATEDIFF(CURDATE(), ap.repayDate) END ) + CASE WHEN CURDATE() > ap.repayDate AND (lpp.penality_charge IS NULL OR lpp.penality_charge = 0) THEN (lpp.principal_amount * (0.1 / 100) * DATEDIFF(CURDATE(), ap.repayDate)) + (500 + (500 * 0.18)) ELSE 0 END ), ln.disbursalAmount + (ln.disbursalAmount * (ap.roi / 100) * DATEDIFF(CURDATE(), ln.disbursalDate)) )
ELSE ln.disbursalAmount END
ELSE ( ln.disbursalAmount + (ln.disbursalAmount * (ap.roi / 100) * CASE WHEN CURDATE() > ap.repayDate THEN DATEDIFF(ap.repayDate, ln.disbursalDate) ELSE DATEDIFF(CURDATE(), ln.disbursalDate) END ) + CASE WHEN CURDATE() > ap.repayDate THEN ln.disbursalAmount * (1.25 / 100) * DATEDIFF(CURDATE(), ap.repayDate) ELSE 0 END ) - COALESCE(cs.totalCollection, 0) END AS Repay_Amount,
DATEDIFF(CURDATE(), ap.repayDate) AS dayPassDue, c.employeeType AS employmentType, l.fbLeads AS loanType,
DATE_FORMAT(ln.disbursalDate, '%d %M %Y') AS disbursedDate, DATE_FORMAT(ap.repayDate, '%d %M %Y') AS repayDate,
cs.collectionHistory, COALESCE(cs.totalCollection, 0) AS totalCollection,
ap.roi, l.createdDate
FROM customer c JOIN leads l ON c.customerID = l.customerID JOIN approval ap ON l.leadID = ap.leadID JOIN loan ln ON l.leadID = ln.leadID
LEFT JOIN lender ld ON ld.lenderID = l.lenderID LEFT JOIN lender len ON len.lenderID = l.lenderID
LEFT JOIN collection_summary cs ON cs.leadID = ln.leadID
LEFT JOIN latest_part_payment lpp ON lpp.leadID = l.leadID
WHERE l.status IN ('Disbursed','Part Payment') AND l.productID = 2 AND ap.loanType = 0 AND ln.payout_status = 2 AND ap.repayDate BETWEEN startDate AND endDate
GROUP BY l.leadID ORDER BY l.leadID DESC;
END
DELIMITER $$
