ROUND( loan.disbursalAmount + ( loan.disbursalAmount * (a.roi / 100) * DATEDIFF(CURDATE(), loan.disbursalDate) ), 2) AS 'Repay Amount',
DATEDIFF(CURDATE(), a.repayDate) AS 'Days Past Due',
