( SELECT COUNT(*) FROM leads l2 WHERE l2.customerID = c.customerID AND l2.status IN ('Closed', 'Settlement', 'Disbursed') ) AS 'Loan Frequency',
DATE_FORMAT(loan.disbursalDate, '%d-%M-%Y') AS 'Disbursed Date',
DATE_FORMAT(loan.disbursalDate, '%M-%Y') AS 'Disbursed Month',
DATE_FORMAT(a.repayDate, '%d-%M-%Y') AS 'Repay Date',
DATE_FORMAT(a.repayDate, '%M-%Y') AS 'Repay Month',
( ROUND( loan.disbursalAmount + ( loan.disbursalAmount * (a.roi / 100) * DATEDIFF(CURDATE(), loan.disbursalDate) ), 2) - COALESCE( ( SELECT SUM(collectedAmount) FROM collection WHERE leadID = loan.leadID AND collectionStatus = 'Approved' ), 0) ) AS 'Remaining Collection',
COALESCE( ( SELECT SUM(collectedAmount) FROM collection WHERE leadID = loan.leadID AND collectionStatus = 'Approved' ), 0) AS 'Total Collection',
