COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = c.customerID AND type NOT IN ('Current Address', 'Rent') LIMIT 1 ), '') AS 'Permanent Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = c.customerID AND type = 'Current Address' LIMIT 1 ), '') AS 'Current Address',
COALESCE( ( SELECT CONCAT_WS( ' ', address, city, state, pincode, landmark ) FROM address WHERE customerID = c.customerID AND type = 'Rent' LIMIT 1 ), '') AS 'Rent Address',
COALESCE( ( SELECT CONCAT_WS( ' ', employerName, empEmail, empDesignation, address, city, state, pincode ) FROM employer WHERE customerID = c.customerID LIMIT 1 ), '') AS 'Employment Detail',
COALESCE( ( SELECT CONCAT( relation, ': ', name, ' - ', contactNo ) FROM `reference` WHERE customerID = c.customerID AND reference_verify = '0' ORDER BY referenceID LIMIT 1 ), '') AS 'Reference 1',
COALESCE( ( SELECT CONCAT( relation, ': ', name, ' - ', contactNo ) FROM `reference` WHERE customerID = c.customerID AND reference_verify = '0' ORDER BY referenceID LIMIT 1,1 ), '') AS 'Reference 2'
FROM leads l
