DELIMITER $$
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE pending_collection_summary_report( IN p_start_date DATE, IN p_end_date DATE ) BEGIN
WITH month_offsets AS ( SELECT -2 AS month_offset UNION ALL SELECT -1 UNION ALL SELECT 0 UNION ALL SELECT 1 UNION ALL SELECT 2 )
SELECT DATE_FORMAT( DATE_ADD(p_start_date, INTERVAL mo.month_offset MONTH), '%Y-%m' ) AS 'Month',
(total_data.total_cases - IFNULL(ap_data.ap_cases, 0)) AS 'Loan Cases',
ROUND( total_data.total_loan_amount - IFNULL(ap_data.ap_loan_amount, 0) ) AS 'Loan Amount',
CONCAT( CASE WHEN total_data.total_loan_amount != 0 THEN ROUND( ( ( total_data.total_loan_amount - IFNULL(ap_data.ap_loan_amount, 0) ) * 100 ) / total_data.total_loan_amount, 2) ELSE 0 END, '%' ) AS 'Loan Percentage',
(total_data.ct - IFNULL(ap_data.ap_repay_cases, 0)) AS 'Repay Cases',
ROUND(IFNULL(pd_data.repay_amount, 0)) AS 'Repay Date Amount',
ROUND( total_data.ami - IFNULL(ap_data.ap_collection_amount, 0) ) AS 'Collection Amount',
CONCAT( CASE WHEN total_data.ami != 0 THEN ROUND( ( ( total_data.ami - IFNULL(ap_data.ap_collection_amount, 0) ) * 100 ) / total_data.ami, 2) ELSE 0 END, '%' ) AS 'Collection Percentage'
FROM month_offsets mo
LEFT JOIN (
SELECT DATE_FORMAT(approval.repayDate, '%Y-%m') AS repay_month,
COUNT(loan.leadID) AS total_cases,
SUM(loan.disbursalAmount) AS total_loan_amount,
SUM( loan.disbursalAmount + ( approval.tenure * ROUND( ( loan.disbursalAmount * (approval.roi / 100) ), 2) ) ) AS ami,
COUNT(*) AS ct
FROM approval
INNER JOIN loan ON approval.leadID = loan.leadID
INNER JOIN leads ON approval.leadID = leads.leadID
WHERE approval.status IN ('Approved', 'Approved Process') AND loan.status = 'Disbursed' AND leads.productID = 2
GROUP BY DATE_FORMAT(approval.repayDate, '%Y-%m')
) total_data ON total_data.repay_month = DATE_FORMAT( DATE_ADD(p_start_date, INTERVAL mo.month_offset MONTH), '%Y-%m' )
LEFT JOIN (
SELECT DATE_FORMAT(approval.repayDate, '%Y-%m') AS repay_month,
COUNT(loan.leadID) AS ap_cases,
SUM(loan.disbursalAmount) AS ap_loan_amount,
COUNT( DISTINCT CASE WHEN leads.status IN ( 'Closed', 'Settlement', 'Part Payment' ) THEN loan.leadID END ) AS ap_repay_cases,
SUM(IFNULL(coll.collection_amount, 0)) AS ap_collection_amount
FROM approval
INNER JOIN loan ON approval.leadID = loan.leadID
INNER JOIN leads ON approval.leadID = leads.leadID
LEFT JOIN ( SELECT leadID, SUM(collectedAmount) AS collection_amount FROM collection WHERE collectionStatus = 'Approved' GROUP BY leadID ) coll ON loan.leadID = coll.leadID
WHERE leads.status IN ( 'Closed', 'Settlement', 'Part Payment' ) AND loan.status = 'Disbursed' AND leads.productID = 2
GROUP BY DATE_FORMAT(approval.repayDate, '%Y-%m')
) ap_data ON ap_data.repay_month = DATE_FORMAT( DATE_ADD(p_start_date, INTERVAL mo.month_offset MONTH), '%Y-%m' )
LEFT JOIN (
SELECT DATE_FORMAT(approval.repayDate, '%Y-%m') AS repay_month,
SUM( loan.disbursalAmount + ( DATEDIFF( approval.repayDate, loan.disbursalDate ) * ROUND( ( loan.disbursalAmount * (approval.roi / 100) ), 2) ) ) AS repay_amount
FROM approval
INNER JOIN loan ON approval.leadID = loan.leadID
INNER JOIN leads ON approval.leadID = leads.leadID
WHERE leads.status = 'Disbursed' AND loan.status = 'Disbursed' AND leads.productID = 2
GROUP BY DATE_FORMAT(approval.repayDate, '%Y-%m')
) pd_data ON pd_data.repay_month = DATE_FORMAT( DATE_ADD(p_start_date, INTERVAL mo.month_offset MONTH), '%Y-%m' )
ORDER BY mo.month_offset;
END $$
DELIMITER ;
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `PendingAccountsProcedure`( IN startDate DATE, IN endDate DATE ) BEGIN SELECT l.loanNo AS 'Loan No', c.name AS 'Name', ld.customerID AS 'CustomerID', ld.leadID AS 'leadID', MAX(CASE WHEN cf.followType = 'Call' THEN cf.createdDate ELSE NULL END) AS 'Call Date', MAX(CASE WHEN cf.followType = 'Call' THEN cf.followType ELSE NULL END) AS 'Contact Type', MAX(cf.statusType) AS 'Status', MAX(CASE WHEN cf.statusType = 'PTP' THEN cf.statusTypeDate ELSE NULL END) AS 'PTP Date', MAX(cf.remark) AS 'Remark', l.disbursalAmount AS 'Loan Amount', a.tenure AS 'Tenure', a.roi AS 'ROI', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay Amount', a.repayDate AS 'Repay Date', ld.status AS 'Status', l.disbursalDate AS 'Date', MAX(addr.address) AS 'Address', MONTHNAME(l.disbursalDate) AS 'Disbursal Month', ld.fbLeads AS 'Loan Type', MAX(u.name) AS 'Credited By', lf.LoanFrequency AS 'Loan Frequency', c.employeeType AS 'Employee Type', MAX(cf.createdDate) AS 'Max Follow-up Date' FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN customer c ON ld.customerID = c.customerID LEFT JOIN collectionFollowup cf ON ld.leadID = cf.leadID LEFT JOIN address addr ON c.customerID = addr.customerID LEFT JOIN users u ON a.creditedby = u.userID JOIN ( SELECT customerID, COUNT(DISTINCT loanNo) AS LoanFrequency FROM loan WHERE status = 'Disbursed' GROUP BY customerID ) lf ON c.customerID = lf.customerID WHERE a.repayDate BETWEEN startDate AND endDate AND (ld.status = 'Disbursed' or ld.status='Part Payment' or ld.status='Blacklisted')
GROUP BY l.loanNo, c.name, ld.customerID, ld.leadID, l.disbursalAmount, a.tenure, a.roi, a.repayDate, l.disbursalDate, ld.fbLeads, ld.status, lf.LoanFrequency, c.employeeType ORDER BY a.repayDate; END
# stored-procedure-RamFin stored-procedure-RamFin
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `rejection`() BEGIN WITH RejectionReasons AS ( SELECT a.creditedBy, DATE_FORMAT(a.createdDate, '%Y-%m') as YearMonth, a.rejectionReason, COUNT(DISTINCT a.leadID) AS ReasonCount, ROW_NUMBER() OVER (PARTITION BY a.creditedBy, DATE_FORMAT(a.createdDate, '%Y-%m') ORDER BY COUNT(DISTINCT a.leadID) DESC) as ReasonRank FROM approval a WHERE a.status LIKE 'Rejected%' AND a.rejectionReason IS NOT NULL AND TRIM(a.rejectionReason) <> '' GROUP BY a.creditedBy, YearMonth, a.rejectionReason ), StatusCounts AS ( SELECT a.creditedBy, DATE_FORMAT(a.createdDate, '%Y-%m') as YearMonth, COUNT(DISTINCT CASE WHEN a.status IN ('Approved', 'Approved Process') THEN a.leadID END) AS TotalApproveProcess, COUNT(DISTINCT CASE WHEN a.status IN ('Rejected', 'Rejected Process') THEN a.leadID END) AS TotalRejectProcess FROM approval a GROUP BY a.creditedBy, YearMonth ) SELECT u.name AS Credit_ManagerWise, sc.YearMonth AS Decision_YearMonth, (sc.TotalApproveProcess + sc.TotalRejectProcess) AS TotalDecision, sc.TotalApproveProcess, sc.TotalRejectProcess, MAX(CASE WHEN rr.ReasonRank = 1 THEN rr.ReasonCount END) AS Bad_Cibil, MAX(CASE WHEN rr.ReasonRank = 2 THEN rr.ReasonCount END) AS Bad_Banking, SUM(CASE WHEN rr.ReasonRank > 2 THEN rr.ReasonCount ELSE 0 END) AS Other_Rejection_Reason FROM users u LEFT JOIN StatusCounts sc ON u.userID = sc.creditedBy LEFT JOIN RejectionReasons rr ON u.userID = rr.creditedBy AND rr.YearMonth = sc.YearMonth GROUP BY u.name, sc.YearMonth HAVING TotalDecision IS NOT NULL ORDER BY u.name, sc.YearMonth; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `repeat_dpd_report`(IN till_date varchar(20)) BEGIN WITH LoanDPD AS (
SELECT
ap.creditedBy,
u.name AS CreditedByName,
DATE_FORMAT(ln.disbursalDate, '%Y-%m') AS DisbursalMonth,
l.fbLeads,
ln.loanNo,
ln.disbursalAmount,
CASE
WHEN ap.repayDate > CURRENT_DATE THEN 'Not Due Yet'
WHEN ap.repayDate <= CURRENT_DATE AND MAX(cl.collectedDate) IS NULL THEN
CASE
WHEN DATEDIFF(CURRENT_DATE, ap.repayDate) > 120 THEN 'DPD >120'
ELSE 'No Payment Received'
END
WHEN MAX(cl.collectedDate) < ap.repayDate THEN 'DPD <0'
WHEN MAX(cl.collectedDate) = ap.repayDate THEN 'DPD 0'
WHEN MAX(cl.collectedDate) > ap.repayDate THEN
CASE
WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 1 AND 7 THEN 'DPD 1-7'
WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 8 AND 30 THEN 'DPD 8-30'
WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 31 AND 60 THEN 'DPD 31-60'
WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 61 AND 90 THEN 'DPD 61-90'
WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 91 AND 120 THEN 'DPD 91-120'
WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) > 120 THEN 'DPD >120'
END
END AS DPDStatus
FROM
loan ln
JOIN
approval ap ON ln.leadID = ap.leadID
JOIN
leads l ON ln.leadID = l.leadID
LEFT JOIN
(SELECT loanNo, MAX(collectedDate) AS collectedDate FROM collection WHERE collectionStatus = 'Approved' GROUP BY loanNo) cl ON ln.loanNo = cl.loanNo
JOIN
users u ON ap.creditedBy = u.userID
GROUP BY
ap.creditedBy, u.name, ln.disbursalDate, l.fbLeads, ln.loanNo, ln.disbursalAmount, ap.repayDate
)
SELECT
CreditedByName AS 'Credit Manager Name',
DisbursalMonth,
COUNT(DISTINCT CASE WHEN fbLeads IN ('Repeat Case') THEN LoanNo END) AS 'Due A/c\'s',
ROUND(SUM(DisbursalAmount), 2) AS 'Repay Amt.',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD <0' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD <0',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD 0' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD 0',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD 1-7' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD 1-7',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD 8-30' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD 8-30',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD 31-60' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD 31-60',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD 61-90' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD 61-90',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD 91-120' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD 91-120',
ROUND(SUM(CASE WHEN DPDStatus = 'No Payment Received' THEN DisbursalAmount ELSE 0 END), 2) AS 'No Payment Received',
ROUND(SUM(CASE WHEN DPDStatus = 'DPD >120' THEN DisbursalAmount ELSE 0 END), 2) AS 'DPD >120'
FROM
LoanDPD
WHERE
fbLeads IN ('Repeat Case')
GROUP BY
CreditedByName, DisbursalMonth, fbLeads
HAVING
DisbursalMonth > '2022-12-31'
ORDER BY
DisbursalMonth ASC, CreditedByName, fbLeads;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `repeat_dpd_reports`(from_date VARCHAR(20)) BEGIN WITH LoanDPD AS ( SELECT ap.creditedBy, u.name AS CreditedByName, DATE_FORMAT(ln.disbursalDate, '%Y-%m') AS DisbursalMonth, l.fbLeads, ln.loanNo, ln.disbursalAmount, CASE WHEN ap.repayDate > CURRENT_DATE THEN 'Not Due Yet' WHEN ap.repayDate <= CURRENT_DATE AND MAX(cl.collectedDate) IS NULL THEN CASE WHEN DATEDIFF(CURRENT_DATE, ap.repayDate) > 120 THEN 'DPD >120' ELSE 'No Payment' END WHEN MAX(cl.collectedDate) < ap.repayDate THEN 'DPD <0' WHEN MAX(cl.collectedDate) = ap.repayDate THEN 'DPD 0' WHEN MAX(cl.collectedDate) > ap.repayDate THEN CASE WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 1 AND 7 THEN 'DPD 1-7' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 8 AND 30 THEN 'DPD 8-30' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 31 AND 60 THEN 'DPD 31-60' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 61 AND 90 THEN 'DPD 61-90' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 91 AND 120 THEN 'DPD 91-120' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) > 120 THEN 'DPD >120' END END AS DPDStatus FROM loan ln JOIN approval ap ON ln.leadID = ap.leadID JOIN leads l ON ln.leadID = l.leadID LEFT JOIN collection cl ON ln.loanNo = cl.loanNo JOIN users u ON ap.creditedBy = u.userID GROUP BY ap.creditedBy, u.name, ln.disbursalDate, l.fbLeads, ln.loanNo, ln.disbursalAmount, ap.repayDate )
SELECT CreditedByName AS Credit_Manager_Name, DisbursalMonth, COUNT(DISTINCT CASE WHEN fbLeads IN ('Repeat Case') THEN LoanNo END) AS Due_A_cs, ROUND(SUM(DisbursalAmount), 2) AS Repay_Amt, ROUND(SUM(CASE WHEN DPDStatus = 'DPD <0' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_less_0, ROUND(SUM(CASE WHEN DPDStatus = 'DPD 0' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_0, ROUND(SUM(CASE WHEN DPDStatus = 'DPD 1-7' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_1_7, ROUND(SUM(CASE WHEN DPDStatus = 'DPD 8-30' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_8_30, ROUND(SUM(CASE WHEN DPDStatus = 'DPD 31-60' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_31_60, ROUND(SUM(CASE WHEN DPDStatus = 'DPD 61-90' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_61_90, ROUND(SUM(CASE WHEN DPDStatus = 'DPD 91-120' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_91_120, ROUND(SUM(CASE WHEN DPDStatus = 'No Payment Received' THEN DisbursalAmount ELSE 0 END), 2) AS No_Payment_Received, ROUND(SUM(CASE WHEN DPDStatus = 'DPD >120' THEN DisbursalAmount ELSE 0 END), 2) AS DPD_gretter_120 FROM LoanDPD WHERE fbLeads IN ('Repeat Case') AND DisbursalMonth > from_date GROUP BY CreditedByName, DisbursalMonth, fbLeads ORDER BY DisbursalMonth ASC, Credit_Manager_Name, fbLeads; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `salaried_vs_self_employed_report`(IN DISDATE varchar(20)) BEGIN
WITH LoanDPD AS ( SELECT ln.loanNo, ln.customerID, ln.disbursalAmount, COALESCE(SUM(CASE WHEN cl.collectionStatus = 'Approved' THEN cl.collectedAmount ELSE 0 END), 0) AS CollectedAmount, ap.repayDate, CASE WHEN ap.repayDate <= CURRENT_DATE AND MAX(cl.collectedDate) IS NULL THEN 999 ELSE GREATEST(DATEDIFF(MAX(cl.collectedDate), ap.repayDate), 0) END AS DPD, DATE_FORMAT(ln.disbursalDate, '%Y-%m-%d') AS DisbursalMonth, CASE WHEN ap.repayDate > CURRENT_DATE THEN 'Repay Date Not Yet Passed' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) < 0 THEN '< 0' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 0 AND 7 THEN '0-7' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 8 AND 30 THEN '08 to 30' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) BETWEEN 31 AND 60 THEN '31 to 60' WHEN DATEDIFF(MAX(cl.collectedDate), ap.repayDate) > 60 THEN '60+' WHEN ap.repayDate <= CURRENT_DATE AND MAX(cl.collectedDate) IS NULL THEN 'No Payment' ELSE NULL END AS DPDGroup FROM loan ln JOIN approval ap ON ln.leadID = ap.leadID LEFT JOIN collection cl ON ln.loanNo = cl.loanNo AND cl.collectionStatus = 'Approved' GROUP BY ln.loanNo, ln.customerID, ln.disbursalAmount, ap.repayDate, ln.disbursalDate ), DisbursedData AS ( SELECT ldpd.DisbursalMonth, c.employeeType, ldpd.DPDGroup, COUNT(ldpd.loanNo) AS TotalLoans, SUM(ldpd.disbursalAmount) AS TotalDisbursedAmount
FROM LoanDPD ldpd JOIN customer c ON ldpd.customerID = c.customerID WHERE c.employeeType IN ('Salaried', 'Self Employee') GROUP BY ldpd.DisbursalMonth, c.employeeType, ldpd.DPDGroup ) SELECT dd.DisbursalMonth, dd.employeeType, dd.DPDGroup, dd.TotalLoans, dd.TotalDisbursedAmount
FROM DisbursedData dd WHERE dd.DisbursalMonth = DISDATE ORDER BY dd.DisbursalMonth, dd.employeeType, dd.DPDGroup;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `SettledAccountsProcedure`( IN startDate DATE, IN endDate DATE ) BEGIN WITH LastSettlement AS ( SELECT loanNo, MAX(CASE WHEN status = 'Settlement' THEN collectedDate ELSE NULL END) AS lastSettlementDate FROM collection GROUP BY loanNo ), TotalCollected AS ( SELECT col.loanNo, SUM(col.collectedAmount) AS totalCollectedAmount FROM collection col JOIN LastSettlement ls ON col.loanNo = ls.loanNo WHERE col.collectionStatus = 'Approved' AND col.collectedMode <> 'Waive Off' AND col.collectedDate <= ls.lastSettlementDate GROUP BY col.loanNo ) SELECT l.loanNo AS 'Loan No', ld.customerID AS 'CustomerID', ld.leadID AS 'leadID', c.name AS 'Name', MAX(CASE WHEN cf.followType = 'Call' THEN cf.createdDate ELSE NULL END) AS 'Call Date', MAX(CASE WHEN cf.followType = 'Call' THEN cf.followType ELSE NULL END) AS 'Contact Type', MAX(cf.statusType) AS 'Status', MAX(CASE WHEN cf.statusType = 'PTP' THEN cf.statusTypeDate ELSE NULL END) AS 'PTP Date', MAX(cf.remark) AS 'Remark', l.disbursalAmount AS 'Loan Amount', a.tenure AS 'Tenure', a.roi AS 'ROI', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay Amount', a.repayDate AS 'Repay Date', COALESCE(tc.totalCollectedAmount, 0) AS 'Total Collected Amount', MAX(col.status) AS 'Collection Status', l.disbursalDate AS 'Date', MAX(addr.address) AS 'Address', MONTHNAME(l.disbursalDate) AS 'Disbursal Month', ld.fbLeads AS 'Loan Type', MAX(u.name) AS 'Credited By', lf.LoanFrequency AS 'Loan Frequency', c.employeeType AS 'Employee Type', MAX(cf.createdDate) AS 'Max Follow-up Date' FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN customer c ON ld.customerID = c.customerID LEFT JOIN collectionFollowup cf ON ld.leadID = cf.leadID LEFT JOIN collection col ON l.loanNo = col.loanNo LEFT JOIN address addr ON c.customerID = addr.customerID LEFT JOIN users u ON a.creditedby = u.userID JOIN ( SELECT customerID, COUNT(DISTINCT loanNo) AS LoanFrequency FROM loan WHERE status = 'Disbursed' GROUP BY customerID ) lf ON c.customerID = lf.customerID LEFT JOIN TotalCollected tc ON l.loanNo = tc.loanNo WHERE a.repayDate BETWEEN startDate AND endDate AND l.status = 'Disbursed' AND col.status = 'Settlement' GROUP BY l.loanNo, ld.customerID, ld.leadID, c.name, l.disbursalAmount, a.tenure, a.roi, a.repayDate, l.disbursalDate, ld.fbLeads, lf.LoanFrequency, c.employeeType, tc.totalCollectedAmount ORDER BY a.repayDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `settlement_data`() BEGIN SELECT c.name AS 'Customer_Name', c.mobile AS 'Contact_Number', DATE_FORMAT(l.disbursalDate, '%d-%m-%Y') AS 'Loan_Date', DATE_FORMAT(a.repayDate, '%d-%m-%Y') AS 'Repay_Date', ROUND(l.disbursalAmount) AS 'Loan_Amount', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay_Amount', DATE_FORMAT(MAX(co.collectionDate), '%d-%m-%Y') AS 'Settlement_Date', ROUND(SUM(CASE WHEN co.collectionStatus = 'Approved' THEN co.collectedAmount ELSE 0 END)) AS 'Settlement_Amount', ROUND( ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) + (l.disbursalAmount * 1.25 / 100 * DATEDIFF(MAX(co.collectionDate), a.repayDate)) - SUM(CASE WHEN co.collectionStatus = 'Approved' THEN co.collectedAmount ELSE 0 END) ) AS 'Due_Amount_on_Settlement_Date' FROM customer c JOIN leads ld ON c.customerID = ld.customerID JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON ld.leadID = a.leadID LEFT JOIN (SELECT leadID, collectedAmount, collectionStatus, createdDate AS collectionDate FROM collection WHERE collectionStatus = 'Approved' AND createdDate <= (SELECT MAX(createdDate) FROM collection WHERE status = 'Settlement') ) co ON l.leadID = co.leadID WHERE ld.status = 'Settlement' GROUP BY c.customerID ORDER BY c.name; END
CREATE DEFINER=`admin`@`%` PROCEDURE `sp_disbursal_attribution_report`( IN p_start_date DATE, IN p_end_date DATE, IN utm_codes TEXT, IN p_user_id INT ) BEGIN
DECLARE v_utmCode TEXT DEFAULT NULL; DECLARE v_sql LONGTEXT;
SET sql_mode = (SELECT REPLACE(@@sql_mode, 'ONLY_FULL_GROUP_BY', '')); SET SESSION group_concat_max_len = 10000000;
IF p_user_id IS NOT NULL AND p_user_id > 0 THEN
-- If user_id provided directly SELECT GROUP_CONCAT(utm_source SEPARATOR "','") INTO v_utmCode FROM user_utm_link WHERE user_id = p_user_id;
ELSE
-- If user_id is NULL → derive from utm_codes SET v_utmCode = IFNULL( ( SELECT GROUP_CONCAT(utm_source SEPARATOR "','") FROM user_utm_link WHERE user_id = ( SELECT internal_user_id FROM dsa.users WHERE utm_code = utm_codes LIMIT 1 ) ), utm_codes );
END IF;
SET v_sql = CONCAT(" WITH base AS ( SELECT lo.leadID as leadId, lo.loanNo, lo.customerID as customerId, c.name as name, a.createdDate as approveProcessedDate, a.loanAmtApproved as approveAmount, l.createdDate as leadDate, DATE(lo.disbursalDate) AS disbursalDate, lo.disbursalAmount,
ROUND(lo.disbursalAmount * a.roi / 100 * a.tenure) AS interest, a.repayDate AS due_date, ua_last.Source as utmCode,
ROUND( lo.disbursalAmount + (lo.disbursalAmount * a.roi / 100 * a.tenure) ) AS repay_amount,
ua_last.source AS attributed_source, ua_last.Source AS Actual_utmSource,
CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN lo.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status,
CASE WHEN l.status IN ('Disbursed', 'Settlement', 'Closed', 'Part Payment', 'Blacklisted') THEN 'Disbursed' ELSE l.status END AS currentStatus, c.mobile, ua_last.medium AS utmMedium, ua_last.campaign AS utmCampaign, ua_last.trackingid AS utmTrackingid
FROM ramfin.leads l
JOIN ramfin.customer c ON l.customerID = c.customerID
JOIN ramfin.approval a ON a.leadID = l.leadID
JOIN ramfin.loan lo ON lo.leadID = l.leadID
LEFT JOIN ( SELECT ua.* FROM ramfin.user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM ramfin.user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = l.customerID
WHERE lo.disbursalDate >= '", p_start_date, "' AND lo.disbursalDate < DATE_ADD('", p_end_date, "', INTERVAL 1 DAY) AND lo.payout_status = 2 AND lo.status = 'Disbursed' AND l.fbLeads <> 'Repeat Case' AND a.status IN ('Approved','Approved Process') ");
IF v_utmCode IS NOT NULL AND v_utmCode != '' THEN SET v_sql = CONCAT(v_sql, " AND ua_last.Source IN ('", v_utmCode, "') "); END IF;
-- IF in_lead_status IS NOT NULL AND in_lead_status != '' THEN -- SET v_sql = CONCAT(v_sql, " -- AND a.status = '", in_lead_status, "' -- "); -- END IF;
SET v_sql = CONCAT(v_sql, " ),
vuul AS ( SELECT LOWER(vul.utm_source) AS utm_source, MAX(NULLIF(TRIM(vul.dsa_name), '')) AS dsa_name, MAX(u.email) AS dsa_email FROM user_utm_link vul LEFT JOIN ramfin.users u ON vul.user_id = u.userID GROUP BY LOWER(vul.utm_source) )
SELECT b.*, COALESCE(v.dsa_name, 'others') AS dsa_name, v.dsa_email AS email FROM base b LEFT JOIN vuul v ON LOWER(b.Actual_utmSource) = v.utm_source WHERE b.attr_status = 1 ");
SET @final_sql = v_sql; PREPARE stmt FROM @final_sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
END
CREATE DEFINER=`admin`@`%` PROCEDURE `sp_lead_status_count_report`( IN p_start_date DATE, IN p_end_date DATE, IN utm_codes TEXT, IN filter_type VARCHAR(30), IN p_user_id INT ) BEGIN DECLARE v_utmCode TEXT DEFAULT NULL; DECLARE v_sql LONGTEXT; SET SESSION group_concat_max_len = 10000000; -- Logic to fetch UTM codes based on user_id or provided utm_codes IF p_user_id IS NOT NULL AND p_user_id > 0 THEN SELECT GROUP_CONCAT(DISTINCT QUOTE(utm_source)) INTO v_utmCode FROM user_utm_link WHERE user_id = p_user_id; ELSE -- Subquery to find internal_user_id from dsa.users SET v_utmCode = ( SELECT GROUP_CONCAT(DISTINCT QUOTE(utm_source)) FROM user_utm_link WHERE user_id = ( SELECT internal_user_id FROM dsa.users WHERE utm_code = utm_codes LIMIT 1 ) );
-- Fallback to the provided utm_codes if the subquery returns NULL IF v_utmCode IS NULL AND utm_codes IS NOT NULL THEN SET v_utmCode = QUOTE(utm_codes); END IF; END IF; -- Constructing the Dynamic SQL SET v_sql = CONCAT(" WITH base AS ( SELECT l.leadID, l.status, lo.disbursalAmount, lo.status AS loan_status, a.repayDate, DATE(lo.disbursalDate) AS disbursalDate, l.createdDate, ua_last.Source AS Actual_utmSource, CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN lo.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status FROM ramfin.leads l JOIN ramfin.customer c ON l.customerID = c.customerID LEFT JOIN ramfin.approval a ON a.leadID = l.leadID LEFT JOIN ramfin.loan lo ON lo.leadID = l.leadID LEFT JOIN ( SELECT ua.* FROM ramfin.user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM ramfin.user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = l.customerID WHERE DATE(l.createdDate) BETWEEN ", QUOTE(p_start_date), " AND ", QUOTE(p_end_date), " AND l.fbLeads <> 'Repeat Case' "); -- Injecting UTM filter if present IF v_utmCode IS NOT NULL AND v_utmCode != '' THEN SET v_sql = CONCAT(v_sql, " AND ua_last.Source IN (", v_utmCode, ") "); END IF; SET v_sql = CONCAT(v_sql, " ) SELECT COUNT(DISTINCT leadID) AS lead_count, COUNT(CASE WHEN status IN ('Disbursed','Settlement','Closed','Part Payment','Blacklisted') THEN leadID END) AS disbursed_leads, COUNT(CASE WHEN status = 'Part Payment' THEN leadID END) AS part_payment_leads, COUNT(CASE WHEN status IN ('Closed','Settlement','Blacklisted') THEN leadID END) AS closed_leads, COUNT(CASE WHEN status IN ('Rejected','Rejected Process','Not Eligible') THEN leadID END) AS rejected_leads, COUNT(CASE WHEN status IN ('Not Interested','Not Required','Not Required Process') THEN leadID END) AS not_interested_leads, COUNT(CASE WHEN (status IN ('Disbursed','Part Payment') AND repayDate < CURDATE()) THEN leadID END) AS overdue_leads, SUM(CASE WHEN loan_status = 'Disbursed' THEN disbursalAmount ELSE 0 END) AS disbursal_amount FROM base WHERE attr_status = 1 "); IF filter_type = 'inhouse' THEN SET v_sql = CONCAT(v_sql, " AND Actual_utmSource IS NOT NULL "); END IF; -- Execution SET @final_sql = v_sql; PREPARE stmt FROM @final_sql; EXECUTE stmt; DEALLOCATE PREPARE stmt; END
CREATE DEFINER=`admin`@`%` PROCEDURE `sp_lead_status_report`( IN p_start_date DATE, IN p_end_date DATE, IN utm_codes TEXT, IN in_lead_status VARCHAR(50), IN filter_type VARCHAR(30), IN p_user_id INT, IN p_limit INT, IN p_offset INT ) BEGIN
DECLARE v_utmCode TEXT DEFAULT NULL; DECLARE v_sql LONGTEXT;
SET SESSION group_concat_max_len = 10000000;
IF p_user_id IS NOT NULL AND p_user_id > 0 THEN
SELECT GROUP_CONCAT(utm_source SEPARATOR "','") INTO v_utmCode FROM user_utm_link WHERE user_id = p_user_id;
ELSE
SET v_utmCode = IFNULL( ( SELECT GROUP_CONCAT(utm_source SEPARATOR "','") FROM user_utm_link WHERE user_id = ( SELECT internal_user_id FROM dsa.users WHERE utm_code = utm_codes LIMIT 1 ) ), utm_codes );
END IF;
SET v_sql = CONCAT(" WITH base AS (
SELECT l.leadID as leadId, lo.loanNo, lo.customerID as customerId, c.name as name, a.createdDate as approveProcessedDate, a.loanAmtApproved as approveAmount, l.createdDate as leadDate, DATE(lo.disbursalDate) AS disbursalDate, lo.disbursalAmount,
ROUND(lo.disbursalAmount * a.roi / 100 * a.tenure) AS interest, a.repayDate AS due_date, ua_last.Source as utmCode,
ROUND( lo.disbursalAmount + (lo.disbursalAmount * a.roi / 100 * a.tenure) ) AS repay_amount,
ua_last.source AS attributed_source, ua_last.Source AS Actual_utmSource,
CASE WHEN ua_last.expiryDate IS NULL THEN 0 WHEN lo.disbursalDate <= ua_last.expiryDate THEN 1 ELSE 0 END AS attr_status,
l.status AS currentStatus, c.mobile, ua_last.medium AS utmMedium, ua_last.campaign AS utmCampaign, ua_last.trackingid AS utmTrackingid
FROM ramfin.leads l
JOIN ramfin.customer c ON l.customerID = c.customerID
LEFT JOIN ramfin.approval a ON a.leadID = l.leadID
LEFT JOIN ramfin.loan lo ON lo.leadID = l.leadID
LEFT JOIN ( SELECT ua.* FROM ramfin.user_attributions ua INNER JOIN ( SELECT customerID, MAX(id) AS max_id FROM ramfin.user_attributions GROUP BY customerID ) latest ON ua.customerID = latest.customerID AND ua.id = latest.max_id ) ua_last ON ua_last.customerID = l.customerID
WHERE DATE(l.createdDate) >= '", p_start_date, "' AND DATE(l.createdDate) <= '", p_end_date, "' AND l.fbLeads <> 'Repeat Case' ");
IF v_utmCode IS NOT NULL AND v_utmCode != '' THEN SET v_sql = CONCAT(v_sql, " AND ua_last.Source IN ('", v_utmCode, "') "); END IF;
IF in_lead_status IS NOT NULL AND in_lead_status != '' AND in_lead_status != 'all' THEN
CASE in_lead_status
WHEN 'rejected' THEN SET v_sql = CONCAT(v_sql, " AND l.status IN ('Rejected','Rejected Process','Not Eligible') ");
WHEN 'not_interested' THEN SET v_sql = CONCAT(v_sql, " AND l.status IN ('Not Interested','Not Required','Not Required Process') ");
WHEN 'approved' THEN SET v_sql = CONCAT(v_sql, " AND l.status IN ('Approved Process','Approved') ");
WHEN 'fresh_Incomplete' THEN SET v_sql = CONCAT(v_sql, " AND l.status IN ('Fresh Lead','Incomplete User') ");
ELSE -- fallback if someone passes exact status name SET v_sql = CONCAT(v_sql, " AND l.status = '", in_lead_status, "' ");
END CASE;
END IF;
SET v_sql = CONCAT(v_sql, " ),
vuul AS ( SELECT LOWER(utm_source) AS utm_source, MAX(NULLIF(TRIM(dsa_name), '')) AS dsa_name FROM ramfin.user_utm_link GROUP BY LOWER(utm_source) )
SELECT b.*, COALESCE(v.dsa_name, 'others') AS dsa_name FROM base b LEFT JOIN vuul v ON LOWER(b.Actual_utmSource) = v.utm_source ");
IF filter_type = 'inhouse' THEN SET v_sql = CONCAT(v_sql, " AND b.Actual_utmSource IS NOT NULL "); END IF; IF p_limit IS NOT NULL AND p_limit > 0 THEN SET v_sql = CONCAT(v_sql, " LIMIT ", p_limit, " OFFSET ", p_offset); END IF;
SET @final_sql = v_sql; PREPARE stmt FROM @final_sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `TotalCasesProcedure`() BEGIN WITH collection_sums AS ( SELECT leadID, SUM(collectedAmount) AS collectedAmount FROM collection WHERE collectionstatus = 'Approved' GROUP BY leadID ), loan_data AS ( SELECT ld.fbLeads AS Type, l.disbursalAmount, (l.disbursalAmount * a.roi / 100 * a.tenure) AS interestAmount, l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure) AS repayAmount, COALESCE(c.collectedAmount, 0) AS collectedAmount FROM loan l JOIN leads ld ON l.leadID = ld.leadID JOIN approval a ON l.leadID = a.leadID LEFT JOIN collection_sums c ON l.leadID = c.leadID WHERE a.repaydate BETWEEN '2024-01-01' AND '2024-04-30' ), aggregated_data AS ( SELECT Type, ROUND(SUM(disbursalAmount)) AS 'Loan Amount', ROUND(SUM(repayAmount)) AS 'Repay Amount', ROUND(SUM(collectedAmount)) AS 'Collection Amount', ROUND(SUM(repayAmount - collectedAmount)) AS 'Pending Amount' FROM loan_data GROUP BY Type
UNION ALL
SELECT 'Total' AS Type, ROUND(SUM(disbursalAmount)) AS 'Loan Amount', ROUND(SUM(repayAmount)) AS 'Repay Amount', ROUND(SUM(collectedAmount)) AS 'Collection Amount', ROUND(SUM(repayAmount - collectedAmount)) AS 'Pending Amount' FROM loan_data ) SELECT Type, `Loan Amount`, `Repay Amount`, `Collection Amount`, CASE WHEN Type = 'Total' THEN ROUND((`Collection Amount` / `Repay Amount`) * 100, 2) ELSE ROUND((`Collection Amount` / `Repay Amount`) * 100, 2) END AS `Collection%`, `Pending Amount`, CASE WHEN Type = 'Total' THEN ROUND((`Pending Amount` / `Repay Amount`) * 100, 2) ELSE ROUND((`Pending Amount` / `Repay Amount`) * 100, 2) END AS `Pending%` FROM aggregated_data ORDER BY CASE WHEN Type = 'Total' THEN 2 ELSE 1 END, Type; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `TotalLoanRepayment`( IN startDate DATE, IN endDate DATE ) BEGIN SELECT l.loanNo AS 'Loan No', ld.customerID AS 'CustomerID', ld.leadID AS 'leadID', c.name AS 'Name', MAX(CASE WHEN cf.followType = 'Call' THEN cf.createdDate ELSE NULL END) AS 'Call Date', MAX(CASE WHEN cf.followType = 'Call' THEN cf.followType ELSE NULL END) AS 'Contact Type', MAX(cf.statusType) AS 'Status', MAX(CASE WHEN cf.statusType = 'PTP' THEN cf.statusTypeDate ELSE NULL END) AS 'PTP Date', MAX(cf.remark) AS 'Remark', l.disbursalAmount AS 'Loan Amount', a.tenure AS 'Tenure', a.roi AS 'ROI', ROUND(l.disbursalAmount + (l.disbursalAmount * a.roi / 100 * a.tenure)) AS 'Repay Amount', a.repayDate AS 'Repay Date', MAX(CASE WHEN col.collectionStatus = 'Approved' AND col.collectedMode <> 'Waive Off' THEN col.collectedAmount ELSE NULL END) AS 'Total Collected Amount', ld.status AS 'Status', l.disbursalDate AS 'Date', MAX(addr.address) AS 'Address', MONTHNAME(l.disbursalDate) AS 'Disbursal Month', ld.fbLeads AS 'Loan Type', MAX(u.name) AS 'Credited By', lf.LoanFrequency AS 'Loan Frequency', c.employeeType AS 'Employee Type', MAX(cf.createdDate) AS 'Max Follow-up Date' FROM leads ld JOIN loan l ON ld.leadID = l.leadID JOIN approval a ON l.leadID = a.leadID JOIN customer c ON ld.customerID = c.customerID LEFT JOIN collectionFollowup cf ON ld.leadID = cf.leadID LEFT JOIN collection col ON l.loanNo = col.loanNo LEFT JOIN address addr ON c.customerID = addr.customerID LEFT JOIN users u ON a.creditedby = u.userID JOIN ( SELECT customerID, COUNT(DISTINCT loanNo) AS LoanFrequency FROM loan WHERE status = 'Disbursed' GROUP BY customerID ) lf ON c.customerID = lf.customerID WHERE a.repayDate BETWEEN startDate AND endDate AND l.status = 'Disbursed' GROUP BY l.loanNo, ld.customerID, ld.leadID, c.name, l.disbursalAmount, a.tenure, a.roi, a.repayDate, l.disbursalDate, ld.fbLeads, ld.status, lf.LoanFrequency, c.employeeType ORDER BY a.repayDate; END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `update_all_timestamp_columns_with_logs`() BEGIN DECLARE done INT DEFAULT 0; DECLARE tbl_name VARCHAR(255); DECLARE pk_column VARCHAR(255); DECLARE set_list TEXT; DECLARE where_list TEXT; DECLARE last_id BIGINT; DECLARE max_id BIGINT; DECLARE batch_size INT DEFAULT 10000; DECLARE cur CURSOR FOR SELECT TABLE_NAME FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME IN ( 'AppcustLocation','AppreqDoc','Data_mart','DisbLogs','aadhaar_mode','address','alternative_contact','api_req_res_logs_kfs', 'appCallback','app_lead','app_track','app_versions','approval','aum_data','auto_disb_status','auto_disb_status_logs', 'auto_disbursal_log','balance_history','bankList','bank_ifsc','bank_update_check','bankingData','banks','blacklistCustomer', 'blacklistCustomerLeadLog','blacklistCustomerPancard','branch','bre_approval_amount','bulk_emandate','bureauCustomerToken', 'bureauData','callhistory','callhistoryApp','callhistoryLogs','cashfree_emCharge','cashfree_mandate','cibil_data_log','cibil_score', 'cibil_test_data','cities','collection','collectionFollowup','collectionRefund','collection_temp','company_payout_accounts', 'complaint','complaint_data','contact_us','contactus','convoque_call_logs','cr_buckets','cr_profile_accounts','cr_profile_enquiry', 'cr_profile_repayment_data','cr_profiles','credit_reports','credit_score_user_journey','credits','crm_transaction','cron_job_logs', 'cust_data','customer','customer2','customerAccount','customerApp','customerAppLocation','customerAppVersion','customerByPartner', 'customerEditLogs','customer_awareness_read','customer_dnd','customer_mandates','customer_name_match','customer_salary', 'device_profile','deviceconnectFinbox','dialerFollowup','dialerLead','dialer_api_logs','digiloger_initiate_session', 'disbursal_job_initiation','disbursal_jobs','document','documentFinbox','documentFinbox1','documentfinboxlog','dsaUtmData', 'dsa_api_logs','dtree_test','e_sign','emandate_nach_na','emandate_not_required_logs','emi_transactions','emis','employer', 'equated_monthly_installments','exsl_filelog','exsl_mandate','facebook_lead','failed_jobs','finbox_aa_dow_st','finbox_aa_validity', 'finbox_client_url','finbox_device_conn_status','finbox_name_match','flow_screen_map','issue_type','issues','ivrStatus', 'ivr_api_attempt','jobs','kaleyra_logs','lead_assign','lead_chat','lead_chat_template','leads','leads_agent_collection', 'leads_apr','leads_auto_status','leads_field_officer','leads_last_utm','leads_run_bre_logs','loan','loan_ac_remove_logs', 'loan_account_type','loan_detail_data','loan_disDate_chLogs','loan_summary_result','loanwise_disbursement_collection_data', 'loanwise_disbursement_collection_data_1','locations','loginLogs','login_device_detail','lpa_utmList','mail_sent_temp', 'mail_template','marketing_record','marketing_source','master_crons','migrations','mobile_token','move_customer_logs', 'no_loan_follow_up_logs','not_required_leads','not_required_leads_filelog','notification_admin','notifications', 'onlinePaymentlog','onlinepayment','other_charges','payment_mode','payment_mode_for_banks','payout_accounts_log', 'penny_drop','penny_namemismatch_accept','permissions','permissions_old_3APR','pg_type','pg_type_change_logs','pincode', 'pincode_city_list','products','query_logs','ramBlog','razorpay_emOrder','razorpay_emch_queue','razorpay_logs','razorpay_mandate', 'razorpay_mandate_status','razorpay_payout_accounts','razorpay_payout_contacts','razorpay_payout_disbured_amount', 'razorpay_subscription','record_counts_by_date','reference','referrers','referrers_unique','refunds','repaydate_holiday', 'report_datatable','report_permission','report_table','review','rj_api','role_permission_links','roles','send_inblue_email_log', 'send_whatsapp_status','setting','source_partners','states','step_control','step_tracker','subscription_payments', 'subscription_refunds','surepass_logs','switch_thirdparty_api','temp_pans','temp_razorpay','third_party_recharge','tl_tellecaller', 'tl_tellecaller_lead_assign','transactions','user_edit_logs','user_ip_details','user_ip_details_logs','user_login_attempt', 'user_metadata','user_permission_links','user_summary','user_utm_link','users','users_lat_long','users_logs','usersgoogle', 'virtualAccount','virtualCustomer','virtualQr','waive_off_logs','waiver','web_amount_d','web_engage','website_amount', 'whatsapp_logs','whatsapp_message_ids'); DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1; OPEN cur; table_loop: LOOP FETCH cur INTO tbl_name; IF done THEN LEAVE table_loop; END IF; SET pk_column = NULL; BEGIN DECLARE CONTINUE HANDLER FOR NOT FOUND SET pk_column = NULL; SELECT COLUMN_NAME INTO pk_column FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = tbl_name AND CONSTRAINT_NAME = 'PRIMARY' LIMIT 1; END; IF pk_column IS NULL THEN ITERATE table_loop; END IF;
SELECT GROUP_CONCAT( CONCAT('`', COLUMN_NAME, '` = IF(`', COLUMN_NAME, '` IS NOT NULL, DATE_SUB(`', COLUMN_NAME, '`, INTERVAL 330 MINUTE), NULL)') SEPARATOR ', ') INTO set_list FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = tbl_name AND DATA_TYPE = 'timestamp' AND TABLE_SCHEMA = DATABASE();
SELECT GROUP_CONCAT(CONCAT('`', COLUMN_NAME, '` IS NOT NULL') SEPARATOR ' OR ') INTO where_list FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = tbl_name AND DATA_TYPE = 'timestamp' AND TABLE_SCHEMA = DATABASE(); IF set_list IS NOT NULL AND where_list IS NOT NULL THEN SET last_id = 0; SET @max_id_sql = CONCAT('SELECT MAX(`', pk_column, '`) INTO @max_id FROM `', tbl_name, '`'); PREPARE max_stmt FROM @max_id_sql; EXECUTE max_stmt; DEALLOCATE PREPARE max_stmt; SET max_id = @max_id; batch_loop: WHILE last_id < max_id DO SET @update_sql = CONCAT( 'UPDATE `', tbl_name, '` ', 'SET ', set_list, ' WHERE `', pk_column, '` > ', last_id, ' AND (', where_list, ')', ' ORDER BY `', pk_column, '` LIMIT ', batch_size ); SELECT CONCAT('Executing: ', @update_sql) AS executing_query; PREPARE stmt FROM @update_sql; EXECUTE stmt; DEALLOCATE PREPARE stmt; SET @id_sql = CONCAT( 'SELECT MAX(`', pk_column, '`) INTO @last_id FROM (', 'SELECT `', pk_column, '` FROM `', tbl_name, '` ', 'WHERE `', pk_column, '` > ', last_id, ' AND (', where_list, ')', ' ORDER BY `', pk_column, '` LIMIT ', batch_size, ') AS temp_table' ); PREPARE id_stmt FROM @id_sql; EXECUTE id_stmt; DEALLOCATE PREPARE id_stmt; SET last_id = @last_id; IF last_id IS NULL THEN LEAVE batch_loop; END IF; END WHILE; END IF; END LOOP; CLOSE cur; END
CREATE DEFINER=`admin`@`%` PROCEDURE `update_collection_calculations`(IN input_leadID INT) BEGIN DECLARE done INT DEFAULT FALSE; DECLARE v_collectionID INT; DECLARE v_collectedAmount DECIMAL(10,2); DECLARE v_collectedDate DATE; DECLARE v_status VARCHAR(50); DECLARE v_disbursalAmount DECIMAL(10,2); DECLARE v_disbursalDate VARCHAR(40); DECLARE v_roi DECIMAL(5,2); DECLARE v_repayDate DATE; DECLARE v_prev_closing_balance DECIMAL(10,2) DEFAULT 0; DECLARE v_last_collection_date DATE DEFAULT NULL; DECLARE v_is_first_collection BOOLEAN DEFAULT TRUE; DECLARE v_lead_status VARCHAR(50); DECLARE v_prev_penalty_balance DECIMAL(10,2) DEFAULT 0; DECLARE v_prev_interest_balance DECIMAL(10,2) DEFAULT 0;
DECLARE v_opening_balance DECIMAL(10,2); DECLARE v_closing_balance DECIMAL(10,2); DECLARE v_total_interest DECIMAL(10,2); DECLARE v_principal_amount DECIMAL(10,2); DECLARE v_penality_charge DECIMAL(10,2); DECLARE v_collected_interest DECIMAL(10,2); DECLARE v_collected_principal DECIMAL(10,2); DECLARE v_collected_penality DECIMAL(10,2); DECLARE v_days_from_disbursal INT; DECLARE v_days_past_due INT; DECLARE v_normal_interest DECIMAL(10,2); DECLARE v_penalty_interest DECIMAL(10,2); DECLARE v_remaining_amount DECIMAL(10,2); DECLARE v_total_due_amount DECIMAL(10,2); DECLARE v_excess_amount DECIMAL(10,2) DEFAULT 0; DECLARE v_sanction_tenure INT DEFAULT 0; DECLARE v_dpd_tenure INT DEFAULT 0; DECLARE v_one_time_penalty DECIMAL(10,2) DEFAULT 0; DECLARE penalty_amount DECIMAL(10,2) DEFAULT 590.00; DECLARE v_calculate_from_date DATE; DECLARE v_total_interest_actual DECIMAL(10,2) DEFAULT 0; DECLARE v_penality_charge_actual DECIMAL(10,2) DEFAULT 0; DECLARE v_current_penalty DECIMAL(10,2) DEFAULT 0; DECLARE v_loan_already_closed BOOLEAN DEFAULT FALSE;
DECLARE collection_cursor CURSOR FOR SELECT c.collectionID, c.collectedAmount, c.collectedDate, c.status, l.disbursalAmount, l.disbursalDate, a.roi, a.repayDate, ld.status as lead_status FROM collection c LEFT JOIN loan l ON c.leadID = l.leadID AND c.customerID = l.customerID LEFT JOIN approval a ON c.leadID = a.leadID AND c.customerID = a.customerID LEFT JOIN leads ld ON c.leadID = ld.leadID AND c.customerID = ld.customerID WHERE c.leadID = input_leadID AND c.collectionStatus = 'Approved' ORDER BY c.collectedDate ASC;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
SELECT l.disbursalAmount, a.roi, a.repayDate, l.disbursalDate INTO v_disbursalAmount, v_roi, v_repayDate, v_disbursalDate FROM loan l JOIN approval a ON l.leadID = a.leadID AND l.customerID = a.customerID WHERE l.leadID = input_leadID LIMIT 1;
SET v_prev_closing_balance = v_disbursalAmount;
OPEN collection_cursor;
collection_loop: LOOP FETCH collection_cursor INTO v_collectionID, v_collectedAmount, v_collectedDate, v_status, v_disbursalAmount, v_disbursalDate, v_roi, v_repayDate, v_lead_status;
IF done THEN LEAVE collection_loop; END IF;
IF v_loan_already_closed = TRUE THEN
SET v_opening_balance = 0; SET v_closing_balance = 0; SET v_total_interest = 0; SET v_principal_amount = 0; SET v_penality_charge = 0; SET v_collected_interest = 0; SET v_collected_principal = 0; SET v_collected_penality = 0; SET v_excess_amount = v_collectedAmount;
UPDATE collection SET opening_balance = v_opening_balance, closing_balance = v_closing_balance, total_interest = v_total_interest, principal_amount = v_principal_amount, penality_charge = v_penality_charge, collected_interest = v_collected_interest, collected_principal = v_collected_principal, collected_penality = v_collected_penality, excess_amount = v_excess_amount, updated_date = NOW() WHERE collectionID = v_collectionID;
ITERATE collection_loop; END IF;
IF v_is_first_collection THEN
SET v_principal_amount = v_disbursalAmount; SET v_calculate_from_date = STR_TO_DATE(v_disbursalDate, '%Y-%m-%d'); SET v_is_first_collection = FALSE; ELSE
SET v_principal_amount = v_prev_closing_balance; SET v_calculate_from_date = v_last_collection_date; END IF;
IF v_last_collection_date IS NOT NULL THEN
SET v_days_from_disbursal = DATEDIFF(v_collectedDate, v_calculate_from_date);
IF v_collectedDate <= v_repayDate AND v_repayDate >= v_calculate_from_date THEN SET v_sanction_tenure = DATEDIFF(v_collectedDate, v_calculate_from_date); SET v_dpd_tenure = 0; SET v_one_time_penalty = 0; ELSEIF v_collectedDate >= v_repayDate AND v_repayDate >= v_calculate_from_date THEN SET v_sanction_tenure = DATEDIFF(v_repayDate, v_calculate_from_date); SET v_dpd_tenure = DATEDIFF(v_collectedDate, v_repayDate);
IF v_prev_penalty_balance = 0 THEN SET v_one_time_penalty = penalty_amount; ELSE SET v_one_time_penalty = 0; END IF; ELSEIF v_collectedDate >= v_repayDate AND v_repayDate <= v_calculate_from_date THEN SET v_sanction_tenure = 0; SET v_dpd_tenure = DATEDIFF(v_collectedDate, v_calculate_from_date);
IF v_prev_penalty_balance = 0 THEN SET v_one_time_penalty = penalty_amount; ELSE SET v_one_time_penalty = 0; END IF; END IF; ELSE
SET v_days_from_disbursal = DATEDIFF(v_collectedDate, STR_TO_DATE(v_disbursalDate, '%Y-%m-%d'));
IF v_collectedDate <= v_repayDate THEN SET v_sanction_tenure = v_days_from_disbursal; SET v_dpd_tenure = 0; SET v_one_time_penalty = 0; ELSE SET v_sanction_tenure = DATEDIFF(v_repayDate, STR_TO_DATE(v_disbursalDate, '%Y-%m-%d')); SET v_dpd_tenure = DATEDIFF(v_collectedDate, v_repayDate); SET v_one_time_penalty = penalty_amount; END IF; END IF;
IF v_last_collection_date IS NULL THEN
SET v_total_interest = v_principal_amount * (v_roi / 100) * (v_sanction_tenure + v_dpd_tenure); ELSE
SET v_total_interest = v_principal_amount * (v_roi / 100) * (v_sanction_tenure + v_dpd_tenure) + v_prev_interest_balance; END IF;
SET v_current_penalty = v_principal_amount * (0.1 / 100) * v_dpd_tenure + v_one_time_penalty;
SET v_penality_charge = v_current_penalty + v_prev_penalty_balance;
SET v_total_due_amount = v_principal_amount + v_total_interest + v_penality_charge;
SET v_opening_balance = v_total_due_amount;
SET v_total_interest_actual = v_total_interest; SET v_penality_charge_actual = v_penality_charge;
SET v_collected_interest = 0; SET v_collected_principal = 0; SET v_collected_penality = 0; SET v_excess_amount = 0;
IF v_total_due_amount > v_collectedAmount AND v_status = 'Closed' THEN SET v_status = 'Part Payment'; END IF;
IF v_status = 'Closed' THEN IF v_total_due_amount > v_collectedAmount THEN
SET v_status = 'Part Payment'; ELSEIF v_total_due_amount < v_collectedAmount THEN SET v_excess_amount = v_collectedAmount - v_total_due_amount; END IF;
SET v_collected_interest = v_total_interest; SET v_collected_principal = v_principal_amount; SET v_collected_penality = v_penality_charge; SET v_closing_balance = 0; SET v_principal_amount = 0;
IF v_collectedAmount - v_total_due_amount >= 0 THEN SET v_penality_charge = 0; SET v_total_interest = 0; END IF;
ELSEIF v_status = 'Part Payment' THEN SET v_closing_balance = 0;
IF v_total_due_amount = v_collectedAmount THEN
SET v_status = 'Closed'; SET v_collected_interest = v_total_interest; SET v_collected_principal = v_principal_amount; SET v_collected_penality = v_penality_charge; SET v_principal_amount = 0; SET v_total_interest = 0; SET v_penality_charge = 0;
ELSEIF v_total_due_amount < v_collectedAmount THEN
SET v_excess_amount = v_collectedAmount - v_total_due_amount; SET v_status = 'Closed'; SET v_collected_interest = v_total_interest; SET v_collected_principal = v_principal_amount; SET v_collected_penality = v_penality_charge; SET v_principal_amount = 0; SET v_total_interest = 0; SET v_penality_charge = 0;
ELSE
SET v_closing_balance = v_total_due_amount - v_collectedAmount;
IF v_collectedAmount > v_total_interest THEN
IF v_total_interest_actual = 0 AND v_collectedAmount >= v_principal_amount THEN SET v_collected_principal = v_principal_amount; ELSEIF v_total_interest_actual = 0 AND v_collectedAmount < v_principal_amount THEN SET v_collected_principal = v_collectedAmount; ELSE SET v_collected_principal = v_collectedAmount - v_total_interest_actual;
IF v_collectedAmount > (v_principal_amount + v_total_interest_actual) THEN SET v_collected_principal = v_principal_amount; END IF; END IF;
SET v_total_interest = 0; SET v_principal_amount = v_principal_amount - v_collected_principal; SET v_collected_interest = v_total_interest_actual - v_total_interest;
IF v_principal_amount < 0 THEN SET v_penality_charge = v_penality_charge + v_principal_amount; SET v_principal_amount = 0; IF v_penality_charge < 0 THEN SET v_penality_charge = 0; END IF; ELSE SET v_penality_charge = GREATEST(0, v_penality_charge_actual - (v_collectedAmount - v_collected_principal - v_collected_interest)); END IF;
SET v_collected_penality = GREATEST(0, v_penality_charge_actual - v_penality_charge);
IF v_collected_interest = 0 AND v_collected_principal = 0 THEN SET v_collected_penality = v_collectedAmount; SET v_penality_charge = v_penality_charge_actual - v_collected_penality; END IF;
ELSE
SET v_total_interest = v_total_interest - v_collectedAmount; SET v_collected_interest = v_total_interest_actual - v_total_interest; END IF; END IF;
ELSEIF v_status = 'Settlement' THEN
SET v_closing_balance = v_total_due_amount - v_collectedAmount;
IF v_collectedAmount > v_total_interest THEN
IF v_total_interest_actual = 0 AND v_collectedAmount >= v_principal_amount THEN SET v_collected_principal = v_principal_amount; ELSEIF v_total_interest_actual = 0 AND v_collectedAmount < v_principal_amount THEN SET v_collected_principal = v_collectedAmount; ELSE SET v_collected_principal = v_collectedAmount - v_total_interest_actual;
IF v_collectedAmount > (v_principal_amount + v_total_interest_actual) THEN SET v_collected_principal = v_principal_amount; END IF; END IF;
SET v_total_interest = 0; SET v_principal_amount = v_principal_amount - v_collected_principal;
IF v_principal_amount < 0 THEN SET v_penality_charge = v_penality_charge + v_principal_amount; SET v_principal_amount = 0; IF v_penality_charge < 0 THEN SET v_penality_charge = 0; END IF; ELSE SET v_penality_charge = v_penality_charge_actual; END IF;
SET v_collected_interest = v_total_interest_actual - v_total_interest; SET v_collected_penality = v_penality_charge_actual - v_penality_charge;
IF v_collected_interest = 0 AND v_collected_principal = 0 THEN SET v_collected_penality = v_collectedAmount; SET v_penality_charge = v_penality_charge_actual - v_collected_penality; END IF;
ELSE
SET v_total_interest = v_total_interest - v_collectedAmount; SET v_collected_interest = v_total_interest_actual - v_total_interest; END IF; END IF;
UPDATE collection SET opening_balance = v_opening_balance, closing_balance = v_closing_balance, total_interest = v_total_interest, principal_amount = v_principal_amount, penality_charge = v_penality_charge, collected_interest = v_collected_interest, collected_principal = v_collected_principal, collected_penality = v_collected_penality, excess_amount = v_excess_amount, updated_date = NOW() WHERE collectionID = v_collectionID;
IF v_status = 'Closed' THEN SET v_prev_closing_balance = 0; SET v_loan_already_closed = TRUE; ELSE
SET v_prev_closing_balance = v_principal_amount; END IF;
SET v_last_collection_date = v_collectedDate;
SET v_prev_penalty_balance = v_penality_charge; SET v_prev_interest_balance = v_total_interest;
END LOOP;
CLOSE collection_cursor;
SELECT 'Collection calculations updated successfully' as message, COUNT(*) as records_updated FROM collection WHERE leadID = input_leadID AND collectionStatus = 'Approved';
END
CREATE DEFINER=`ramfin_read`@`%` PROCEDURE `user_funnel`( IN start_date DATE, IN end_date DATE) BEGIN
WITH pan_users AS ( SELECT DISTINCT customerID, DATE(event_date) AS funnel_date FROM user_flow_data WHERE event_type = 'PAN Verification' AND DATE(event_date) between start_date and end_date )
SELECT p.funnel_date AS pan_verification_time, 'Matured' AS Type, COUNT(DISTINCT p.customerID) AS pan_count, COUNT(DISTINCT CASE WHEN u.event_type = 'LeadCreated' THEN u.customerID END) AS lead_created_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Approved Process' THEN u.customerID END) AS approved_count, COUNT(DISTINCT CASE WHEN u.event_type = 'KYC COMPLETED' THEN u.customerID END) AS kyc_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Selfie' THEN u.customerID END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Emandate' THEN u.customerID END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Disbursed' THEN u.customerID END) AS disbursed_count FROM pan_users p LEFT JOIN user_flow_data u ON u.customerID = p.customerID GROUP BY p.funnel_date
UNION ALL
SELECT p.funnel_date AS pan_verification_time, 'Sameday' AS Type, COUNT(DISTINCT p.customerID) AS pan_count, COUNT(DISTINCT CASE WHEN u.event_type = 'LeadCreated' AND DATE(u.event_date) = p.funnel_date THEN u.customerID END) AS lead_created_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Approved Process' AND DATE(u.event_date) = p.funnel_date THEN u.customerID END) AS approved_count, COUNT(DISTINCT CASE WHEN u.event_type = 'KYC COMPLETED' AND DATE(u.event_date) = p.funnel_date THEN u.customerID END) AS kyc_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Selfie' AND DATE(u.event_date) = p.funnel_date THEN u.customerID END) AS selfie_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Emandate' AND DATE(u.event_date) = p.funnel_date THEN u.customerID END) AS emandate_count, COUNT(DISTINCT CASE WHEN u.event_type = 'Disbursed' AND DATE(u.event_date) = p.funnel_date THEN u.customerID END) AS disbursed_count FROM pan_users p LEFT JOIN user_flow_data u ON u.customerID = p.customerID GROUP BY p.funnel_date
ORDER BY pan_verification_time, Type DESC;
END
